import (
	"fmt"
	"regexp"
	"strings"
	"unicode"
)

var (
	trailingDashRE = regexp.MustCompile(`\s[\x{2013}\x{2014}-]+\s*$`)
	verbRE         = regexp.MustCompile(`(?i)\b(is|are|was|were|has|have|had|can|will|may|should|would|could|do|does|did|been|be|being|occur|form|cause|help|provide|include|involve|develop|affect|require|contain|consist|allow|make|take|give|show|use|need|want|seem|appear|become|remain|stay|go|come)\b`)
	fullPhraseRE   = regexp.MustCompile(`(?m)([.!?] )([A-Z][^\n.!?]{2,}?)(?= [A-Z][a-z])`)
)

func isValidHeader(phrase string, maxHeaderWords, maxHeaderChars int) bool {
	words := strings.Fields(phrase)
	if len(words) < 2 || len(words) > maxHeaderWords {
		return false
	}
	if len(phrase) > maxHeaderChars {
		return false
	}
	if verbRE.MatchString(phrase) {
		return false
	}
	runes := []rune(phrase)
	if len(runes) == 0 || !unicode.IsUpper(runes[0]) {
		return false
	}
	if trailingDashRE.MatchString(phrase) {
		return false
	}
	return true
}

func promoteShortPhraseHeaders(text string, maxHeaderWords, maxHeaderChars int) string {
	return fullPhraseRE.ReplaceAllStringFunc(text, func(match string) string {
		subs := fullPhraseRE.FindStringSubmatch(match)
		if len(subs) < 3 {
			return match
		}
		sentEnd := subs[1]
		phrase := strings.TrimRight(strings.TrimSpace(subs[2]), ".,;:")
		if !isValidHeader(phrase, maxHeaderWords, maxHeaderChars) {
			return match
		}
		return fmt.Sprintf("%s\n\n## %s\n\n", sentEnd, phrase)
	})
}

