import "strings"

func isListLine(line string) bool {
	stripped := strings.TrimLeft(line, " \t")
	if len(stripped) >= 2 {
		prefix := stripped[:2]
		if prefix == "- " || prefix == "* " || prefix == "+" + " " {
			return true
		}
	}
	if len(stripped) > 0 && stripped[0] >= '0' && stripped[0] <= '9' {
		dotPos := strings.Index(stripped, ". ")
		if dotPos > 0 && dotPos <= 4 {
			numPart := stripped[:dotPos]
			allDigits := true
			for _, c := range numPart {
				if c < '0' || c > '9' {
					allDigits = false
					break
				}
			}
			return allDigits
		}
	}
	return false
}

