func lcaPath(paths [][]string) []string {
	var nonEmpty [][]string
	for _, p := range paths {
		if len(p) > 0 {
			nonEmpty = append(nonEmpty, p)
		}
	}
	if len(nonEmpty) == 0 {
		return []string{}
	}
	if len(nonEmpty) == 1 {
		result := make([]string, len(nonEmpty[0]))
		copy(result, nonEmpty[0])
		return result
	}
	minLen := len(nonEmpty[0])
	for _, p := range nonEmpty[1:] {
		if len(p) < minLen {
			minLen = len(p)
		}
	}
	var result []string
	for i := 0; i < minLen; i++ {
		val := nonEmpty[0][i]
		allSame := true
		for _, p := range nonEmpty[1:] {
			if p[i] != val {
				allSame = false
				break
			}
		}
		if allSame {
			result = append(result, val)
		} else {
			break
		}
	}
	if len(result) > 0 {
		return result
	}
	last := nonEmpty[len(nonEmpty)-1]
	out := make([]string, len(last))
	copy(out, last)
	return out
}

