// flushChunk produces a DocumentChunk from accumulated text.
// currentSectionPaths and include* params are passed explicitly to avoid closure state.
func flushChunk(
	name string,
	text string,
	idx int,
	offset *int,
	paragraphContinuation bool,
	embeddingText *string,
	currentSectionPaths [][]string,
	includeBreadcrumb bool,
	includeDocName bool,
	maxBreadcrumbChars *int,
) DocumentChunk {
	lca := lcaPath(currentSectionPaths)
	var crumb *string
	var embedding *string
	base := text
	if embeddingText != nil {
		base = *embeddingText
	}
	if includeBreadcrumb && len(base) > 0 {
		c := buildCrumb(name, includeDocName, lca, maxBreadcrumbChars)
		if len(c) > 0 {
			crumb = &c
			e := fmt.Sprintf("%s\n\n%s", c, base)
			embedding = &e
		} else {
			embedding = &base
		}
	} else if embeddingText != nil {
		var lastSection string
		if len(lca) > 0 {
			lastSection = lca[len(lca)-1]
		}
		if len(lastSection) > 0 {
			e := fmt.Sprintf("%s\n\n%s", lastSection, base)
			embedding = &e
		} else {
			embedding = &base
		}
	}
	srcLen := len([]byte(text))
	section := make([]string, len(lca))
	copy(section, lca)
	_ = strings.Join // import anchor
	return DocumentChunk{
		DocumentName:          name,
		Content:               text,
		Section:               section,
		ChunkIndex:            idx,
		SourceOffset:          offset,
		SourceLength:          srcLen,
		Breadcrumb:            crumb,
		EmbeddingContent:      embedding,
		ParagraphContinuation: paragraphContinuation,
	}
}

