// EnrichChunk returns a new DocumentChunk with EmbeddingContent set.
// Never mutates the input chunk.
func EnrichChunk(chunk DocumentChunk) DocumentChunk {
	var crumb string
	if chunk.Breadcrumb != nil && len(*chunk.Breadcrumb) > 0 {
		crumb = *chunk.Breadcrumb
	} else {
		var sectionParts []string
		if len(chunk.Section) > 0 {
			sectionParts = chunk.Section
		}
		var parts []string
		if len(chunk.DocumentName) > 0 {
			parts = append([]string{chunk.DocumentName}, sectionParts...)
		} else {
			parts = sectionParts
		}
		if len(parts) > 0 {
			crumb = fmt.Sprintf("[%s]", strings.Join(parts, " > "))
		}
	}
	var embeddingContent string
	if len(crumb) > 0 {
		embeddingContent = fmt.Sprintf("%s\n\n%s", crumb, chunk.Content)
	} else {
		embeddingContent = chunk.Content
	}
	result := chunk
	result.EmbeddingContent = &embeddingContent
	return result
}

