// Join waits for the background indexing goroutine to finish.
// timeout is optional: pass nil to wait indefinitely.
func (h *IndexHandle) Join(timeout *time.Duration) {
	if timeout == nil {
		h.wg.Wait()
		return
	}
	done := make(chan struct{})
	go func() {
		h.wg.Wait()
		close(done)
	}()
	select {
	case <-done:
	case <-time.After(*timeout):
	}
}

