func ingestGlob(loader *DocumentLoader, src map[string]any) ([]*DocumentChunk, error) {
	basePath, _ := src["path"].(string)
	pattern, _ := src["pattern"].(string)
	if pattern == "" {
		pattern = "*"
	}
	prefix, _ := src["name_prefix"].(string)
	docType, _ := src["doc_type"].(string)

	matches, err := filepath.Glob(filepath.Join(basePath, pattern))
	if err != nil {
		return nil, fmt.Errorf("ingestGlob: glob failed: %w", err)
	}
	// filter hidden files and sort
	var filtered []string
	for _, m := range matches {
		base := filepath.Base(m)
		if !strings.HasPrefix(base, ".") {
			filtered = append(filtered, m)
		}
	}
	sort.Strings(filtered)

	var chunks []*DocumentChunk
	for _, p := range filtered {
		stem := strings.TrimSuffix(filepath.Base(p), filepath.Ext(p))
		name := prefix + stem
		var sub []*DocumentChunk
		if docType != "" {
			data, err := os.ReadFile(p)
			if err != nil {
				return nil, fmt.Errorf("ingestGlob: read %q: %w", p, err)
			}
			sub, err = loader.LoadBytes(data, name, docType)
			if err != nil {
				return nil, err
			}
		} else {
			sub, err = loader.Load(p, name)
			if err != nil {
				return nil, err
			}
		}
		chunks = append(chunks, sub...)
	}
	return chunks, nil
}

func ingestJSONArray(loader *DocumentLoader, src map[string]any) ([]*DocumentChunk, error) {
	path, _ := src["path"].(string)
	arrayField, _ := src["array_field"].(string)
	idPathStr, _ := src["id_path"].(string)
	var idPath []string
	if idPathStr != "" {
		for _, part := range strings.Split(idPathStr, ".") {
			if part != "" {
				idPath = append(idPath, part)
			}
		}
	}

	raw, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("ingestJSONArray: read %q: %w", path, err)
	}
	var obj any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return nil, fmt.Errorf("ingestJSONArray: parse JSON: %w", err)
	}

	var items []any
	switch v := obj.(type) {
	case map[string]any:
		if arr, ok := v[arrayField].([]any); ok {
			items = arr
		}
	case []any:
		items = v
	}

	stem := strings.TrimSuffix(filepath.Base(path), filepath.Ext(path))
	var chunks []*DocumentChunk
	for _, item := range items {
		var nameVal any = item
		for _, key := range idPath {
			if m, ok := nameVal.(map[string]any); ok {
				nameVal = m[key]
			} else {
				nameVal = "unknown"
				break
			}
		}
		name := fmt.Sprintf("%v", nameVal)
		if name == "" || name == "<nil>" {
			name = stem
		}
		payload, err := json.Marshal(map[string]any{arrayField: []any{item}})
		if err != nil {
			return nil, fmt.Errorf("ingestJSONArray: marshal item: %w", err)
		}
		sub, err := loader.LoadBytes(payload, name, "json")
		if err != nil {
			return nil, err
		}
		chunks = append(chunks, sub...)
	}
	return chunks, nil
}

func ingestSQL(loader *DocumentLoader, src map[string]any) ([]*DocumentChunk, error) {
	connection, _ := src["connection"].(string)
	query := strings.TrimSpace(func() string { s, _ := src["query"].(string); return s }())
	name, _ := src["name"].(string)
	if name == "" {
		name = "sql_source"
	}
	nameCol, _ := src["name_col"].(string)
	contentCol, _ := src["content_col"].(string)

	if nameCol != "" && contentCol != "" {
		dbPath := strings.Replace(connection, "duckdb:///", "", 1)
		rows, colNames, err := duckdbQuery(dbPath, query)
		if err != nil {
			return nil, fmt.Errorf("ingestSQL: query: %w", err)
		}
		nameIdx := -1
		contentIdx := -1
		for i, col := range colNames {
			if col == nameCol {
				nameIdx = i
			}
			if col == contentCol {
				contentIdx = i
			}
		}
		if nameIdx < 0 {
			return nil, fmt.Errorf("ingestSQL: column %q not found", nameCol)
		}
		if contentIdx < 0 {
			return nil, fmt.Errorf("ingestSQL: column %q not found", contentCol)
		}
		var chunks []*DocumentChunk
		for _, row := range rows {
			rowName := fmt.Sprintf("%v", row[nameIdx])
			rowContent := fmt.Sprintf("%v", row[contentIdx])
			sub, err := loader.LoadBytes([]byte(rowContent), rowName, "text")
			if err != nil {
				return nil, err
			}
			chunks = append(chunks, sub...)
		}
		return chunks, nil
	}
	return loader.LoadFromDB(connection, map[string]string{name: query})
}

func embedChunks(chunks []*DocumentChunk, cfg map[string]any) ([][]float32, error) {
	var ec map[string]any
	if v, ok := cfg["embed"].(map[string]any); ok {
		ec = v
	}
	modelName := "BAAI/bge-large-en-v1.5"
	if v, ok := ec["model"].(string); ok && v != "" {
		modelName = v
	}
	batchSize := 256
	if v, ok := ec["batch_size"].(int); ok && v > 0 {
		batchSize = v
	}
	model, err := NewSentenceTransformer(modelName)
	if err != nil {
		return nil, fmt.Errorf("embedChunks: load model: %w", err)
	}
	texts := make([]string, 0, len(chunks))
	for _, c := range chunks {
		texts = append(texts, c.Content)
	}
	var allVecs [][]float32
	for i := 0; i < len(texts); i += batchSize {
		end := i + batchSize
		if end > len(texts) {
			end = len(texts)
		}
		v, err := model.Encode(texts[i:end])
		if err != nil {
			return nil, fmt.Errorf("embedChunks: encode batch %d: %w", i/batchSize, err)
		}
		allVecs = append(allVecs, v...)
		done := end
		if (i/batchSize)%10 == 0 {
			fmt.Printf("  embedded %d/%d\n", done, len(texts))
		}
	}
	return allVecs, nil
}

