// Note: batchSize=0 is treated as default 256 to avoid zero-value ambiguity.
func embedTexts(texts []string, modelName string, batchSize int) ([][]float32, error) {
	if batchSize <= 0 {
		batchSize = 256
	}
	model, err := NewSentenceTransformer(modelName)
	if err != nil {
		return nil, fmt.Errorf("embedTexts: load model: %w", err)
	}
	var allVecs [][]float32
	for i := 0; i < len(texts); i += batchSize {
		end := i + batchSize
		if end > len(texts) {
			end = len(texts)
		}
		v, err := model.Encode(texts[i:end])
		if err != nil {
			return nil, fmt.Errorf("embedTexts: encode batch at %d: %w", i, err)
		}
		allVecs = append(allVecs, v...)
	}
	return allVecs, nil
}

// Note: description is *string; nil means no description (distinct from empty string).
func (idx *Index) getOrRegisterDomain(namespaceID, domainName string, description *string) (string, error) {
	nsMap := idx.domainMap[namespaceID]
	if nsMap != nil {
		if did, ok := nsMap[domainName]; ok {
			return did, nil
		}
	}
	did := stableID(namespaceID, domainName)
	if err := idx.store.RegisterDomain(did, namespaceID, domainName, description); err != nil {
		return "", fmt.Errorf("getOrRegisterDomain: %w", err)
	}
	if idx.domainMap[namespaceID] == nil {
		idx.domainMap[namespaceID] = map[string]string{}
	}
	idx.domainMap[namespaceID][domainName] = did
	return did, nil
}

func (idx *Index) RemoveDomain(namespaceID, domainName string) (int, error) {
	nsMap := idx.domainMap[namespaceID]
	domainID, ok := nsMap[domainName]
	if !ok || domainID == "" {
		return 0, nil
	}
	n, err := idx.store.DeleteDomain(domainID)
	if err != nil {
		return 0, fmt.Errorf("RemoveDomain: %w", err)
	}
	if idx.domainMap[namespaceID] != nil {
		delete(idx.domainMap[namespaceID], domainName)
	}
	idx.invalidateSearch()
	return n, nil
}

// Note: async_ false blocks until all namespaces are rebuilt; true returns immediately.
func (idx *Index) Rebuild(namespaceID *string, async_ bool, cbs RebuildCallbacks) ([]*IndexHandle, error) {
	dbPath, err := idx.store.Vector.DBPath()
	if err != nil {
		return nil, fmt.Errorf("Rebuild: get db path: %w", err)
	}
	var namespaces []string
	if namespaceID != nil {
		namespaces = []string{*namespaceID}
	} else {
		for ns := range idx.domainMap {
			namespaces = append(namespaces, ns)
		}
	}
	nasOpts := BuildNamespaceOptions{
		RunNER:               boolFromMap(idx.indexCfg, "ner", true),
		RunCommunity:         boolFromMap(idx.indexCfg, "community", true),
		SpacyModel:           stringFromMap(idx.indexCfg, "spacy_model", "en_core_web_sm"),
		CommunityAlpha:       float64FromMap(idx.indexCfg, "community_alpha", 0.2),
		CommunitySimThreshold: float64FromMap(idx.indexCfg, "community_sim_threshold", 0.6),
		Force:                true,
		OnProgress:           cbs.OnProgress,
		OnComplete:           cbs.OnComplete,
		OnError:              cbs.OnError,
	}
	handles := make([]*IndexHandle, 0, len(namespaces))
	for _, ns := range namespaces {
		h, err := BuildNamespaceAsync(ns, dbPath, idx.embedModel, nasOpts)
		if err != nil {
			return nil, fmt.Errorf("Rebuild: start namespace %q: %w", ns, err)
		}
		handles = append(handles, h)
	}
	if !async_ {
		for _, h := range handles {
			h.Join(nil)
		}
		idx.invalidateSearch()
	}
	return handles, nil
}

type SearchOptions struct {
	K          *int    // nil → use search_defaults["k"] or 10
	Mode       *string // nil → use search_defaults["mode"] or "vector_first"
	Namespaces []string
	Domains    []string
	Extra      map[string]any
}

func (idx *Index) Search(query string, opts SearchOptions) ([]*ScoredChunk, error) {
	es, err := idx.getSearch()
	if err != nil {
		return nil, fmt.Errorf("Search: get search: %w", err)
	}
	callK := 10
	if opts.K != nil {
		callK = *opts.K
	} else if v, ok := idx.searchDefaults["k"].(int); ok {
		callK = v
	}
	callMode := "vector_first"
	if opts.Mode != nil {
		callMode = *opts.Mode
	} else if v, ok := idx.searchDefaults["mode"].(string); ok && v != "" {
		callMode = v
	}
	domainIDs := idx.resolveDomains(opts.Namespaces, opts.Domains)
	extra := opts.Extra
	if extra == nil {
		extra = map[string]any{}
	}
	if _, ok := extra["namespace_filter_llm_fn"]; !ok {
		extra["namespace_filter_llm_fn"] = idx.NamespaceFilterLLMFn
	}
	if _, ok := extra["domain_filter_llm_fn"]; !ok {
		extra["domain_filter_llm_fn"] = idx.DomainFilterLLMFn
	}
	return es.Search(SearchRequest{
		QueryText: query,
		K:         callK,
		Mode:      callMode,
		DomainIDs: domainIDs,
		Extra:     extra,
	})
}

