func buildSVOPhase(store *Store, ic map[string]any, svoModel string, force bool) error {
	var existing int
	row := store.Vector.Conn.QueryRow("SELECT COUNT(*) FROM svo_triples")
	if err := row.Scan(&existing); err != nil {
		return fmt.Errorf("buildSVOPhase: count triples: %w", err)
	}
	if existing == 0 || force {
		fmt.Printf("Building SVO graph via %q (calls LLM API)...\n", svoModel)
		var llmClient LLMClient
		if v := ic["svo_llm_client"]; v != nil {
			var ok bool
			llmClient, ok = v.(LLMClient)
			if !ok {
				return fmt.Errorf("buildSVOPhase: svo_llm_client does not implement LLMClient")
			}
		}
		if llmClient == nil {
			openAIClient, err := NewOpenAILLMClient(svoModel)
			if err != nil {
				return fmt.Errorf("buildSVOPhase: index.svo=true requires an OpenAI client or LLMClient in config: %w", err)
			}
			llmClient = openAIClient
		}
		extractor := NewSVOExtractor(llmClient)
		pipeline := NewEntityGraphPipeline(extractor)
		stats, err := pipeline.Build(store, force)
		if err != nil {
			return fmt.Errorf("buildSVOPhase: pipeline.Build: %w", err)
		}
		fmt.Printf("  %d triples.\n", stats.TriplesWritten)
	} else {
		fmt.Printf("SVO index: %d triples (skipped)\n", existing)
	}
	return nil
}

func Build(configInput any, force bool) (*Index, error) {
	var cfg map[string]any
	switch v := configInput.(type) {
	case map[string]any:
		cfg = v
	case string:
		data, err := os.ReadFile(v)
		if err != nil {
			return nil, fmt.Errorf("Build: read config %q: %w", v, err)
		}
		if err := yaml.Unmarshal(data, &cfg); err != nil {
			return nil, fmt.Errorf("Build: parse config: %w", err)
		}
	default:
		return nil, fmt.Errorf("Build: config must be a file path (string) or map[string]any")
	}

	sc, _ := cfg["store"].(map[string]any)
	if sc == nil {
		sc = map[string]any{}
	}
	dbPathStr, _ := sc["path"].(string)
	if dbPathStr == "" {
		return nil, fmt.Errorf("Build: store.path is required")
	}
	embeddingDim := 1024
	if v, ok := sc["embedding_dim"].(int); ok && v > 0 {
		embeddingDim = v
	}

	embedCfg, _ := cfg["embed"].(map[string]any)
	if embedCfg == nil {
		embedCfg = map[string]any{}
	}
	embedModelName := "BAAI/bge-large-en-v1.5"
	if v, ok := embedCfg["model"].(string); ok && v != "" {
		embedModelName = v
	}

	loaderCfg, _ := cfg["loader"].(map[string]any)
	if loaderCfg == nil {
		loaderCfg = map[string]any{}
	}
	ic, _ := cfg["index"].(map[string]any)
	if ic == nil {
		ic = map[string]any{}
	}
	runNER := boolFromMap(ic, "ner", true)
	runCommunity := boolFromMap(ic, "community", true)
	runSVO := boolFromMap(ic, "svo", false)
	spacyModel := stringFromMap(ic, "spacy_model", "en_core_web_sm")
	svoModel := stringFromMap(ic, "svo_model", "gpt-4o-mini")
	communityAlpha := float64FromMap(ic, "community_alpha", 0.2)
	communitySimThreshold := float64FromMap(ic, "community_sim_threshold", 0.6)

	searchDefaults := map[string]any{
		"entity_ref_expansion": true,
		"lane_entity_min_sim":  0.60,
	}
	if sv, ok := cfg["search"].(map[string]any); ok {
		for k, v := range sv {
			searchDefaults[k] = v
		}
	}

	store, err := buildIngestPhase(cfg, dbPathStr, embeddingDim, loaderCfg, embedCfg, force)
	if err != nil {
		return nil, fmt.Errorf("Build: ingest phase: %w", err)
	}

	if runNER {
		var existing int
		row := store.Vector.Conn.QueryRow("SELECT COUNT(*) FROM chunk_entities")
		if err := row.Scan(&existing); err != nil {
			return nil, fmt.Errorf("Build: NER count: %w", err)
		}
		if existing == 0 || force {
			fmt.Println("Building NER index...")
			if err := BuildNER(store, spacyModel); err != nil {
				return nil, fmt.Errorf("Build: NER: %w", err)
			}
			fmt.Println("  NER done.")
		} else {
			fmt.Printf("NER index: %d associations (skipped)\n", existing)
		}
	}

	if runCommunity {
		var existing int
		row := store.Vector.Conn.QueryRow("SELECT COUNT(*) FROM chunk_communities")
		if err := row.Scan(&existing); err != nil {
			return nil, fmt.Errorf("Build: community count: %w", err)
		}
		if existing == 0 || force {
			fmt.Println("Building community index...")
			n, err := BuildCommunity(dbPathStr, embedModelName, communityAlpha, communitySimThreshold, force)
			if err != nil {
				return nil, fmt.Errorf("Build: community: %w", err)
			}
			fmt.Printf("  %d communities.\n", n)
		} else {
			fmt.Printf("Community index: %d assignments (skipped)\n", existing)
		}
	}

	if runSVO {
		if err := buildSVOPhase(store, ic, svoModel, force); err != nil {
			return nil, fmt.Errorf("Build: SVO: %w", err)
		}
	}

	return NewIndex(store, embedModelName, searchDefaults, ic, loaderCfg, embedCfg)
}

func (idx *Index) AddSource(src map[string]any, rebuild bool, cbs RebuildCallbacks) (*IndexHandle, error) {
	namespaceID, _ := src["namespace"].(string)
	if namespaceID == "" {
		namespaceID = "global"
	}
	domainName, _ := src["domain"].(string)
	if domainName == "" {
		if n, ok := src["name"].(string); ok && n != "" {
			domainName = n
		} else if t, ok := src["type"].(string); ok && t != "" {
			domainName = t
		} else {
			domainName = "unnamed"
		}
	}

	var enrichPtr *bool
	if v, ok := src["enrich_context"].(bool); ok {
		enrichPtr = &v
	}
	loader, err := makeLoader(map[string]any{"loader": idx.loaderCfg}, enrichPtr)
	if err != nil {
		return nil, fmt.Errorf("AddSource: make loader: %w", err)
	}

	if idx.domainMap[namespaceID] == nil {
		if err := idx.store.RegisterNamespace(namespaceID, nil); err != nil {
			return nil, fmt.Errorf("AddSource: register namespace: %w", err)
		}
		idx.domainMap[namespaceID] = map[string]string{}
	}
	domainID, err := idx.getOrRegisterDomain(namespaceID, domainName, nil)
	if err != nil {
		return nil, fmt.Errorf("AddSource: register domain: %w", err)
	}

	chunks, err := ingestSource(src, loader)
	if err != nil {
		return nil, fmt.Errorf("AddSource: ingest: %w", err)
	}
	if len(chunks) == 0 {
		return nil, nil
	}

	texts := make([]string, 0, len(chunks))
	for _, c := range chunks {
		texts = append(texts, c.Content)
	}
	batchSize := 256
	if v, ok := idx.embedCfg["batch_size"].(int); ok && v > 0 {
		batchSize = v
	}
	emb, err := embedTexts(texts, idx.embedModel, batchSize)
	if err != nil {
		return nil, fmt.Errorf("AddSource: embed: %w", err)
	}
	if err := idx.store.AddDocument(chunks, emb, namespaceID, domainID); err != nil {
		return nil, fmt.Errorf("AddSource: store: %w", err)
	}
	if err := idx.store.Vector.RebuildFTSIndex(); err != nil {
		return nil, fmt.Errorf("AddSource: rebuild FTS: %w", err)
	}
	idx.invalidateSearch()

	if rebuild {
		dbPath, err := idx.store.Vector.DBPath()
		if err != nil {
			return nil, fmt.Errorf("AddSource: get db path: %w", err)
		}
		return BuildNamespaceAsync(namespaceID, dbPath, idx.embedModel, BuildNamespaceOptions{
			OnProgress:            cbs.OnProgress,
			OnComplete:            cbs.OnComplete,
			OnError:               cbs.OnError,
			Force:                 true,
			RunNER:                boolFromMap(idx.indexCfg, "ner", true),
			RunCommunity:          boolFromMap(idx.indexCfg, "community", true),
			SpacyModel:            stringFromMap(idx.indexCfg, "spacy_model", "en_core_web_sm"),
			CommunityAlpha:        float64FromMap(idx.indexCfg, "community_alpha", 0.2),
			CommunitySimThreshold: float64FromMap(idx.indexCfg, "community_sim_threshold", 0.6),
		})
	}
	return nil, nil
}

// BuildNamespaceAsyncOptions holds optional parameters for BuildNamespaceAsync.
// Note: CommunityAlpha and CommunitySimThreshold use *float64 to distinguish
// explicit 0.0 from "not set"; EmbedBatchSize uses *int for the same reason.
type BuildNamespaceAsyncOptions struct {
	OnProgress          func(phase string, done, total int)
	OnComplete          func(total int)
	OnError             func(phase string, err error)
	Force               bool
	RunNER              bool
	RunCommunity        bool
	SpacyModel          string
	CommunityAlpha      *float64 // default 0.2
	CommunitySimThreshold *float64 // default 0.6
	EmbedBatchSize      *int     // default 256
}

func defaultBuildOpts() BuildNamespaceAsyncOptions {
	alpha := 0.2
	sim := 0.6
	batch := 256
	return BuildNamespaceAsyncOptions{
		RunNER:               true,
		RunCommunity:         true,
		SpacyModel:           "en_core_web_sm",
		CommunityAlpha:       &alpha,
		CommunitySimThreshold: &sim,
		EmbedBatchSize:       &batch,
	}
}

func BuildNamespaceAsync(
	namespaceID string,
	dbPath string,
	embedModel string,
	opts BuildNamespaceAsyncOptions,
) *IndexHandle {
	onProgress := opts.OnProgress
	if onProgress == nil {
		onProgress = func(string, int, int) {}
	}
	onComplete := opts.OnComplete
	if onComplete == nil {
		onComplete = func(int) {}
	}
	onError := opts.OnError
	if onError == nil {
		onError = func(string, error) {}
	}

	run := func() {
		// pipeline body (see separate examples)
		_ = dbPath
		_ = onProgress
		_ = onComplete
		_ = onError
	}

	t := NewIndexHandleThread(run)
	return t
}

func run(dbPath string, namespaceID string, force bool,
	store *Store,
	onComplete func(int),
	onProgress func(string, int, int),
	indexer *Indexer,
) error {
	defer store.Close()

	if !force && store.NamespaceCacheValid(namespaceID) {
		count, err := store.Vector.CountEmbeddings(namespaceID)
		if err != nil {
			return fmt.Errorf("count embeddings: %w", err)
		}
		onComplete(count)
		return nil
	}

	sources, err := store.Vector.QuerySources(namespaceID)
	if err != nil {
		return fmt.Errorf("query sources: %w", err)
	}

	totalChunks := 0
	for _, src := range sources {
		var config map[string]interface{}
		if len(src.ConfigJSON) > 0 {
			if jsonErr := json.Unmarshal([]byte(src.ConfigJSON), &config); jsonErr != nil {
				return fmt.Errorf("parse config json for source %s: %w", src.SourceID, jsonErr)
			}
		} else {
			config = map[string]interface{}{}
		}
		config["source_id"] = src.SourceID
		config["type"] = src.SType
		config["uri"] = src.URI
		config["domain_id"] = src.DomainID
		config["namespace"] = namespaceID
		n, indexErr := indexer.IndexSource(config)
		if indexErr != nil {
			return fmt.Errorf("index source %s: %w", src.SourceID, indexErr)
		}
		totalChunks += n
	}
	return nil
