// NamespaceRefresher is a periodic background job that re-indexes stale namespaces.
type NamespaceRefresher struct {
	dbPathFn    func(namespaceID string) string
	embedModel  string
	interval    time.Duration
	onRebuild   func(namespaceID string)
	buildKwargs map[string]interface{}
	stop        chan struct{}
	thread      *sync.WaitGroup
	active      map[string]*IndexHandle
	lock        sync.Mutex
}

// NewNamespaceRefresher constructs a NamespaceRefresher.
// Note: intervalSeconds uses *int so callers can distinguish explicit 0 from unset;
// passing nil uses the default of 3600 seconds.
func NewNamespaceRefresher(
	dbPathFn func(namespaceID string) string,
	embedModel string,
	intervalSeconds *int,
	onRebuild func(namespaceID string),
	buildKwargs map[string]interface{},
) *NamespaceRefresher {
	seconds := 3600
	if intervalSeconds != nil {
		seconds = *intervalSeconds
	}
	if onRebuild == nil {
		onRebuild = func(string) {}
	}
	if buildKwargs == nil {
		buildKwargs = map[string]interface{}{}
	}
	return &NamespaceRefresher{
		dbPathFn:    dbPathFn,
		embedModel:  embedModel,
		interval:    time.Duration(seconds) * time.Second,
		onRebuild:   onRebuild,
		buildKwargs: buildKwargs,
		stop:        make(chan struct{}),
		thread:      &sync.WaitGroup{},
		active:      map[string]*IndexHandle{},
	}
}

