// Start starts the background refresh loop (non-blocking).
func (r *NamespaceRefresher) Start() {
	r.stop = make(chan struct{})
	r.thread.Add(1)
	go func() {
		defer r.thread.Done()
		r.loop()
	}()
}

// Stop stops the refresh loop and waits for the loop goroutine to exit.
func (r *NamespaceRefresher) Stop() {
	close(r.stop)
	r.thread.Wait()
}

// DocumentLoader orchestrates the full pipeline: fetch bytes → extract text → chunk → enrich.
type DocumentLoader struct {
	MinChunkSize       int
	MaxChunkSize       int
	OverflowMargin     float64
	EnrichContext      bool
	IncludeDocName     bool
	extraTransports    []Transport
	extraExtractors    []Extractor
	transportRegistry  []Transport
}

// DocumentLoaderOptions holds optional overrides for NewDocumentLoader.
// Note: MinChunkSize, MaxChunkSize, OverflowMargin use pointer types to
// distinguish explicit zero from "use default".
type DocumentLoaderOptions struct {
	MinChunkSize    *int
	MaxChunkSize    *int
	OverflowMargin  *float64
	EnrichContext   *bool
	IncludeDocName  *bool
	ExtraTransports []Transport
	ExtraExtractors []Extractor
}

// NewDocumentLoader constructs a DocumentLoader with defaults applied for any nil option.
func NewDocumentLoader(opts DocumentLoaderOptions) *DocumentLoader {
	minChunk := 600
	if opts.MinChunkSize != nil {
		minChunk = *opts.MinChunkSize
	}
	maxChunk := 1500
	if opts.MaxChunkSize != nil {
		maxChunk = *opts.MaxChunkSize
	}
	overflowMargin := 0.15
	if opts.OverflowMargin != nil {
		overflowMargin = *opts.OverflowMargin
	}
	enrichContext := true
	if opts.EnrichContext != nil {
		enrichContext = *opts.EnrichContext
	}
	includeDocName := true
	if opts.IncludeDocName != nil {
		includeDocName = *opts.IncludeDocName
	}
	extraTransports := opts.ExtraTransports
	if extraTransports == nil {
		extraTransports = []Transport{}
	}
	extraExtractors := opts.ExtraExtractors
	if extraExtractors == nil {
		extraExtractors = []Extractor{}
	}

	registry := make([]Transport, 0, len(extraTransports)+5)
	registry = append(registry, extraTransports...)
	registry = append(registry,
		NewLocalTransport(),
		NewHttpTransport(),
		NewS3Transport(),
		NewFtpTransport(),
		NewSftpTransport(),
	)

	return &DocumentLoader{
		MinChunkSize:      minChunk,
		MaxChunkSize:      maxChunk,
		OverflowMargin:    overflowMargin,
		EnrichContext:     enrichContext,
		IncludeDocName:    includeDocName,
		extraTransports:   extraTransports,
		extraExtractors:   extraExtractors,
		transportRegistry: registry,
	}
}

