// findTransport iterates the registry and returns the first transport that can handle uri.
func (dl *DocumentLoader) findTransport(uri string) (Transport, error) {
	for _, transport := range dl.transportRegistry {
		if transport.CanHandle(uri) {
			return transport, nil
		}
	}
	return nil, fmt.Errorf("no transport found for URI: %q", uri)
}

// findExtractor checks extra extractors first, then falls back to DetectExtractor.
func (dl *DocumentLoader) findExtractor(docType string) (Extractor, error) {
	for _, extractor := range dl.extraExtractors {
		if extractor.CanHandle(docType) {
			return extractor, nil
		}
	}
	return DetectExtractor(docType)
}

var structuredExtensions = map[string]struct{}{
	".parquet": {}, ".arrow": {}, ".feather": {},
	".csv": {}, ".json": {}, ".jsonl": {}, ".ndjson": {},
}

// Load fetches, extracts, chunks, and enriches the document at uri.
// name is optional; pass empty string to derive from the URI path stem.
func (dl *DocumentLoader) Load(uri string, name string) ([]DocumentChunk, error) {
	ext := strings.ToLower(filepath.Ext(uri))
	if _, ok := structuredExtensions[ext]; ok {
		return dl.LoadStructuredFile(uri, name)
	}

	transport, err := dl.findTransport(uri)
	if err != nil {
		return nil, fmt.Errorf("load %s: %w", uri, err)
	}
	result, err := transport.Fetch(uri)
	if err != nil {
		return nil, fmt.Errorf("fetch %s: %w", uri, err)
	}

	sourcePath := result.SourcePath
	if sourcePath == "" {
		sourcePath = uri
	}
	docType, err := DetectTypeFromSource(sourcePath, result.DetectedMime)
	if err != nil {
		return nil, fmt.Errorf("detect type: %w", err)
	}
	extractor, err := dl.findExtractor(docType)
	if err != nil {
		return nil, fmt.Errorf("find extractor: %w", err)
	}
	text, err := extractor.Extract(result.Data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("extract text: %w", err)
	}

	docName := name
	if docName == "" {
		docName = strings.TrimSuffix(filepath.Base(sourcePath), filepath.Ext(sourcePath))
	}

	chunks, err := ChunkDocument(docName, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
	if err != nil {
		return nil, fmt.Errorf("chunk document: %w", err)
	}
	chunks, err = extractor.Annotate(chunks, result.Data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("annotate chunks: %w", err)
	}
	return dl.enrich(chunks)
}

// LoadBytes skips fetch and extracts from raw bytes.
// Pass docType="auto" to detect type from sourcePath or name.
// Note: sourcePath is optional; pass empty string when not available.
func (dl *DocumentLoader) LoadBytes(data []byte, name string, docType string, sourcePath string) ([]DocumentChunk, error) {
	var extractor Extractor
	var err error
	if docType == "auto" {
		hint := sourcePath
		if hint == "" {
			hint = name
		}
		resolvedType, typeErr := DetectTypeFromSource(hint, "")
		if typeErr != nil {
			return nil, fmt.Errorf("detect type: %w", typeErr)
		}
		extractor, err = dl.findExtractor(resolvedType)
	} else {
		extractor, err = dl.findExtractorRaw(docType)
	}
	if err != nil {
		return nil, fmt.Errorf("find extractor: %w", err)
	}

	text, err := extractor.Extract(data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("extract text: %w", err)
	}

	chunks, err := ChunkDocument(name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
	if err != nil {
		return nil, fmt.Errorf("chunk document: %w", err)
	}
	chunks, err = extractor.Annotate(chunks, data, sourcePath)
	if err != nil {
		return nil, fmt.Errorf("annotate chunks: %w", err)
	}
	return dl.enrich(chunks)
}

// LoadQuery executes a SQL query via a SQLAlchemy-equivalent transport and returns chunks.
// params may be nil when there are no bind parameters.
func (dl *DocumentLoader) LoadQuery(
	connectionURL string,
	query string,
	name string,
	params map[string]interface{},
) ([]DocumentChunk, error) {
	transport := NewSqlAlchemyTransport(connectionURL, query, params)
	result, err := transport.Fetch(fmt.Sprintf("sqlalchemy://%s", name))
	if err != nil {
		return nil, fmt.Errorf("sql fetch: %w", err)
	}
	text, err := NewCsvExtractor().Extract(result.Data, "")
	if err != nil {
		return nil, fmt.Errorf("csv extract: %w", err)
	}
	chunks, err := ChunkDocument(name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
	if err != nil {
		return nil, fmt.Errorf("chunk document: %w", err)
	}
	return dl.enrich(chunks)
}

// NameSQLPair holds a document name and its corresponding SQL query.
type NameSQLPair struct {
	Name string
	SQL  string
}

// LoadFromDB executes SQL queries against a live connection and returns chunks.
// Note: docType defaults to "csv" when empty string is passed.
func (dl *DocumentLoader) LoadFromDB(
	connection DBConnection,
	queries []NameSQLPair,
	docType string,
) ([]DocumentChunk, error) {
	if docType == "" {
		docType = "csv"
	}
	transport := NewSqlQueryTransport(connection)
	extractor, err := dl.findExtractor(docType)
	if err != nil {
		return nil, fmt.Errorf("find extractor: %w", err)
	}
	provenance, err := DBProvenance(connection)
	if err != nil {
		return nil, fmt.Errorf("db provenance: %w", err)
	}

	var allChunks []DocumentChunk
	for _, pair := range queries {
		result, fetchErr := transport.Fetch(fmt.Sprintf("sqlquery://%s", pair.Name), pair.SQL)
		if fetchErr != nil {
			return nil, fmt.Errorf("fetch query %s: %w", pair.Name, fetchErr)
		}
		text, extractErr := extractor.Extract(result.Data, pair.Name)
		if extractErr != nil {
			return nil, fmt.Errorf("extract %s: %w", pair.Name, extractErr)
		}
		chunks, chunkErr := ChunkDocument(pair.Name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
		if chunkErr != nil {
			return nil, fmt.Errorf("chunk %s: %w", pair.Name, chunkErr)
		}
		chunks, annotErr := extractor.Annotate(chunks, result.Data, pair.Name)
		if annotErr != nil {
			return nil, fmt.Errorf("annotate %s: %w", pair.Name, annotErr)
		}
		for i := range chunks {
			if chunks[i].SourceDetail == nil {
				chunks[i].SourceDetail = map[string]interface{}{}
			}
			chunks[i].SourceDetail["query"] = pair.SQL
			for k, v := range provenance {
				chunks[i].SourceDetail[k] = v
			}
		}
		enriched, enrichErr := dl.enrich(chunks)
		if enrichErr != nil {
			return nil, fmt.Errorf("enrich %s: %w", pair.Name, enrichErr)
		}
		allChunks = append(allChunks, enriched...)
	}
	return allChunks, nil
}

// CassandraOptions holds optional Cassandra connection parameters.
