// LoadAPI builds N+1 DocumentChunks per endpoint (one endpoint chunk + one per field).
func (dl *DocumentLoader) LoadAPI(endpoints []EndpointMeta) ([]DocumentChunk, error) {
	graphqlChunkTypes := map[string]string{
		"graphql_query":    "api_graphql_query",
		"graphql_mutation": "api_graphql_mutation",
		"graphql_type":     "api_graphql_type",
	}

	var chunks []DocumentChunk
	for _, endpoint := range endpoints {
		apiPrefix := endpoint.SourceAPI
		if apiPrefix == "" {
			apiPrefix = "api"
		}
		docName := fmt.Sprintf("api:%s.%s", apiPrefix, endpoint.Path)
		chunkType, ok := graphqlChunkTypes[endpoint.EndpointType]
		if !ok {
			chunkType = "api_endpoint"
		}

		lines := []string{fmt.Sprintf("Endpoint: %s", endpoint.Path)}
		if endpoint.Method != "" {
			lines = append(lines, fmt.Sprintf("Method: %s", endpoint.Method))
		}
		lines = append(lines, fmt.Sprintf("Type: %s", endpoint.EndpointType))
		if endpoint.SourceAPI != "" {
			lines = append(lines, fmt.Sprintf("Source API: %s", endpoint.SourceAPI))
		}
		if endpoint.Description != "" {
			lines = append(lines, fmt.Sprintf("Description: %s", endpoint.Description))
		}
		if len(endpoint.Fields) > 0 {
			fieldNames := make([]string, len(endpoint.Fields))
			for i, f := range endpoint.Fields {
				fieldNames[i] = f.Name
			}
			lines = append(lines, fmt.Sprintf("Fields: %s", strings.Join(fieldNames, ", ")))
		}
		chunks = append(chunks, DocumentChunk{
			DocumentName: docName,
			Content:      strings.Join(lines, "\n"),
			Section:      []string{},
			ChunkIndex:   0,
			ChunkType:    chunkType,
		})

		for fieldIdx, fld := range endpoint.Fields {
			fieldDocName := fmt.Sprintf("api:%s.%s.%s", apiPrefix, endpoint.Path, fld.Name)
			required := "no"
			if fld.Required {
				required = "yes"
			}
			fieldLines := []string{
				fmt.Sprintf("Field: %s", fld.Name),
				fmt.Sprintf("Endpoint: %s", endpoint.Path),
				fmt.Sprintf("Type: %s", fld.FieldType),
				fmt.Sprintf("Required: %s", required),
			}
			if fld.Description != "" {
				fieldLines = append(fieldLines, fmt.Sprintf("Description: %s", fld.Description))
			}
			chunks = append(chunks, DocumentChunk{
				DocumentName: fieldDocName,
				Content:      strings.Join(fieldLines, "\n"),
				Section:      []string{},
				ChunkIndex:   fieldIdx + 1,
				ChunkType:    "api_field",
			})
		}
	}
	return dl.enrich(chunks)
}

