// LoadCrawl crawls uri with the provided Crawler and loads each discovered document.
// Pass nil for crawler to auto-select WebCrawler for http(s) or DirectoryCrawler otherwise.
func (dl *DocumentLoader) LoadCrawl(uri string, crawler Crawler) ([]DocumentChunk, error) {
	if crawler == nil {
		if strings.HasPrefix(uri, "http://") || strings.HasPrefix(uri, "https://") {
			crawler = NewWebCrawler()
		} else {
			crawler = NewDirectoryCrawler()
		}
	}

	uris, err := crawler.Crawl(uri)
	if err != nil {
		return nil, fmt.Errorf("crawl %s: %w", uri, err)
	}
	log.Printf("load_crawl: %d URI(s) discovered from %s", len(uris), uri)

	var allChunks []DocumentChunk
	for _, docURI := range uris {
		chunks, loadErr := dl.Load(docURI, "")
		if loadErr != nil {
			log.Printf("load_crawl: skipping %s: %v", docURI, loadErr)
			continue
		}
		allChunks = append(allChunks, chunks...)
	}
	return allChunks, nil
}

// LoadSiteOptions holds optional parameters for LoadSite.
// Note: MaxPages and MaxDepth use *int to distinguish explicit 0 from default values.
type LoadSiteOptions struct {
	MaxPages        *int     // default 50
	MaxDepth        *int     // default 3
	SameDomain      *bool    // default true
	ExcludePatterns []string // nil means no exclusions
	IncludePattern  string   // empty string means include all
	Crawler         Crawler  // nil means auto-construct WebCrawler
}

// LoadSite crawls a website and loads all discovered HTML pages.
func (dl *DocumentLoader) LoadSite(url string, opts LoadSiteOptions) ([]DocumentChunk, error) {
	crawler := opts.Crawler
	if crawler == nil {
		maxPages := 50
		if opts.MaxPages != nil {
			maxPages = *opts.MaxPages
		}
		maxDepth := 3
		if opts.MaxDepth != nil {
			maxDepth = *opts.MaxDepth
		}
		sameDomain := true
		if opts.SameDomain != nil {
			sameDomain = *opts.SameDomain
		}
		crawler = NewWebCrawler(maxPages, maxDepth, sameDomain, opts.ExcludePatterns, opts.IncludePattern)
	}
	return dl.LoadCrawl(url, crawler)
}

// LoadText skips fetch and extract; chunks and enriches pre-extracted plain text.
func (dl *DocumentLoader) LoadText(text string, name string) ([]DocumentChunk, error) {
	chunks, err := ChunkDocument(
		name, text,
		dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin,
		dl.EnrichContext, dl.IncludeDocName,
	)
	if err != nil {
		return nil, fmt.Errorf("chunk document: %w", err)
	}
	return dl.enrich(chunks)
}

import (
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"log/slog"
	"strings"
)

func processQueueJob(
	log *slog.Logger,
	backend Backend,
	sourceURI string,
	namespace string,
	embedModel string,
	batchSize int,
	runNER bool,
	spacyModel string,
) error {
	loader := NewDocumentLoader()
	chunks, err := loader.Load(sourceURI)
	if err != nil {
		return fmt.Errorf("processQueueJob: failed to load %q: %w", sourceURI, err)
	}
	if len(chunks) == 0 {
		log.Warn("No chunks produced from source", "source_uri", sourceURI)
		return nil
	}

	var sb strings.Builder
	for i, c := range chunks {
		if i > 0 {
			sb.WriteByte('\n')
		}
		sb.WriteString(c.Content)
	}
	hashBytes := sha256.Sum256([]byte(sb.String()))
	contentHash := hex.EncodeToString(hashBytes[:])[:32]

	contents := make([]string, len(chunks))
	for i, c := range chunks {
		contents[i] = c.Content
	}
	emb, err := embedTexts(contents, embedModel, batchSize)
	if err != nil {
		return fmt.Errorf("processQueueJob: embed: %w", err)
	}
	if err := backend.AddChunks(chunks, emb, namespace); err != nil {
		return fmt.Errorf("processQueueJob: add_chunks: %w", err)
	}
	if err := backend.RegisterDocument(chunks[0].DocumentName, contentHash, sourceURI, len(chunks)); err != nil {
		return fmt.Errorf("processQueueJob: register_document: %w", err)
	}
	return nil
}

import (
	"database/sql"
	"fmt"
	"log/slog"
	"time"
)

// workerLoop runs the main poll-and-process loop until ctx is cancelled.
func workerLoop(
	log *slog.Logger,
	queueDB *sql.DB,
	backend Backend,
	workerID string,
	embedModel string,
	batchSize int,
	runNER bool,
	spacyModel string,
	idleSleep time.Duration,
) error {
	for {
		// Check pause flag
		var pausedVal string
		err := queueDB.QueryRow("SELECT value FROM control WHERE key = 'workers_paused'").Scan(&pausedVal)
		if err != nil && err != sql.ErrNoRows {
			return fmt.Errorf("workerLoop: query pause flag: %w", err)
		}
		if pausedVal == "1" {
			time.Sleep(idleSleep)
			continue
		}

		// Claim next pending item (SKIP LOCKED prevents double-assignment)
		tx, err := queueDB.Begin()
		if err != nil {
			return fmt.Errorf("workerLoop: begin tx: %w", err)
		}
		var jobID int64
		var sourceURI, namespace string
		err = tx.QueryRow(`
			UPDATE ingest_queue
			SET status = 'processing', worker_id = $1, leased_at = now()
			WHERE id = (
				SELECT id FROM ingest_queue
				WHERE status = 'pending'
				LIMIT 1
				FOR UPDATE SKIP LOCKED
			)
			RETURNING id, source_uri, namespace`,
			workerID,
		).Scan(&jobID, &sourceURI, &namespace)
		if err == sql.ErrNoRows {
			_ = tx.Rollback()
			time.Sleep(idleSleep)
			continue
		}
		if err != nil {
			_ = tx.Rollback()
			return fmt.Errorf("workerLoop: claim job: %w", err)
		}
		if err := tx.Commit(); err != nil {
			return fmt.Errorf("workerLoop: commit claim: %w", err)
		}

		log.Info("Worker processing job", "worker_id", workerID, "job_id", jobID, "source_uri", sourceURI)

		processErr := processQueueJob(log, backend, sourceURI, namespace, embedModel, batchSize, runNER, spacyModel)
		newStatus := "done"
		if processErr != nil {
			log.Error("Job failed", "job_id", jobID, "error", processErr)
			newStatus = "failed"
		}
		if _, err := queueDB.Exec("UPDATE ingest_queue SET status = $1 WHERE id = $2", newStatus, jobID); err != nil {
			return fmt.Errorf("workerLoop: update job status: %w", err)
		}
	}
}

