func fetchNamespaces(log *slog.Logger, db *sql.DB) ([]string, error) {
	rows, err := db.Query("SELECT DISTINCT namespace FROM embeddings WHERE namespace IS NOT NULL")
	if err != nil {
		return nil, fmt.Errorf("fetchNamespaces: query: %w", err)
	}
	defer rows.Close()

	var namespaces []string
	for rows.Next() {
		var ns string
		if err := rows.Scan(&ns); err != nil {
			return nil, fmt.Errorf("fetchNamespaces: scan: %w", err)
		}
		namespaces = append(namespaces, ns)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("fetchNamespaces: rows err: %w", err)
	}

	if len(namespaces) == 0 {
		log.Info("No namespaces found; skipping graph build.")
		return nil, nil
	}
	for _, ns := range namespaces {
		log.Info("Building community graph for namespace", "namespace", ns)
	}
	return namespaces, nil
}

