type ChunkRow struct {
	ChunkID     string
	DocName     string
	Content     string
	SectionStr  string
	ChunkIdx    int
	Breadcrumb  string
	ChunkType   string
	SrcOff      int
	SrcLen      int
	SrcDetStr   string
	SrcID       string
	DomID       string
	EmbeddingVec []float32
}

func assembleChunks(chunkRows []ChunkRow) ([]DocumentChunk, [][]float32, error) {
	tmpChunks := make([]DocumentChunk, 0, len(chunkRows))
	tmpEmbeddings := make([][]float32, 0, len(chunkRows))

	for _, row := range chunkRows {
		var sec []string
		if len(row.SectionStr) > 0 {
			if err := json.Unmarshal([]byte(row.SectionStr), &sec); err != nil {
				return nil, nil, fmt.Errorf("assembleChunks: parse section: %w", err)
			}
		}
		var srcDet map[string]interface{}
		if len(row.SrcDetStr) > 0 {
			if err := json.Unmarshal([]byte(row.SrcDetStr), &srcDet); err != nil {
				return nil, nil, fmt.Errorf("assembleChunks: parse source_detail: %w", err)
			}
		}
		chunkType := row.ChunkType
		if len(chunkType) == 0 {
			chunkType = "document"
		}
		tmpChunks = append(tmpChunks, DocumentChunk{
			DocumentName: row.DocName,
			Content:      row.Content,
			Section:      sec,
			ChunkIndex:   row.ChunkIdx,
			Breadcrumb:   row.Breadcrumb,
			ChunkType:    chunkType,
			SourceOffset: row.SrcOff,
			SourceLength: row.SrcLen,
			SourceDetail: srcDet,
		})
		embVec := make([]float32, len(row.EmbeddingVec))
		copy(embVec, row.EmbeddingVec)
		tmpEmbeddings = append(tmpEmbeddings, embVec)
	}
	return tmpChunks, tmpEmbeddings, nil
}

