import (
	"encoding/json"
	"fmt"
)

func inferJSON(data []byte, name string) (*TableMeta, error) {
	var raw interface{}
	if err := json.Unmarshal(data, &raw); err != nil {
		return nil, fmt.Errorf("inferJSON: cannot parse JSON for %q: %w", name, err)
	}

	switch obj := raw.(type) {
	case []interface{}:
		keyTypes := make(map[string]string)
		keyOrder := make([]string, 0)
		limit := 100
		if len(obj) < limit {
			limit = len(obj)
		}
		for i := 0; i < limit; i++ {
			item := obj[i]
			if m, ok := item.(map[string]interface{}); ok {
				for k, v := range m {
					if _, exists := keyTypes[k]; !exists {
						keyTypes[k] = pythonTypeToStr(v)
						keyOrder = append(keyOrder, k)
					}
				}
			}
		}
		columns := make([]ColumnMeta, 0, len(keyOrder))
		for _, k := range keyOrder {
			columns = append(columns, ColumnMeta{Name: k, DataType: keyTypes[k]})
		}
		rowCount := len(obj)
		return &TableMeta{Name: name, Columns: columns, RowCount: &rowCount}, nil

	case map[string]interface{}:
		type kv struct{ k string; v interface{} }
		pairs := make([]kv, 0, len(obj))
		for k, v := range obj {
			pairs = append(pairs, kv{k, v})
			if len(pairs) == 100 {
				break
			}
		}
		columns := make([]ColumnMeta, 0, len(pairs))
		for _, p := range pairs {
			columns = append(columns, ColumnMeta{Name: p.k, DataType: pythonTypeToStr(p.v)})
		}
		rowCount := 1
		return &TableMeta{Name: name, Columns: columns, RowCount: &rowCount}, nil
	}

	return &TableMeta{Name: name}, nil
}

