import (
	"fmt"
	"sync"
)

// VersionedRef is a thread-safe versioned holder for any value of type T.
// Version is 0 when constructed with an initial value, -1 when constructed without one.
type VersionedRef[T any] struct {
	current *T
	pending *T
	version int
	mu      sync.Mutex
}

// NewVersionedRef constructs a VersionedRef.
// Pass a non-nil pointer to set an initial value (version 0); pass nil for unset (version -1).
// Note: initial is *T so that a zero-value T is distinguishable from "no initial value".
func NewVersionedRef[T any](initial *T) *VersionedRef[T] {
	v := &VersionedRef[T]{pending: nil}
	if initial != nil {
		v.current = initial
		v.version = 0
	} else {
		v.version = -1
	}
	return v
}

// Current returns the active value or nil if no value has been set.
func (r *VersionedRef[T]) Current() *T {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.current
}

// Version returns the monotonically increasing version counter. -1 means never set.
func (r *VersionedRef[T]) Version() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.version
}

// HasPending returns true if a staged value is waiting to be promoted.
func (r *VersionedRef[T]) HasPending() bool {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.pending != nil
}

// Update atomically replaces the current value, clears pending, increments version.
func (r *VersionedRef[T]) Update(value T) int {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.current = &value
	r.pending = nil
	r.version++
	return r.version
}

// Stage stores a pending value without activating it.
func (r *VersionedRef[T]) Stage(value T) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.pending = &value
}

// Promote activates the staged value as current. Returns new version or error if nothing staged.
func (r *VersionedRef[T]) Promote() (int, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	if r.pending == nil {
		return 0, fmt.Errorf("promote: called with nothing staged")
	}
	r.current = r.pending
	r.pending = nil
	r.version++
	return r.version, nil
}

// DiscardStaged discards the staged value without promoting it.
func (r *VersionedRef[T]) DiscardStaged() {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.pending = nil
}

