// ClusterEntitiesOptions holds optional parameters for ClusterEntities.
// Note: Algorithm defaults to "agglomerative"; DistanceThreshold defaults to 0.5.
type ClusterEntitiesOptions struct {
	Algorithm         string
	DistanceThreshold float64
}

func ClusterEntities(
	cooccurrence map[[2]string]float64,
	entities []string,
	opts ClusterEntitiesOptions,
) (map[string]string, error) {
	if opts.Algorithm == "" {
		opts.Algorithm = "agglomerative"
	}
	if opts.DistanceThreshold == 0.0 {
		opts.DistanceThreshold = 0.5
	}
	if len(entities) == 0 {
		return map[string]string{}, nil
	}
	switch opts.Algorithm {
	case "agglomerative":
		return agglomerative(cooccurrence, entities, opts.DistanceThreshold)
	case "dbscan":
		return dbscan(cooccurrence, entities, opts.DistanceThreshold)
	case "leiden":
		return leiden(cooccurrence, entities, opts.DistanceThreshold)
	default:
		return nil, fmt.Errorf("unknown clustering algorithm: %q", opts.Algorithm)
	}
}

// agglomerative builds a distance matrix and runs agglomerative clustering.
// Note: This is a pure-Go skeleton; actual sklearn AgglomerativeClustering
// must be called via cgo or a subprocess. This implements the matrix-build step
// and label-format step that surround the sklearn call.
func agglomerative(
	cooccurrence map[[2]string]float64,
	entities []string,
	distanceThreshold float64,
) (map[string]string, error) {
	n := len(entities)
	idx := make(map[string]int, n)
	for i, e := range entities {
		idx[e] = i
	}

	// Build distance matrix initialised to 1.0
	dist := make([][]float64, n)
	for i := range dist {
		dist[i] = make([]float64, n)
		for j := range dist[i] {
			dist[i][j] = 1.0
		}
		dist[i][i] = 0.0
	}

	// Min-max normalisation
	var lo, span float64
	if len(cooccurrence) > 0 {
		lo = math.MaxFloat64
		hi := -math.MaxFloat64
		for _, v := range cooccurrence {
			if v < lo {
				lo = v
			}
			if v > hi {
				hi = v
			}
		}
		span = hi - lo
	}

	for pair, score := range cooccurrence {
		a, b := pair[0], pair[1]
		ai, aok := idx[a]
		bi, bok := idx[b]
		if !aok || !bok {
			continue
		}
		var sim float64
		if span > 0 {
			sim = (score - lo) / span
		} else {
			sim = 1.0
		}
		d := math.Max(0.0, 1.0-sim)
		dist[ai][bi] = d
		dist[bi][ai] = d
	}

	// TODO: invoke sklearn AgglomerativeClustering via subprocess/cgo with distanceThreshold
	// labels []int must be populated from the external call.
	labels := make([]int, n) // placeholder

	result := make(map[string]string, n)
	for i, e := range entities {
		result[e] = fmt.Sprintf("cluster_%04d", labels[i])
	}
	return result, nil
}

