// normalise computes a normalised co-occurrence score.
func (m *CooccurrenceMatrix) normalise(count, dfA, dfB, total int) (float64, error) {
	switch m.normalization {
	case "raw":
		return float64(count), nil
	case "jaccard":
		union := dfA + dfB - count
		if union > 0 {
			return float64(count) / float64(union), nil
		}
		return 0.0, nil
	default:
		// PMI
		t := float64(total)
		pAB := float64(count) / t
		pA := float64(dfA) / t
		pB := float64(dfB) / t
		if pA == 0 || pB == 0 || pAB == 0 {
			return 0.0, nil
		}
		return math.Log2(pAB / (pA * pB)), nil
	}
}

