// buildFromAssignments populates the ClusterMap from entity→cluster assignments.
func (cm *ClusterMap) buildFromAssignments(
	assignments map[string]string,
	cooccurrence map[[2]string]float64,
) error {
	cm.entityToCluster = make(map[string]string, len(assignments))
	for k, v := range assignments {
		cm.entityToCluster[k] = v
	}

	cm.clusterToEntities = make(map[string][]string)
	for entityID, clusterID := range assignments {
		cm.clusterToEntities[clusterID] = append(cm.clusterToEntities[clusterID], entityID)
	}

	cm.clusters = make(map[string]ClusterRecord)
	for clusterID, members := range cm.clusterToEntities {
		var intraScores []float64
		for i := 0; i < len(members); i++ {
			for j := i + 1; j < len(members); j++ {
				a, b := members[i], members[j]
				if a > b {
					a, b = b, a
				}
				pair := [2]string{a, b}
				if score, ok := cooccurrence[pair]; ok {
					intraScores = append(intraScores, score)
				}
			}
		}
		var cohesion float64
		if len(intraScores) > 0 {
			sum := 0.0
			for _, s := range intraScores {
				sum += s
			}
			cohesion = math.Round((sum/float64(len(intraScores)))*10000) / 10000
		}
		membersCopy := make([]string, len(members))
		copy(membersCopy, members)
		cm.clusters[clusterID] = ClusterRecord{
			ClusterID:    clusterID,
			Entities:     membersCopy,
			CohesionScore: cohesion,
		}
	}
	return nil
}

