// ClusterMapFromDict reconstructs a ClusterMap from a serialised map.
func ClusterMapFromDict(data map[string]interface{}) (*ClusterMap, error) {
	instance := NewClusterMap()

	if rawAssign, ok := data["assignments"]; ok {
		if assignMap, ok := rawAssign.(map[string]string); ok {
			for k, v := range assignMap {
				instance.entityToCluster[k] = v
			}
		}
	}

	if rawClusters, ok := data["clusters"]; ok {
		if clustersMap, ok := rawClusters.(map[string]interface{}); ok {
			for _, rawCD := range clustersMap {
				cd, ok := rawCD.(map[string]interface{})
				if !ok {
					continue
				}
				cid, _ := cd["cluster_id"].(string)
				var members []string
				if rawMembers, ok := cd["entities"]; ok {
					if ms, ok := rawMembers.([]string); ok {
						members = ms
					}
				}
				var cohesion float64
				if rawC, ok := cd["cohesion_score"]; ok {
					if cf, ok := rawC.(float64); ok {
						cohesion = cf
					}
				}
				instance.clusterToEntities[cid] = members
				instance.clusters[cid] = ClusterRecord{
					ClusterID:    cid,
					Entities:     members,
					CohesionScore: cohesion,
				}
			}
		}
	}
	return instance, nil
}

