// assignDBSCANLabels converts DBSCAN integer labels to string cluster IDs,
// promoting noise labels (-1) to unique singleton clusters.
func assignDBSCANLabels(entities []string, labels []int) map[string]string {
	// Find max non-noise label to seed the singleton counter
	clusterCounter := -1
	for _, lbl := range labels {
		if lbl >= 0 && lbl > clusterCounter {
			clusterCounter = lbl
		}
	}
	clusterCounter++

	result := make(map[string]string, len(entities))
	for i, e := range entities {
		lbl := labels[i]
		if lbl == -1 {
			result[e] = fmt.Sprintf("cluster_%04d", clusterCounter)
			clusterCounter++
		} else {
			result[e] = fmt.Sprintf("cluster_%04d", lbl)
		}
	}
	return result
}

