// EmbedFunc is a function that takes a slice of texts and returns normalized float32 embeddings.
type EmbedFunc func(texts []string) ([][]float32, error)

// embedBreadcrumbs embeds breadcrumb strings using the provided embed function.
// Returns nil if all breadcrumbs are empty (whitespace-only).
func embedBreadcrumbs(breadcrumbs []string, embed EmbedFunc) ([][]float32, error) {
	hasNonEmpty := false
	for _, bc := range breadcrumbs {
		if len(strings.TrimSpace(bc)) > 0 {
			hasNonEmpty = true
			break
		}
	}
	if !hasNonEmpty {
		return nil, nil
	}

	bcTexts := make([]string, len(breadcrumbs))
	for i, bc := range breadcrumbs {
		if len(strings.TrimSpace(bc)) > 0 {
			bcTexts[i] = bc
		} else {
			bcTexts[i] = ""
		}
	}

	allBcVecs, err := embed(bcTexts)
	if err != nil {
		return nil, fmt.Errorf("embedBreadcrumbs: encode: %w", err)
	}

	for i, bc := range breadcrumbs {
		if len(strings.TrimSpace(bc)) == 0 {
			for j := range allBcVecs[i] {
				allBcVecs[i][j] = 0.0
			}
		}
	}
	return allBcVecs, nil
}

// BuildCommunityOptions holds optional parameters for BuildCommunity.
type BuildCommunityOptions struct {
	NamespaceID  string
	Alpha        float64 // default 0.2
	SimThreshold float64 // default 0.6
	Force        bool
}

// BuildCommunity builds and persists a CommunityIndex, returning the number of communities.
func BuildCommunity(dbPath string, embed EmbedFunc, opts BuildCommunityOptions) (int, error) {
	if !opts.Force {
		n, err := checkExistingCount(dbPath)
		if err != nil {
			return 0, fmt.Errorf("BuildCommunity: check existing: %w", err)
		}
		if n > 0 {
			return n, nil
		}
	}

	rows, db, err := loadChunks(dbPath, opts.NamespaceID)
	if err != nil {
		return 0, fmt.Errorf("BuildCommunity: load chunks: %w", err)
	}
	extraEdges, err := loadEntityEdges(db, rows)
	_ = db.Close()
	if err != nil {
		return 0, fmt.Errorf("BuildCommunity: load entity edges: %w", err)
	}

	if len(rows) == 0 {
		return 0, nil
	}

	chunkIDs := make([]string, len(rows))
	chunkTexts := make([]string, len(rows))
	breadcrumbs := make([]string, len(rows))
	contentVecs := make([][]float32, len(rows))
	for i, r := range rows {
		chunkIDs[i] = r.ChunkID
		if r.Content != "" {
			chunkTexts[i] = r.Content
		}
		if r.Breadcrumb != "" {
			breadcrumbs[i] = r.Breadcrumb
		}
		contentVecs[i] = r.Embedding
	}

	headingVecs, err := embedBreadcrumbs(breadcrumbs, embed)
	if err != nil {
		return 0, fmt.Errorf("BuildCommunity: embed breadcrumbs: %w", err)
	}

	var extraEdgesArg []EdgeTuple
	if len(extraEdges) > 0 {
		extraEdgesArg = extraEdges
	}

	idx, err := NewCommunityIndex(BuildParams{
		ChunkIDs:     chunkIDs,
		ContentVecs:  contentVecs,
		ChunkTexts:   chunkTexts,
		HeadingVecs:  headingVecs,
		Alpha:        opts.Alpha,
		SimThreshold: opts.SimThreshold,
		ExtraEdges:   extraEdgesArg,
	})
	if err != nil {
		return 0, fmt.Errorf("BuildCommunity: build index: %w", err)
	}

	if err := idx.Persist(dbPath); err != nil {
		return 0, fmt.Errorf("BuildCommunity: persist: %w", err)
	}
	return idx.CommunityCount(), nil
}

