// CommunityIndexBuilder builds a CommunityIndex in a background goroutine and atomically hot-swaps when done.
type CommunityIndexBuilder struct {
	Ref    *VersionedRef
	wg     sync.WaitGroup
	logger *slog.Logger
}

// NewCommunityIndexBuilder returns a CommunityIndexBuilder with an optional initial index.
func NewCommunityIndexBuilder(initial *CommunityIndex) *CommunityIndexBuilder {
	return &CommunityIndexBuilder{
		Ref:    NewVersionedRef(initial),
		logger: slog.Default(),
	}
}

// BuildParams holds parameters forwarded to the index build.
type BuildParams struct {
	ChunkIDs     []string
	ContentVecs  [][]float32
	ChunkTexts   []string
	HeadingVecs  [][]float32
	Alpha        float64
	SimThreshold float64
	ExtraEdges   []EdgeTuple
}

// Build starts a background build. Hot-swaps the Ref when complete.
// onComplete is called on the build goroutine with the new index; may be nil.
func (b *CommunityIndexBuilder) Build(params BuildParams, onComplete func(*CommunityIndex)) {
	b.wg.Add(1)
	go func() {
		defer b.wg.Done()
		idx, err := NewCommunityIndex(params)
		if err != nil {
			b.logger.Error("CommunityIndexBuilder background build failed", "err", err)
			return
		}
		newVersion := b.Ref.Update(idx)
		b.logger.Debug("CommunityIndex ready",
			"version", newVersion,
			"levels", idx.LevelCount(),
			"chunks", idx.ChunkCount(),
		)
		if onComplete != nil {
			onComplete(idx)
		}
	}()
}

