// IsBuilding reports whether a build goroutine is currently running.
// Note: Go's sync.WaitGroup does not expose a direct "is running" check;
// we track it with an atomic counter.
func (b *CommunityIndexBuilder) IsBuilding() bool {
	return atomic.LoadInt64(&b.buildCount) > 0
}

// Wait blocks until the running build finishes or the timeout elapses.
// Returns true if done (or never started), false if timed out.
// Pass a zero duration to wait indefinitely.
func (b *CommunityIndexBuilder) Wait(timeout time.Duration) bool {
	if timeout <= 0 {
		b.wg.Wait()
		return true
	}
	done := make(chan struct{})
	go func() {
		b.wg.Wait()
		close(done)
	}()
	select {
	case <-done:
		return true
	case <-time.After(timeout):
		return false
	}
}

