def _compute_working_vecs(
    content_vecs: np.ndarray,
    heading_vecs: np.ndarray | None,
    alpha: float,
) -> np.ndarray:
    """Blend heading and content embeddings; return L2-normalised working vectors."""
    if heading_vecs is not None and alpha > 0:
        vecs = alpha * heading_vecs + (1.0 - alpha) * content_vecs
        norms = np.linalg.norm(vecs, axis=1, keepdims=True)
        return vecs / np.maximum(norms, 1e-9)
    return content_vecs

output:
// computeWorkingVecs blends heading and content embeddings and returns L2-normalised vectors.
// headingVecs may be nil; if nil or alpha == 0 the content vecs are returned unchanged.
func computeWorkingVecs(contentVecs [][]float32, headingVecs [][]float32, alpha float64) [][]float32 {
	if headingVecs != nil && alpha > 0 {
		n := len(contentVecs)
		blended := make([][]float32, n)
		for i := 0; i < n; i++ {
			dim := len(contentVecs[i])
			v := make([]float32, dim)
			for d := 0; d < dim; d++ {
				v[d] = float32(alpha)*headingVecs[i][d] + float32(1.0-alpha)*contentVecs[i][d]
			}
			// L2 normalise
			var norm float64
			for _, x := range v {
				norm += float64(x) * float64(x)
			}
			norm = math.Sqrt(norm)
			if norm < 1e-9 {
				norm = 1e-9
			}
			for d := range v {
				v[d] = float32(float64(v[d]) / norm)
			}
			blended[i] = v
		}
		return blended
	}
	return contentVecs
}

// LeidenPartitioner is an interface for external Leiden algorithm implementations.
type LeidenPartitioner interface {
	Partition(n int, edges []EdgeTuple, resolution float64, nIterations int, seed *int) (map[int]int, error)
}

// runLeiden attempts a Leiden partition using the provided partitioner.
// Returns nil map if partitioner is nil (acts as ImportError fallback).
func runLeiden(partitioner LeidenPartitioner, n int, edges []EdgeTuple, resolution float64, nIterations int, seed *int) (map[int]int, error) {
	if partitioner == nil {
		// No Leiden implementation available — signal caller to fall back to Louvain.
		return nil, nil
	}
	partition, err := partitioner.Partition(n, edges, resolution, nIterations, seed)
	if err != nil {
		return nil, fmt.Errorf("runLeiden: partition: %w", err)
	}
	return partition, nil
}

