// LouvainPartitioner is an interface for community-detection algorithm implementations.
type LouvainPartitioner interface {
	BestPartition(n int, edges []EdgeTuple, seed int) (map[int]int, error)
}

// runLouvain runs a Louvain partition or falls back to connected-components.
func runLouvain(partitioner LouvainPartitioner, n int, edges []EdgeTuple, seed *int) (map[int]int, error) {
	if partitioner != nil {
		s := 42
		if seed != nil {
			s = *seed
		}
		partition, err := partitioner.BestPartition(n, edges, s)
		if err != nil {
			return nil, fmt.Errorf("runLouvain: best partition: %w", err)
		}
		return partition, nil
	}
	// Fallback: connected-components (union-find)
	parent := make([]int, n)
	for i := range parent {
		parent[i] = i
	}
	var find func(int) int
	find = func(x int) int {
		if parent[x] != x {
			parent[x] = find(parent[x])
		}
		return parent[x]
	}
	for _, e := range edges {
		ra, rb := find(e.A), find(e.B)
		if ra != rb {
			parent[ra] = rb
		}
	}
	// Assign community IDs by canonical root
	rootToID := make(map[int]int)
	partition := make(map[int]int, n)
	nextID := 0
	for i := 0; i < n; i++ {
		root := find(i)
		if _, ok := rootToID[root]; !ok {
			rootToID[root] = nextID
			nextID++
		}
		partition[i] = rootToID[root]
	}
	return partition, nil
}

