// loadMultilevelSchema populates ci.Levels from the multi-level chunk_communities schema.
func loadMultilevelSchema(db *sql.DB, ci *CommunityIndex) error {
	chunkRows, err := db.Query("SELECT chunk_id, level, community_id FROM chunk_communities ORDER BY level")
	if err != nil {
		return fmt.Errorf("loadMultilevelSchema: query chunk_communities: %w", err)
	}
	defer chunkRows.Close()

	type chunkRow struct {
		chunkID  string
		levelIdx int
		cid      int
	}
	var cRows []chunkRow
	for chunkRows.Next() {
		var r chunkRow
		if err := chunkRows.Scan(&r.chunkID, &r.levelIdx, &r.cid); err != nil {
			return fmt.Errorf("loadMultilevelSchema: scan chunk_communities: %w", err)
		}
		cRows = append(cRows, r)
	}
	if err := chunkRows.Err(); err != nil {
		return fmt.Errorf("loadMultilevelSchema: chunk_communities rows: %w", err)
	}

	commRows, err := db.Query("SELECT community_id, level, topic_label, coherence, resolution FROM communities ORDER BY level")
	if err != nil {
		return fmt.Errorf("loadMultilevelSchema: query communities: %w", err)
	}
	defer commRows.Close()

	type commRow struct {
		cid        int
		levelIdx   int
		label      string
		coherence  float64
		resolution float64
	}
	var communityRows []commRow
	for commRows.Next() {
		var r commRow
		if err := commRows.Scan(&r.cid, &r.levelIdx, &r.label, &r.coherence, &r.resolution); err != nil {
			return fmt.Errorf("loadMultilevelSchema: scan communities: %w", err)
		}
		communityRows = append(communityRows, r)
	}
	if err := commRows.Err(); err != nil {
		return fmt.Errorf("loadMultilevelSchema: communities rows: %w", err)
	}

	levelsByIdx := make(map[int]*LevelData)
	for _, r := range cRows {
		if _, ok := levelsByIdx[r.levelIdx]; !ok {
			levelsByIdx[r.levelIdx] = NewLevelData(1.0)
		}
		ld := levelsByIdx[r.levelIdx]
		ld.ChunkToCommunity[r.chunkID] = r.cid
		ld.CommunityToChunks[r.cid] = append(ld.CommunityToChunks[r.cid], r.chunkID)
	}
	for _, r := range communityRows {
		resolution := r.resolution
		if resolution == 0 {
			resolution = 1.0
		}
		if _, ok := levelsByIdx[r.levelIdx]; !ok {
			levelsByIdx[r.levelIdx] = NewLevelData(resolution)
		}
		ld := levelsByIdx[r.levelIdx]
		ld.Resolution = resolution
		ld.CommunityToLabel[r.cid] = r.label
		ld.CommunityToCoherence[r.cid] = r.coherence
	}

	// Append levels in sorted order
	keys := make([]int, 0, len(levelsByIdx))
	for k := range levelsByIdx {
		keys = append(keys, k)
	}
	sort.Ints(keys)
	for _, k := range keys {
		ci.Levels = append(ci.Levels, levelsByIdx[k])
	}
	return nil
}

// legacyCommunityRow holds one row from the legacy communities table.
type legacyCommunityRow struct {
	cid       int
	label     string
	coherence float64
}

// fetchLegacyCommunityRows fetches community rows from legacy schema, with or without coherence column.
func fetchLegacyCommunityRows(db *sql.DB) ([]legacyCommunityRow, error) {
	rows, err := db.Query("SELECT community_id, topic_label, coherence FROM communities")
	if err != nil {
		// coherence column may be absent in very old schema — retry without it
		rows2, err2 := db.Query("SELECT community_id, topic_label FROM communities")
		if err2 != nil {
			return nil, fmt.Errorf("fetchLegacyCommunityRows: %w", err2)
		}
		defer rows2.Close()
		var result []legacyCommunityRow
		for rows2.Next() {
			var r legacyCommunityRow
			if err := rows2.Scan(&r.cid, &r.label); err != nil {
				return nil, fmt.Errorf("fetchLegacyCommunityRows: scan: %w", err)
			}
			result = append(result, r)
		}
		return result, rows2.Err()
	}
	defer rows.Close()
	var result []legacyCommunityRow
	for rows.Next() {
		var r legacyCommunityRow
		if err := rows.Scan(&r.cid, &r.label, &r.coherence); err != nil {
			return nil, fmt.Errorf("fetchLegacyCommunityRows: scan with coherence: %w", err)
		}
		result = append(result, r)
	}
	return result, rows.Err()
}

// loadLegacySchema populates ci.Levels from the legacy (no level column) schema.
func loadLegacySchema(db *sql.DB, ci *CommunityIndex) error {
	chunkRows, err := db.Query("SELECT chunk_id, community_id FROM chunk_communities")
	if err != nil {
		return fmt.Errorf("loadLegacySchema: query chunk_communities: %w", err)
	}
	defer chunkRows.Close()

	ld := NewLevelData(1.0)
	for chunkRows.Next() {
		var chunkID string
		var cid int
		if err := chunkRows.Scan(&chunkID, &cid); err != nil {
			return fmt.Errorf("loadLegacySchema: scan chunk_communities: %w", err)
		}
		ld.ChunkToCommunity[chunkID] = cid
		ld.CommunityToChunks[cid] = append(ld.CommunityToChunks[cid], chunkID)
	}
	if err := chunkRows.Err(); err != nil {
		return fmt.Errorf("loadLegacySchema: chunk_communities rows: %w", err)
	}

	communityRows, err := fetchLegacyCommunityRows(db)
	if err != nil {
		return fmt.Errorf("loadLegacySchema: fetch community rows: %w", err)
	}
	for _, r := range communityRows {
		ld.CommunityToLabel[r.cid] = r.label
		ld.CommunityToCoherence[r.cid] = r.coherence
	}
	ci.Levels = append(ci.Levels, ld)
	return nil
}

// CommunityIndex holds chunk-to-community assignments with topic labels.
type CommunityIndex struct {
	ChunkToCommunity     map[string]int
	CommunityToLabel     map[int]string
	CommunityToChunks    map[int][]string
	CommunityToCoherence map[int]float64
	Levels               []*LevelData
}

// newEmptyCommunityIndex creates a zero-value CommunityIndex.
