// CommunityIndexFromDB loads a CommunityIndex from a SQL DB.
// Returns an empty (valid) index if no schema has been built yet.
func CommunityIndexFromDB(db *sql.DB) (*CommunityIndex, error) {
	ci := newEmptyCommunityIndex()

	err := loadMultilevelSchema(db, ci)
	if err != nil {
		// Multi-level schema absent — try legacy schema.
		ci2 := newEmptyCommunityIndex()
		legacyErr := loadLegacySchema(db, ci2)
		if legacyErr != nil {
			// Neither schema built yet — return empty index (valid not-yet-built state).
			// Distinguish "table not found" (ok) from unexpected errors by checking msg.
			if strings.Contains(legacyErr.Error(), "does not exist") || strings.Contains(legacyErr.Error(), "no such table") {
				return ci, nil
			}
			return nil, fmt.Errorf("CommunityIndexFromDB: legacy schema: %w", legacyErr)
		}
		ci = ci2
	} else if err != nil {
		return nil, fmt.Errorf("CommunityIndexFromDB: multilevel schema: %w", err)
	}

	// Populate flat attrs from finest level
	if len(ci.Levels) > 0 {
		populateFlatAttrs(ci, ci.Levels[len(ci.Levels)-1])
	}
	return ci, nil
}

// LLMClient is the interface for LLM completions.
type LLMClient interface {
	Complete(prompt string) (string, error)
}

// DocumentChunk holds a generated summary chunk.
type DocumentChunk struct {
	DocumentName string
	Content      string
	ChunkType    string
	Section      []string
}

// CommunitySummarizer generates DocumentChunk summaries for each community via an LLM.
type CommunitySummarizer struct {
	llm          LLMClient
	system       string
	userTemplate string
}

// NewCommunitySummarizer constructs a CommunitySummarizer.
// systemPrompt and userTemplate may be empty strings to use package defaults.
func NewCommunitySummarizer(llm LLMClient, systemPrompt, userTemplate string) (*CommunitySummarizer, error) {
	if llm == nil {
		return nil, fmt.Errorf("NewCommunitySummarizer: llm must not be nil")
	}
	if systemPrompt == "" {
		systemPrompt = defaultSystemPrompt
	}
	if userTemplate == "" {
		userTemplate = defaultUserTemplate
	}
	return &CommunitySummarizer{llm: llm, system: systemPrompt, userTemplate: userTemplate}, nil
}

// Summarize summarizes one community and returns a DocumentChunk.
// Returns nil if chunkTexts is empty.
// communityID is stored in the chunk's DocumentName.
// maxChars truncates combined text before building the prompt (0 = use default 400000).
func (cs *CommunitySummarizer) Summarize(communityID string, chunkTexts []string, topicLabel string, maxChars int) (*DocumentChunk, error) {
	if len(chunkTexts) == 0 {
		return nil, nil
	}
	if maxChars <= 0 {
		maxChars = 400_000
	}
	combined := strings.Join(chunkTexts, "\n---\n")
	if len(combined) > maxChars {
		combined = combined[:maxChars]
	}
	topicLabelUsed := topicLabel
	if len(topicLabelUsed) == 0 {
		topicLabelUsed = "(unlabeled)"
	}
	prompt := cs.system + "\n\n" + fmt.Sprintf(
		cs.userTemplate,
		topicLabelUsed,
		len(chunkTexts),
		combined,
	)
	summary, err := cs.llm.Complete(prompt)
	if err != nil {
		return nil, fmt.Errorf("Summarize: llm complete: %w", err)
	}
	var section []string
	if len(topicLabel) > 0 {
		section = []string{topicLabel}
	}
	return &DocumentChunk{
		DocumentName: fmt.Sprintf("community:%s", communityID),
		Content:      strings.TrimSpace(summary),
		ChunkType:    "community_summary",
		Section:      section,
	}, nil
}

