func (p *MarkdownParser) HandleStartTag(tag string, attrs []html.Attribute) {
	t := strings.ToLower(tag)
	_, inSkip := p.skip[t]
	if inSkip || strings.HasPrefix(t, "ix:") {
		p.skipDepth++
	}
	if p.skipDepth > 0 {
		return
	}
	if marker, ok := p.headingMarkers[t]; ok {
		p.headingMarker = &marker
		p.headingPrefixed = false
		p.parts = append(p.parts, "\n")
	} else if _, inBlock := p.block[t]; inBlock {
		p.parts = append(p.parts, "\n")
	}
}

