func promoteBoldHeadings(htmlStr string, maxLen int) string {
	replace := func(match string, groups []string) string {
		if len(groups) < 1 {
			return match
		}
		text := strings.TrimRight(strings.TrimSpace(groups[0]), ".")
		if len(text) == 0 || len(text) > maxLen {
			return match
		}
		return fmt.Sprintf("<h2>%s</h2>", text)
	}
	htmlStr = boldBRe.ReplaceAllStringFunc(htmlStr, func(m string) string {
		subs := boldBRe.FindStringSubmatch(m)
		if len(subs) < 2 {
			return m
		}
		return replace(m, subs[1:])
	})
	htmlStr = boldSpanRe.ReplaceAllStringFunc(htmlStr, func(m string) string {
		subs := boldSpanRe.FindStringSubmatch(m)
		if len(subs) < 2 {
			return m
		}
		return replace(m, subs[1:])
	})
	return htmlStr
}

type TocEntry struct {
	AnchorID string
	ItemNum  string
}

func parseTOC(htmlStr string) []TocEntry {
	results := []TocEntry{}
	seenAnchors := map[string]struct{}{}

	linkRe := regexp.MustCompile(`(?i)(?s)<a\b[^>]+href="#([^"]+)"[^>]*>(.*?)</a>`)

	matches := linkRe.FindAllStringSubmatchIndex(htmlStr, -1)
	for _, loc := range matches {
		anchorID := strings.TrimSpace(htmlStr[loc[2]:loc[3]])
		if _, seen := seenAnchors[anchorID]; seen {
			continue
		}
		linkContent := htmlStr[loc[4]:loc[5]]
		linkText := stripTags(linkContent)
		// Strategy 1: item text directly in link
		if sub := itemRe.FindStringSubmatch(linkText); len(sub) > 1 {
			raw := strings.TrimRight(strings.ToUpper(sub[1]), ".")
			seenAnchors[anchorID] = struct{}{}
			results = append(results, TocEntry{AnchorID: anchorID, ItemNum: raw})
			continue
		}
		// Strategy 2: item number encoded in href
		if hm := hrefItemRe.FindStringSubmatch(anchorID); len(hm) > 1 {
			raw := strings.ToUpper(hm[1])
			if _, ok := itemNames[raw]; ok {
				seenAnchors[anchorID] = struct{}{}
				results = append(results, TocEntry{AnchorID: anchorID, ItemNum: raw})
				continue
			}
		}
		// Strategy 3: item label in adjacent <td>, same <tr>
		matchStart := loc[0]
		rowStart := strings.LastIndex(htmlStr[:matchStart], "<tr")
		if rowStart != -1 && (matchStart-rowStart) < 2000 {
			rowText := stripTags(htmlStr[rowStart:matchStart])
			if cm := itemRe.FindStringSubmatch(rowText); len(cm) > 1 {
				raw := strings.TrimRight(strings.ToUpper(cm[1]), ".")
				seenAnchors[anchorID] = struct{}{}
				results = append(results, TocEntry{AnchorID: anchorID, ItemNum: raw})
			}
		}
	}
	return results
}

