type ExtractEdgarProseOptions struct {
	ProseOnly           bool
	InferBoldHeadings   bool
	BoldHeadingMaxLen   int
}

func extractEdgarProse(htmlStr string, opts ExtractEdgarProseOptions) string {
	toc := parseTOC(htmlStr)
	if len(toc) == 0 {
		return stripTags(htmlStr)
	}

	var tocFiltered []TocEntry
	if opts.ProseOnly {
		for _, e := range toc {
			if _, ok := proseItems[e.ItemNum]; ok {
				tocFiltered = append(tocFiltered, e)
			}
		}
	} else {
		tocFiltered = toc
	}

	allIDs := make([]string, len(toc))
	for i, e := range toc {
		allIDs[i] = e.AnchorID
	}

	var sections []string
	for _, entry := range tocFiltered {
		attribTarget := fmt.Sprintf("id=\"%s\"", entry.AnchorID)
		attrPos := strings.Index(htmlStr, attribTarget)
		if attrPos == -1 {
			continue
		}
		tagStart := strings.LastIndex(htmlStr[:attrPos], "<")
		posStart := attrPos
		if tagStart != -1 {
			posStart = tagStart
		}

		idx := -1
		for i, id := range allIDs {
			if id == entry.AnchorID {
				idx = i
				break
			}
		}
		if idx == -1 {
			continue
		}

		posEnd := len(htmlStr)
		if idx+1 < len(allIDs) {
			nextID := allIDs[idx+1]
			nextAttr := strings.Index(htmlStr, fmt.Sprintf("id=\"%s\"", nextID))
			if nextAttr != -1 {
				pe := strings.LastIndex(htmlStr[:nextAttr], "<")
				if pe > posStart {
					posEnd = pe
				}
			}
		}

		sectionHTML := htmlStr[posStart:posEnd]
		var text string
		if opts.InferBoldHeadings {
			sectionHTML = promoteBoldHeadings(sectionHTML, opts.BoldHeadingMaxLen)
			text = toMarkdown(sectionHTML)
		} else {
			text = stripTags(sectionHTML)
		}
		if len(strings.TrimSpace(text)) == 0 {
			continue
		}

		name, ok := itemNames[entry.ItemNum]
		if !ok {
			name = fmt.Sprintf("Item %s", entry.ItemNum)
		}
		heading := fmt.Sprintf("# Item %s.  %s", entry.ItemNum, name)
		sections = append(sections, fmt.Sprintf("%s\n\n%s", heading, text))
	}

	return strings.Join(sections, "\n\n---\n\n")
}

