func joinField(val interface{}) string {
	switch v := val.(type) {
	case []interface{}:
		parts := make([]string, 0, len(v))
		for _, item := range v {
			parts = append(parts, fmt.Sprintf("%v", item))
		}
		return strings.TrimSpace(strings.Join(parts, " "))
	case string:
		return strings.TrimSpace(v)
	case nil:
		return ""
	default:
		return strings.TrimSpace(fmt.Sprintf("%v", v))
	}
}

func iterLabels(obj interface{}) []map[string]interface{} {
	switch v := obj.(type) {
	case map[string]interface{}:
		if results, ok := v["results"]; ok {
			if resList, ok := results.([]interface{}); ok {
				var out []map[string]interface{}
				for _, r := range resList {
					if m, ok := r.(map[string]interface{}); ok {
						out = append(out, m)
					}
				}
				return out
			}
		}
		_, hasOpenFDA := v["openfda"]
		_, hasIndications := v["indications_and_usage"]
		if hasOpenFDA || hasIndications {
			return []map[string]interface{}{v}
		}
	case []interface{}:
		var out []map[string]interface{}
		for _, r := range v {
			if m, ok := r.(map[string]interface{}); ok {
				out = append(out, m)
			}
		}
		return out
	}
	return nil
}

