func renderOneFdaLabel(label map[string]interface{}) string {
	openfda, _ := label["openfda"].(map[string]interface{})
	if openfda == nil {
		openfda = map[string]interface{}{}
	}

	brand := firstStringInList(openfda["brand_name"])
	generic := firstStringInList(openfda["generic_name"])
	applID := labelID(label)
	name := brand
	if len(name) == 0 {
		name = generic
	}
	if len(name) == 0 {
		name = applID
	}
	manufacturer := firstStringInList(openfda["manufacturer_name"])
	routeList, _ := openfda["route"].([]interface{})
	routeParts := make([]string, 0, len(routeList))
	for _, r := range routeList {
		if s, ok := r.(string); ok {
			routeParts = append(routeParts, s)
		}
	}
	route := strings.Join(routeParts, ", ")
	productType := firstStringInList(openfda["product_type"])

	lines := []string{fmt.Sprintf("# %s", name), ""}

	if len(applID) > 0 && applID != "UNKNOWN" {
		lines = append(lines, fmt.Sprintf("**Application:** %s", applID))
	}
	if len(generic) > 0 && generic != brand {
		lines = append(lines, fmt.Sprintf("**Generic:** %s", generic))
	}
	if len(manufacturer) > 0 {
		lines = append(lines, fmt.Sprintf("**Manufacturer:** %s", manufacturer))
	}
	if len(route) > 0 {
		lines = append(lines, fmt.Sprintf("**Route:** %s", route))
	}
	if len(productType) > 0 {
		lines = append(lines, fmt.Sprintf("**Type:** %s", productType))
	}

	for _, sec := range labelSections {
		text := joinField(label[sec.Key])
		if len(text) > 0 {
			if len(text) > 3000 {
				text = text[:3000]
			}
			lines = append(lines, "", fmt.Sprintf("## %s", sec.Heading), "", text)
		}
	}

	return strings.Join(lines, "\n")
}

