func iterResources(obj interface{}) []map[string]interface{} {
	switch v := obj.(type) {
	case map[string]interface{}:
		rtype, _ := v["resourceType"].(string)
		if rtype == "Bundle" {
			entries, _ := v["entry"].([]interface{})
			var out []map[string]interface{}
			for _, e := range entries {
				em, ok := e.(map[string]interface{})
				if !ok {
					continue
				}
				res, ok := em["resource"].(map[string]interface{})
				if !ok {
					continue
				}
				out = append(out, res)
			}
			return out
		}
		if _, ok := renderableTypes[rtype]; ok {
			return []map[string]interface{}{v}
		}
	case []interface{}:
		var out []map[string]interface{}
		for _, r := range v {
			rm, ok := r.(map[string]interface{})
			if !ok {
				continue
			}
			if rt, _ := rm["resourceType"].(string); len(rt) > 0 {
				out = append(out, rm)
			}
		}
		return out
	}
	return nil
}

