	rid, _ := res["id"].(string)
	if len(rid) == 0 {
		rid = "UNKNOWN"
	}
	namesRaw, _ := res["name"].([]interface{})
	nameStr := ""
	if len(namesRaw) > 0 {
		if n, ok := namesRaw[0].(map[string]interface{}); ok {
			givenRaw, _ := n["given"].([]interface{})
			givenParts := make([]string, 0, len(givenRaw))
