					givenParts = append(givenParts, s)
				}
			}
			given := strings.Join(givenParts, " ")
			family, _ := n["family"].(string)
			nameStr = strings.TrimSpace(fmt.Sprintf("%s %s", given, family))
		}
	}

	gender, _ := res["gender"].(string)
	birthDate, _ := res["birthDate"].(string)

