// TODO: RE2 does not support backreferences (\1 in navAttrRe). The </\1> back-reference
// is replaced here by a fixed closing-tag alternation; this is RE2-safe but may
// over-match nested tags of different types. A full fix requires an HTML parser.

var (
	stripChromeBlockTags = []string{"nav", "aside", "header", "footer", "noscript", "script", "style"}
	navAttrRe = regexp.MustCompile(`(?is)<(div|section|ul|table)[^>]*?(?:class|id|role)\s*=\s*["'][^"']*?(?:sidebar|navbox|navbar|navigation|toc|catlinks|mw-panel|mw-head|mw-editsection|menu|breadcrumb|noprint|portal|sister-project|interlanguage|authority-control|reflist|references|footnotes|mw-references-wrap|citation)[^"']*?["'][^>]*>.*?</(?:div|section|ul|table)>`)
	supRefRe  = regexp.MustCompile(`(?is)<sup[^>]*class=["'][^"']*reference[^"']*["'][^>]*>.*?</sup>`)
)

func stripHTMLChrome(html string) string {
	for _, tag := range stripChromeBlockTags {
		re := regexp.MustCompile(fmt.Sprintf(`(?is)<%s[\s>].*?</%s>`, tag, tag))
		html = re.ReplaceAllString(html, "")
	}
	html = navAttrRe.ReplaceAllString(html, "")
	html = supRefRe.ReplaceAllString(html, "")
	return html
}

