func (c *MarkdownConverter) HandleEndTag(tag string) {
	tag = strings.ToLower(tag)
	if len(c.tagStack) > 0 && c.tagStack[len(c.tagStack)-1] == tag {
		c.tagStack = c.tagStack[:len(c.tagStack)-1]
	}
	switch tag {
	case "h1", "h2", "h3", "h4", "h5", "h6":
		level := int(tag[1] - '0')
		prefix := strings.Repeat("#", level) + " "
		var textParts []string
		for len(c.output) > 0 && c.output[len(c.output)-1] != "\n\n" {
			textParts = append(textParts, c.output[len(c.output)-1])
			c.output = c.output[:len(c.output)-1]
		}
		for i, j := 0, len(textParts)-1; i < j; i, j = i+1, j-1 {
			textParts[i], textParts[j] = textParts[j], textParts[i]
		}
		text := strings.TrimSpace(strings.Join(textParts, ""))
		c.output = append(c.output, fmt.Sprintf("%s%s\n\n", prefix, text))
	case "p":
		if !c.inCell {
			c.output = append(c.output, "\n")
		}
	case "pre":
		c.inPre = false
		c.output = append(c.output, "\n```\n\n")
	case "ul":
		if len(c.listStack) > 0 {
			c.listStack = c.listStack[:len(c.listStack)-1]
		}
		c.output = append(c.output, "\n")
	case "ol":
		if len(c.listStack) > 0 {
			c.listStack = c.listStack[:len(c.listStack)-1]
		}
		if len(c.olCounters) > 0 {
			c.olCounters = c.olCounters[:len(c.olCounters)-1]
		}
		c.output = append(c.output, "\n")
	case "strong", "b":
		c.appendText("**")
	case "em", "i":
		c.appendText("*")
	case "a":
		linkText := strings.TrimSpace(strings.Join(c.linkText, ""))
		var formatted string
		if len(c.href) > 0 && len(linkText) > 0 {
			formatted = fmt.Sprintf("[%s](%s)", linkText, c.href)
		} else {
			formatted = linkText
		}
		c.appendText(formatted)
		c.inLink = false
		c.href = ""
		c.linkText = nil
	case "td", "th":
		cellText := strings.Join(strings.Fields(strings.Join(c.cellBuf, "")), " ")
		c.currentRowCells = append(c.currentRowCells, cellText)
		c.cellBuf = nil
		c.inCell = false
	case "tr":
		if len(c.currentRowCells) > 0 {
			row := "| " + strings.Join(c.currentRowCells, " | ") + " |"
			c.output = append(c.output, fmt.Sprintf("\n%s", row))
			c.lastRowColCount = len(c.currentRowCells)
		}
	case "thead":
		if c.lastRowColCount > 0 {
			seps := make([]string, c.lastRowColCount)
			for i := range seps {
				seps[i] = "---"
			}
			sep := "| " + strings.Join(seps, " | ") + " |"
			c.output = append(c.output, fmt.Sprintf("\n%s", sep))
		}
	}
}

