func (e *HtmlExtractor) Annotate(chunks []Chunk, data []byte, sourcePath string) []Chunk {
	htmlStr := strings.ToValidUTF8(string(data), string(unicode.ReplacementChar))

	records := scanHeadings(htmlStr)
	if len(records) == 0 {
		return chunks
	}

	// Build section anchors from heading stack
	type stackEntry struct {
		Level  int
		Anchor string
		Text   string
	}
	var headingStack []stackEntry
	sectionAnchors := make([]sectionAnchor, 0, len(records))
	for _, rec := range records {
		var filtered []stackEntry
		for _, s := range headingStack {
			if s.Level < rec.Level {
				filtered = append(filtered, s)
			}
		}
		headingStack = append(filtered, stackEntry{rec.Level, rec.Anchor, rec.Text})

		path := make([]string, len(headingStack))
		for i, s := range headingStack {
			path[i] = s.Text
		}
		topAnchor := ""
		for j := len(headingStack) - 1; j >= 0; j-- {
			if len(headingStack[j].Anchor) > 0 {
				topAnchor = headingStack[j].Anchor
				break
			}
		}
		sectionAnchors = append(sectionAnchors, sectionAnchor{topAnchor, path})
	}

	// Split markdown into segments
	markdown := convertHTMLToMarkdown(htmlStr)
	headingIdx := 0
	type segment struct {
		Anchor string
		Path   []string
		Text   string
	}
	var segments []segment
	currentAnchor := ""
	var currentPath []string
	var currentBuf []string
	headingLineRe := regexp.MustCompile(`^(#{1,6})\s+(.*)`)

	for _, line := range strings.Split(markdown, "\n") {
		if headingLineRe.MatchString(line) && headingIdx < len(sectionAnchors) {
			if len(currentBuf) > 0 {
				segments = append(segments, segment{currentAnchor, currentPath, strings.Join(currentBuf, "\n")})
			}
			currentAnchor = sectionAnchors[headingIdx].Anchor
			currentPath = sectionAnchors[headingIdx].Path
			headingIdx++
			currentBuf = []string{line}
		} else {
			currentBuf = append(currentBuf, line)
		}
	}
	if len(currentBuf) > 0 {
		segments = append(segments, segment{currentAnchor, currentPath, strings.Join(currentBuf, "\n")})
	}

	for i := range chunks {
		content := chunks[i].Content
		for _, seg := range segments {
			matched := false
			for _, frag := range strings.Split(content, "\n") {
				if len(strings.TrimSpace(frag)) > 20 && strings.Contains(seg.Text, frag) {
					matched = true
					break
				}
			}
			if matched {
				detail := map[string]interface{}{"heading_path": seg.Path}
				if len(seg.Anchor) > 0 {
					detail["anchor"] = seg.Anchor
				}
				chunks[i].SourceDetail = detail
				break
			}
		}
	}
	return chunks
}

