func stripJavadoc(lines []string) string {
	var textLines []string
	for _, line := range lines {
		stripped := strings.TrimSpace(strings.TrimLeft(strings.TrimSpace(line), "/*"))
		if len(stripped) > 0 {
			textLines = append(textLines, stripped)
		}
	}
	return strings.Join(textLines, " ")
}

func collectJavaBody(lines []string, start int, currentDepth int) (string, int, int) {
	var collected []string
	depth := currentDepth
	foundOpen := false
	i := start
	for i < len(lines) {
		line := lines[i]
		collected = append(collected, line)
		opens := strings.Count(line, "{")
		closes := strings.Count(line, "}")
		if opens > 0 {
			foundOpen = true
		}
		depth += opens - closes
		i++
		if foundOpen && depth <= currentDepth {
			break
		}
	}
	return strings.Join(collected, "\n"), i, depth
}

