func (e *JavaExtractor) scan(source string) (string, map[string]SectionMeta) {
	lines := strings.Split(source, "\n")
	var parts []string
	sectionMap := make(map[string]SectionMeta)

	var importLineIndices []int
	for idx, ln := range lines {
		if importRE.MatchString(ln) {
			importLineIndices = append(importLineIndices, idx)
		}
	}
	if len(importLineIndices) > 0 {
		var importLines []string
		for _, idx := range importLineIndices {
			importLines = append(importLines, lines[idx])
		}
		parts = append(parts, "## Imports\n\n```java\n"+strings.Join(importLines, "\n")+"\n```")
		sectionMap["Imports"] = SectionMeta{
			LineStart: importLineIndices[0] + 1,
			LineEnd:   importLineIndices[len(importLineIndices)-1] + 1,
			Symbol:    "Imports",
		}
	}

type typeFrame struct {
	name  string
	depth int
}

	braceDepth := 0
	var typeStack []typeFrame
	var pendingJavadoc []string
	inJavadoc := false
	i := 0

	for i < len(lines) {
		line := lines[i]
		stripped := strings.TrimSpace(line)

		if strings.HasPrefix(stripped, "/**") {
			inJavadoc = true
			pendingJavadoc = []string{line}
			if strings.Contains(stripped, "*/") {
				inJavadoc = false
			}
			i++
			continue
		}
		if inJavadoc {
			pendingJavadoc = append(pendingJavadoc, line)
			if strings.Contains(stripped, "*/") {
				inJavadoc = false
			}
			i++
			continue
		}
		if importRE.MatchString(line) {
			pendingJavadoc = nil
			i++
			continue
		}
		if braceDepth <= 1 {
			if m := typeDeclRE.FindStringSubmatch(line); m != nil {
				name := m[1]
				javadoc := ""
				if len(pendingJavadoc) > 0 {
					javadoc = stripJavadoc(pendingJavadoc)
				}
				pendingJavadoc = nil
				parts = append(parts, "# "+name)
				if len(javadoc) > 0 {
					parts = append(parts, javadoc)
				}
				depthBefore := braceDepth
				braceDepth += strings.Count(line, "{") - strings.Count(line, "}")
				typeStack = append(typeStack, typeFrame{name, depthBefore})
				i++
				continue
			}
		}
		if len(typeStack) > 0 {
			className := typeStack[len(typeStack)-1].name
			classDepth := typeStack[len(typeStack)-1].depth
			if braceDepth == classDepth+1 {
				if m := methodRE.FindStringSubmatch(line); m != nil {
					mname := m[1]
					if _, skip := skipKeywords[mname]; !skip {
						javadoc := ""
						if len(pendingJavadoc) > 0 {
							javadoc = stripJavadoc(pendingJavadoc)
						}
						pendingJavadoc = nil
						parts = append(parts, "## "+mname)
						if len(javadoc) > 0 {
							parts = append(parts, javadoc)
						}
						lineStart := i + 1
						var body string
						body, i, braceDepth = collectJavaBody(lines, i, braceDepth)
						sectionMap[className+"."+mname] = SectionMeta{
							LineStart: lineStart,
							LineEnd:   i,
							Symbol:    fmt.Sprintf("%s.%s", className, mname),
						}
						parts = append(parts, fmt.Sprintf("```java\n%s\n```", body))
						for len(typeStack) > 0 && braceDepth <= typeStack[len(typeStack)-1].depth {
							typeStack = typeStack[:len(typeStack)-1]
						}
						continue
					}
				}
			}
		}
		pendingJavadoc = nil
		braceDepth += strings.Count(line, "{") - strings.Count(line, "}")
		for len(typeStack) > 0 && braceDepth <= typeStack[len(typeStack)-1].depth {
			typeStack = typeStack[:len(typeStack)-1]
		}
		i++
	}
	return strings.Join(parts, "\n\n"), sectionMap
}

