func (e *LookupTableExtractor) Extract(data []byte, sourcePath *string) (string, error) {
	text := decodeBytes(data)

	records, err := parseCSV(text)
	if err != nil {
		return "", fmt.Errorf("CSV parse error: %w", err)
	}

	var rows [][]string
	for _, row := range records {
		hasContent := false
		for _, cell := range row {
			if len(strings.TrimSpace(cell)) > 0 {
				hasContent = true
				break
			}
		}
		if hasContent {
			rows = append(rows, row)
		}
	}
	if len(rows) < 2 {
		return "", nil
	}

	var headers []string
	for _, h := range rows[0] {
		headers = append(headers, strings.TrimSpace(h))
	}

	keyIdx := 0
	if e.keyColumn.Index != nil {
		keyIdx = *e.keyColumn.Index
	} else if e.keyColumn.Name != nil {
		keyName := strings.ToLower(*e.keyColumn.Name)
		for i, h := range headers {
			if strings.ToLower(h) == keyName {
				keyIdx = i
				break
			}
		}
	}

	var sections []string
	for _, row := range rows[1:] {
		for len(row) < len(headers) {
			row = append(row, "")
		}
		keyVal := strings.TrimSpace(row[keyIdx])
		if len(keyVal) == 0 && e.skipEmptyKey {
			continue
		}
		lines := []string{fmt.Sprintf("## %s", keyVal)}
		for i, header := range headers {
			if i == keyIdx {
				continue
			}
			v := strings.TrimSpace(row[i])
			if len(v) > 0 {
				lines = append(lines, fmt.Sprintf("%s: %s", header, v))
			}
		}
		sections = append(sections, strings.Join(lines, "\n"))
	}
	return strings.Join(sections, "\n\n"), nil
}

func NormalizeType(userType string) (string, error) {
	if len(userType) == 0 {
		return "auto", nil
	}
	lower := strings.ToLower(strings.TrimSpace(userType))
	if _, ok := knownShort[lower]; ok {
		return lower, nil
	}
	if _, ok := legacyTransportTypes[lower]; ok {
		return "auto", nil
	}
	if short, ok := mimeToShort[lower]; ok {
		return short, nil
	}
	var known []string
	for k := range knownShort {
		if k != "auto" {
			known = append(known, k)
		}
	}
	sort.Strings(known)
	return "", fmt.Errorf("Unknown document type: %q. Use one of: %v or a MIME type.", userType, known)
}

