    for part in parts:
        prose = (part.get("prose") or "").strip()
        sub = part.get("parts", [])
        if prose:
            prefix = "  " * depth
            lines.append(f"{prefix}{prose}")
        if sub:
            lines.extend(_parts_text(sub, depth + 1))
    return lines

