// _partsText recursively extracts prose from OSCAL part trees with depth indentation.
func _partsText(parts []interface{}, depth int) []string {
	var lines []string
	for _, p := range parts {
		pm, ok := p.(map[string]interface{})
		if !ok {
			continue
		}
		prose := ""
		if v, ok := pm["prose"]; ok && v != nil {
			prose = strings.TrimSpace(fmt.Sprintf("%v", v))
		}
		var sub []interface{}
		if s, ok := pm["parts"]; ok {
			if sl, ok := s.([]interface{}); ok {
				sub = sl
			}
		}
		if len(prose) > 0 {
			prefix := strings.Repeat("  ", depth)
			lines = append(lines, fmt.Sprintf("%s%s", prefix, prose))
		}
		if len(sub) > 0 {
			lines = append(lines, _partsText(sub, depth+1)...)
		}
	}
	return lines
}

// _renderOne renders a single OSCAL control dict to markdown.
func _renderOne(ctrl map[string]interface{}) string {
	ctrlID := "UNKNOWN"
	if v, ok := ctrl["id"]; ok && v != nil {
		ctrlID = strings.ToUpper(fmt.Sprintf("%v", v))
	}
	title := ""
	if v, ok := ctrl["title"]; ok && v != nil {
		title = fmt.Sprintf("%v", v)
	}
	var partsRaw []interface{}
	if p, ok := ctrl["parts"]; ok {
		if pl, ok := p.([]interface{}); ok {
			partsRaw = pl
		}
	}
	lines := []string{fmt.Sprintf("# %s %s", ctrlID, title), ""}
	proseLines := _partsText(partsRaw, 0)
	if len(proseLines) > 0 {
		lines = append(lines, "## Statement", "")
		lines = append(lines, proseLines...)
	}
	var subControls []interface{}
	if c, ok := ctrl["controls"]; ok {
		if cl, ok := c.([]interface{}); ok {
			subControls = cl
		}
	}
	for _, s := range subControls {
		sm, ok := s.(map[string]interface{})
		if !ok {
			continue
		}
		subID := ""
		if v, ok := sm["id"]; ok && v != nil {
			subID = strings.ToUpper(fmt.Sprintf("%v", v))
		}
		subTitle := ""
		if v, ok := sm["title"]; ok && v != nil {
			subTitle = fmt.Sprintf("%v", v)
		}
		lines = append(lines, "", fmt.Sprintf("## %s %s", subID, subTitle))
		var subPartsRaw []interface{}
		if p, ok := sm["parts"]; ok {
			if pl, ok := p.([]interface{}); ok {
				subPartsRaw = pl
			}
		}
		subProse := _partsText(subPartsRaw, 0)
		if len(subProse) > 0 {
			lines = append(lines, "")
			lines = append(lines, subProse...)
		}
	}
	return strings.Join(lines, "\n")
}

