			if !ok {
				continue
			}
			cid := ""
			if v, ok := cm["id"]; ok && v != nil {
				cid = fmt.Sprintf("%v", v)
			}
			if osCalIDRe.MatchString(cid) {
				return true
			}
		}
	}
	return false
