// Annotate stamps each DocumentChunk with OSCAL control metadata.
func (r *NistRenderer) Annotate(chunks []*DocumentChunk, obj interface{}) []*DocumentChunk {
	objMap, ok := obj.(map[string]interface{})
	if !ok {
		return chunks
	}
	groupMap := make(map[string]string)
	var catalog map[string]interface{}
	if c, ok := objMap["catalog"]; ok {
		if cm, ok := c.(map[string]interface{}); ok {
			catalog = cm
		} else {
			catalog = objMap
		}
	} else {
		catalog = objMap
	}
	if groupsRaw, ok := catalog["groups"]; ok {
		if groups, ok := groupsRaw.([]interface{}); ok {
			for _, g := range groups {
				gm, ok := g.(map[string]interface{})
				if !ok {
					continue
				}
				gtitle := ""
				if v, ok := gm["title"]; ok && v != nil {
					gtitle = fmt.Sprintf("%v", v)
				}
				if ctrls, ok := gm["controls"].([]interface{}); ok {
					for _, c := range ctrls {
						cm, ok := c.(map[string]interface{})
						if !ok {
							continue
						}
						cid := ""
						if v, ok := cm["id"]; ok && v != nil {
							cid = strings.ToUpper(fmt.Sprintf("%v", v))
						}
						if len(cid) > 0 {
							groupMap[cid] = gtitle
						}
					}
				}
			}
		}
	}
	type metaEntry struct {
		ControlID string
		Title     string
		Group     string
	}
	meta := make(map[string]metaEntry)
	rendered := make(map[string]string)
	for _, ctrl := range _iterControls(objMap) {
		cid := ""
		if v, ok := ctrl["id"]; ok && v != nil {
			cid = strings.ToUpper(fmt.Sprintf("%v", v))
		}
		if len(cid) == 0 {
			continue
		}
		title := ""
		if v, ok := ctrl["title"]; ok && v != nil {
			title = fmt.Sprintf("%v", v)
		}
		meta[cid] = metaEntry{ControlID: cid, Title: title, Group: groupMap[cid]}
		rendered[cid] = _renderOne(ctrl)
	}
	ctrlIDRe := regexp.MustCompile(`(?i)\b([a-z]{2}-\d+(?:\.\d+)?)\b`)
	for _, chunk := range chunks {
		var ctrlID string
		if m := ctrlIDRe.FindStringSubmatch(chunk.Content); m != nil {
			ctrlID = strings.ToUpper(m[1])
		}
		if len(ctrlID) == 0 {
			for _, part := range chunk.Section {
				if sm := ctrlIDRe.FindStringSubmatch(strings.TrimSpace(part)); sm != nil {
					ctrlID = strings.ToUpper(sm[1])
					break
				}
			}
		}
		if len(ctrlID) > 0 {
			if e, ok := meta[ctrlID]; ok {
				chunk.SourceDetail = map[string]string{
					"control_id": e.ControlID,
					"title":      e.Title,
					"group":      e.Group,
				}
				chunk.RenderedSource = rendered[ctrlID]
			}
		}
	}
	return chunks
}

