// ODFElement is an interface representing an ODF document element.
type ODFElement interface {
	GetQName() (string, string)
	GetAttribute(name string) string
	ExtractText() string
	ChildNodes() []ODFElement
}

// extractODT extracts markdown text from an ODT writer document.
func extractODT(childNodes []ODFElement) string {
	var lines []string
	for _, elem := range childNodes {
		_, tag := elem.GetQName()
		if tag == "h" {
			levelStr := elem.GetAttribute("outlinelevel")
			level := 1
			if levelStr != "" {
				if n, err := strconv.Atoi(levelStr); err == nil {
					level = n
				}
			}
			if level > 6 {
				level = 6
			}
			text := strings.TrimSpace(elem.ExtractText())
			if len(text) > 0 {
				lines = append(lines, fmt.Sprintf("%s %s", strings.Repeat("#", level), text))
			}
		} else if tag == "p" {
			text := strings.TrimSpace(elem.ExtractText())
			if len(text) > 0 {
				lines = append(lines, text)
			}
		}
	}
	return strings.Join(lines, "\n\n")
}

