type OdfExtractor struct{}

// Extract returns plain text from ODF document bytes, dispatching on MIME type.
// Returns an error if the odfpy library equivalent is unavailable.
func (e *OdfExtractor) Extract(data []byte, sourcePath *string) (string, error) {
	if !odfAvailable() {
		return "", fmt.Errorf("odf library is required for ODF extraction: install odf support")
	}
