	mime := strings.ToLower(doc.MimeType())
	if strings.Contains(mime, "spreadsheet") {
		return extractODSDoc(doc), nil
	}
	if strings.Contains(mime, "presentation") {
		return extractODPDoc(doc), nil
	}
	return extractODTDoc(doc), nil
}

