// renderData renders an Arrow table as a markdown pipe table.
func renderData(table ArrowTable) string {
	headers := table.Schema().Names()
	headerRow := "| " + strings.Join(headers, " | ") + " |"
	var seps []string
	for range headers {
		seps = append(seps, "---")
	}
	sepRow := "| " + strings.Join(seps, " | ") + " |"
	rows := []string{headerRow, sepRow}
	for i := 0; i < table.NumRows(); i++ {
		var cells []string
		for _, col := range headers {
			val := strings.ReplaceAll(fmt.Sprintf("%v", table.Column(col).Value(i)), "|", "\\|")
			cells = append(cells, val)
		}
		rows = append(rows, "| "+strings.Join(cells, " | ")+" |")
	}
	return strings.Join(rows, "\n")
}

