// Annotate stamps each chunk's SourceDetail with the PDF page(s) where its content appears.
func (e *PdfExtractor) Annotate(chunks []*DocumentChunk, data []byte, sourcePath *string) ([]*DocumentChunk, error) {
	if !pypdfAvailable() {
		return nil, fmt.Errorf("pip install chonk[pdf]")
	}
	reader, err := openPDFReader(bytes.NewReader(data))
	if err != nil {
		return nil, fmt.Errorf("PdfExtractor.Annotate: open reader: %w", err)
	}
	type pageEntry struct {
		num  int
		text string
	}
	var pageTexts []pageEntry
	for i, page := range reader.Pages() {
		text := strings.TrimSpace(page.ExtractText())
		if len(text) > 0 {
			pageTexts = append(pageTexts, pageEntry{num: i + 1, text: text})
		}
	}
	for _, chunk := range chunks {
		content := chunk.Content
		var matchedPages []int
		for _, pe := range pageTexts {
			frags := strings.Split(content, "\n")
			for _, frag := range frags {
				if len(strings.TrimSpace(frag)) > 20 && strings.Contains(pe.text, frag) {
					matchedPages = append(matchedPages, pe.num)
					break
				}
			}
		}
		if len(matchedPages) > 0 {
			if len(matchedPages) == 1 {
				chunk.SourceDetail = map[string]interface{}{"page": matchedPages[0]}
			} else {
				chunk.SourceDetail = map[string]interface{}{
					"page_start": matchedPages[0],
					"page_end":   matchedPages[len(matchedPages)-1],
				}
			}
		}
	}
	return chunks, nil
}

