// ASTNode is a simplified representation of a Python AST node for Go.
type ASTNode struct {
	Kind      string // "ClassDef", "FunctionDef", "Import", "ImportFrom"
	Name      string
	Docstring string
	Source    string
	Methods   []ASTNode
}

type PythonExtractor struct{}

func (p *PythonExtractor) Extract(data []byte, sourcePath *string) (string, error) {
	if len(data) == 0 {
		return "", nil
	}

	source, err := decodeUTF8(data)
	if err != nil {
		sp := "<unknown>"
		if sourcePath != nil {
			sp = *sourcePath
		}
		return "", fmt.Errorf("UTF-8 decode failed in %s: %w", sp, err)
	}

	tree, err := parsePythonAST(source, sourcePath)
	if err != nil {
		sp := "<unknown>"
		if sourcePath != nil {
			sp = *sourcePath
		}
		return "", fmt.Errorf("Python syntax error in %s: %w", sp, err)
	}

	var parts []string

	// Collect top-level imports
	var importNodes []ASTNode
	for _, node := range tree.Walk() {
		if (node.Kind == "Import" || node.Kind == "ImportFrom") && tree.IsTopLevel(node) {
			importNodes = append(importNodes, node)
		}
	}
	if len(importNodes) > 0 {
		var segments []string
		for _, node := range importNodes {
			seg := node.Source
			if len(seg) > 0 {
				segments = append(segments, seg)
			}
		}
		if len(segments) > 0 {
			parts = append(parts, "## Imports\n\n```python\n"+strings.Join(segments, "\n")+"\n```")
		}
	}

	for _, node := range tree.Children() {
		if node.Kind == "ClassDef" {
			parts = append(parts, fmt.Sprintf("# %s", node.Name))
			if len(node.Docstring) > 0 {
				parts = append(parts, node.Docstring)
			}
			if len(node.Methods) > 0 {
				for _, item := range node.Methods {
					parts = append(parts, fmt.Sprintf("## %s", item.Name))
					if len(item.Docstring) > 0 {
						parts = append(parts, item.Docstring)
					}
					if len(item.Source) > 0 {
						parts = append(parts, fmt.Sprintf("```python\n%s\n```", item.Source))
					}
				}
			} else {
				if len(node.Source) > 0 {
					parts = append(parts, fmt.Sprintf("```python\n%s\n```", node.Source))
				}
			}
		} else if node.Kind == "FunctionDef" || node.Kind == "AsyncFunctionDef" {
			parts = append(parts, fmt.Sprintf("# %s", node.Name))
			if len(node.Docstring) > 0 {
				parts = append(parts, node.Docstring)
			}
			if len(node.Source) > 0 {
				parts = append(parts, fmt.Sprintf("```python\n%s\n```", node.Source))
			}
		}
	}

	return strings.Join(parts, "\n\n"), nil
}

