func advanceJSDoc(stripped, line string, inJSDoc bool, pendingJSDoc []string) (bool, []string) {
	if strings.HasPrefix(stripped, "/**") {
		pendingJSDoc = []string{line}
		inJSDoc = !strings.Contains(stripped, "*/")
		return inJSDoc, pendingJSDoc
	}
	// already inside a JSDoc block
	pendingJSDoc = append(pendingJSDoc, line)
	if strings.Contains(stripped, "*/") {
		inJSDoc = false
	}
	return inJSDoc, pendingJSDoc
}

var classRE = regexp.MustCompile(`^(?:export\s+)?(?:abstract\s+)?class\s+(\w+)`)
var interfaceRE = regexp.MustCompile(`^(?:export\s+)?interface\s+(\w+)`)

// ClassEntry holds the class name and the brace depth at which the class opened.
type ClassEntry struct {
	Name       string
	DepthBefore int
}

func handleClassOrInterface(
	stripped, line string,
	i, braceDepth int,
	classStack *[]ClassEntry,
	pendingJSDoc []string,
	parts *[]string,
) (matched bool, nextI, newBraceDepth int, clearedJSDoc []string) {
	if m := classRE.FindStringSubmatch(stripped); m != nil {
		name := m[1]
		jsdoc := consumeJSDoc(pendingJSDoc)
		*parts = append(*parts, fmt.Sprintf("# %s", name))
		if len(jsdoc) > 0 {
			*parts = append(*parts, jsdoc)
		}
		depthBefore := braceDepth
		braceDepth += strings.Count(line, "{") - strings.Count(line, "}")
		*classStack = append(*classStack, ClassEntry{Name: name, DepthBefore: depthBefore})
		return true, i + 1, braceDepth, nil
	}

	if m := interfaceRE.FindStringSubmatch(stripped); m != nil {
		name := m[1]
		jsdoc := consumeJSDoc(pendingJSDoc)
		*parts = append(*parts, fmt.Sprintf("# %s", name))
		if len(jsdoc) > 0 {
			*parts = append(*parts, jsdoc)
		}
		braceDepth += strings.Count(line, "{") - strings.Count(line, "}")
		return true, i + 1, braceDepth, nil
	}

	return false, i, braceDepth, pendingJSDoc
}

var functionRE = regexp.MustCompile(`^(?:export\s+)?(?:async\s+)?function\s+(\w+)\s*\(`)
var constArrowRE = regexp.MustCompile(`^(?:export\s+)?const\s+(\w+)\s*=\s*(?:async\s*)?\(`)

func handleTopLevelCallable(
	stripped string,
	i, braceDepth int,
	classStack []ClassEntry,
	pendingJSDoc []string,
	parts *[]string,
	sectionMap map[string]SectionInfo,
	lines []string,
) (matched bool, nextI, newBraceDepth int, clearedJSDoc []string) {
	if len(classStack) > 0 {
		return false, i, braceDepth, pendingJSDoc
	}

	var m []string
	if mm := functionRE.FindStringSubmatch(stripped); mm != nil {
		m = mm
	} else if mm := constArrowRE.FindStringSubmatch(stripped); mm != nil {
		m = mm
	}
	if m == nil {
		return false, i, braceDepth, pendingJSDoc
	}

	name := m[1]
	jsdoc := consumeJSDoc(pendingJSDoc)
	*parts = append(*parts, fmt.Sprintf("# %s", name))
	if len(jsdoc) > 0 {
		*parts = append(*parts, jsdoc)
	}
	lineStart := i + 1
	body, nextIdx, newDepth := collectBody(lines, i, braceDepth)
	sectionMap[sectionKeyStr(SectionKey{name})] = SectionInfo{
		LineStart: lineStart,
		LineEnd:   nextIdx,
		Symbol:    name,
	}
	*parts = append(*parts, fmt.Sprintf("```typescript\n%s\n```", body))
	return true, nextIdx, newDepth, nil
}

var methodRE = regexp.MustCompile(`^\s{2,}(?:(?:public|private|protected|static|async|readonly|override)\s+)*(\w+)\s*[=(]\s*`)

var keywordNames = map[string]struct{}{
	"if": {}, "for": {}, "while": {}, "switch": {},
	"return": {}, "else": {}, "try": {}, "catch": {},
}

func handleClassMethod(
	line string,
	i, braceDepth int,
	classStack *[]ClassEntry,
	pendingJSDoc []string,
	parts *[]string,
	sectionMap map[string]SectionInfo,
	lines []string,
) (matched bool, nextI, newBraceDepth int, clearedJSDoc []string) {
	if len(*classStack) == 0 {
		return false, i, braceDepth, pendingJSDoc
	}

	top := (*classStack)[len(*classStack)-1]
	className := top.Name
	classDepth := top.DepthBefore
	if braceDepth != classDepth+1 {
		return false, i, braceDepth, pendingJSDoc
	}

	m := methodRE.FindStringSubmatch(line)
	if m == nil {
		return false, i, braceDepth, pendingJSDoc
	}

	mname := m[1]
	if _, isKeyword := keywordNames[mname]; isKeyword {
		return false, i, braceDepth, pendingJSDoc
	}

	jsdoc := consumeJSDoc(pendingJSDoc)
	*parts = append(*parts, fmt.Sprintf("## %s", mname))
	if len(jsdoc) > 0 {
		*parts = append(*parts, jsdoc)
	}
	lineStart := i + 1
	body, nextIdx, newDepth := collectBody(lines, i, braceDepth)
	sectionMap[sectionKeyStr(SectionKey{className, mname})] = SectionInfo{
		LineStart: lineStart,
		LineEnd:   nextIdx,
		Symbol:    fmt.Sprintf("%s.%s", className, mname),
	}
	*parts = append(*parts, fmt.Sprintf("```typescript\n%s\n```", body))
	if len(*classStack) > 0 && newDepth <= (*classStack)[len(*classStack)-1].DepthBefore {
		*classStack = (*classStack)[:len(*classStack)-1]
	}
	return true, nextIdx, newDepth, nil
}

type TypeScriptExtractor struct{}

func (t *TypeScriptExtractor) scan(source string) (string, map[string]SectionInfo) {
	lines := strings.Split(source, "\n")
	var parts []string
	sectionMap := make(map[string]SectionInfo)

	emitImports(lines, &parts, sectionMap)

	braceDepth := 0
	var classStack []ClassEntry
	var pendingJSDoc []string
	inJSDoc := false
	i := 0

	for i < len(lines) {
		line := lines[i]
		stripped := strings.TrimSpace(line)

		if strings.HasPrefix(stripped, "/**") || inJSDoc {
			inJSDoc, pendingJSDoc = advanceJSDoc(stripped, line, inJSDoc, pendingJSDoc)
			i++
			continue
		}

		matched, nextI, newDepth, newJSDoc := handleClassOrInterface(stripped, line, i, braceDepth, &classStack, pendingJSDoc, &parts)
		if matched {
			i, braceDepth, pendingJSDoc = nextI, newDepth, newJSDoc
			continue
		}

		matched, nextI, newDepth, newJSDoc = handleTopLevelCallable(stripped, i, braceDepth, classStack, pendingJSDoc, &parts, sectionMap, lines)
		if matched {
			i, braceDepth, pendingJSDoc = nextI, newDepth, newJSDoc
			continue
		}

		matched, nextI, newDepth, newJSDoc = handleClassMethod(line, i, braceDepth, &classStack, pendingJSDoc, &parts, sectionMap, lines)
		if matched {
			i, braceDepth, pendingJSDoc = nextI, newDepth, newJSDoc
			continue
		}

		pendingJSDoc = nil
		delta := strings.Count(line, "{") - strings.Count(line, "}")
		braceDepth += delta
		for len(classStack) > 0 && braceDepth <= classStack[len(classStack)-1].DepthBefore {
			classStack = classStack[:len(classStack)-1]
		}

		i++
	}

	return strings.Join(parts, "\n\n"), sectionMap
}

