func (t *TypeScriptExtractor) Annotate(chunks []*DocumentChunk, data []byte, sourcePath *string) ([]*DocumentChunk, error) {
	sp := "<unknown>"
	if sourcePath != nil {
		sp = *sourcePath
	}

	source, err := decodeUTF8(data)
	if err != nil {
		return nil, fmt.Errorf("UTF-8 decode failed in %s: %w", sp, err)
	}

	_, sectionMap := t.scan(source)

	for _, chunk := range chunks {
		key := sectionKeyStr(SectionKey(chunk.Section))
		if info, ok := sectionMap[key]; ok {
			chunk.SourceDetail = map[string]interface{}{
				"line_start": info.LineStart,
				"line_end":   info.LineEnd,
				"symbol":     info.Symbol,
			}
		}
	}

	return chunks, nil
}

func collectBody(lines []string, start, currentDepth int) (body string, nextI, finalDepth int) {
	var collected []string
	depth := currentDepth
	foundOpen := false
	i := start

	for i < len(lines) {
		line := lines[i]
		collected = append(collected, line)
		opens := strings.Count(line, "{")
		closes := strings.Count(line, "}")
		if opens > 0 {
			foundOpen = true
		}
		depth += opens - closes
		i++
		if foundOpen && depth <= currentDepth {
			break
		}
	}

	return strings.Join(collected, "\n"), i, depth
}

