// XMLDict represents a parsed XML element as a generic map for renderer dispatch.
type XMLDict map[string]interface{}

func toDict(element *XMLElement) XMLDict {
	result := make(XMLDict)
	result["_tag"] = xmlTag(element)
	for k, v := range element.Attrib {
		result[k] = v
	}

	if len(element.Children) > 0 {
		childDicts := make(map[string][]XMLDict)
		for _, child := range element.Children {
			key := xmlTag(child)
			childDicts[key] = append(childDicts[key], toDict(child))
		}
		for key, vals := range childDicts {
			if len(vals) > 1 {
				result[key] = vals
			} else {
				result[key] = vals[0]
			}
		}
	} else {
		text := strings.TrimSpace(element.Text)
		if len(text) > 0 {
			result["_text"] = text
		}
	}
	return result
}

