	copy(sorted, ctx.Chunks)
	sort.Slice(sorted, func(i, j int) bool {
		return tierOf(sorted[i].Provenance) < tierOf(sorted[j].Provenance)
	})
	used := estimateTokens(pb.buildHeader(ctx))
	var selected []*ScoredChunk
