	for _, para := range paras {
		rawLines := strings.Split(para, "\n")
		var lines []string
		for _, l := range rawLines {
			if strings.TrimSpace(l) != "" {
				lines = append(lines, l)
			}
		}
		if len(lines) == 0 {
			cleaned = append(cleaned, para)
			continue
		}
		indexCount := 0
		for _, l := range lines {
			if _indexLineRE.MatchString(strings.TrimSpace(l)) {
				indexCount++
			}
		}
		if float64(indexCount)/float64(len(lines)) >= indexLineThreshold {
			continue
		}
		cleaned = append(cleaned, para)
	}
	return strings.Join(cleaned, "\n\n")
}

