// resolveDomains converts namespace/domain name filters to domain ID lists.
// Returns nil when both namespaces and domains are nil (no filter).
func (idx *Index) resolveDomains(namespaces []string, domains []string) []string {
	if namespaces == nil && domains == nil {
		return nil
	}
	targetNS := namespaces
	if len(targetNS) == 0 {
		for ns := range idx.domainMap {
			targetNS = append(targetNS, ns)
		}
	}
	var ids []string
	if domains != nil {
		for _, ns := range targetNS {
			nsMap, ok := idx.domainMap[ns]
			if !ok {
				continue
			}
			for _, name := range domains {
				if did, found := nsMap[name]; found {
					ids = append(ids, did)
				}
			}
		}
	} else {
		for _, ns := range targetNS {
			if nsMap, ok := idx.domainMap[ns]; ok {
				for _, did := range nsMap {
					ids = append(ids, did)
				}
			}
		}
	}
	if len(ids) == 0 {
		return nil
	}
	return ids
}

// RemoveNamespace deletes a namespace and all its domains, chunks, and secondary index rows.
func (idx *Index) RemoveNamespace(namespaceID string) error {
	domainIDs := make([]string, 0)
	if nsMap, ok := idx.domainMap[namespaceID]; ok {
		for _, did := range nsMap {
			domainIDs = append(domainIDs, did)
		}
	}
	if len(domainIDs) > 0 {
		placeholders := make([]string, len(domainIDs))
		for i := range domainIDs {
			placeholders[i] = "?"
		}
		ph := strings.Join(placeholders, ", ")
		args := make([]interface{}, len(domainIDs))
		for i, did := range domainIDs {
			args[i] = did
		}
		queries := []string{
			fmt.Sprintf("DELETE FROM chunk_entities WHERE chunk_id IN (SELECT chunk_id FROM embeddings WHERE domain_id IN (%s))", ph),
			fmt.Sprintf("DELETE FROM svo_triples WHERE chunk_id IN (SELECT chunk_id FROM embeddings WHERE domain_id IN (%s))", ph),
			fmt.Sprintf("DELETE FROM embeddings WHERE domain_id IN (%s)", ph),
			fmt.Sprintf("DELETE FROM domains WHERE domain_id IN (%s)", ph),
		}
		for _, q := range queries {
			if _, err := idx.conn.Exec(q, args...); err != nil {
				return fmt.Errorf("RemoveNamespace: %w", err)
			}
		}
	}
	if _, err := idx.conn.Exec("DELETE FROM namespaces WHERE namespace_id = ?", namespaceID); err != nil {
		return fmt.Errorf("RemoveNamespace: delete namespace: %w", err)
	}
	delete(idx.domainMap, namespaceID)
	idx.invalidateSearch()
	return nil
}

