// ingestGlob loads all files matching a glob pattern from a directory.
func ingestGlob(loader *DocumentLoader, src map[string]interface{}) ([]*DocumentChunk, error) {
	basePath, _ := src["path"].(string)
	pattern, ok := src["pattern"].(string)
	if !ok || pattern == "" {
		pattern = "*"
	}
	prefix, _ := src["name_prefix"].(string)
	docType, _ := src["doc_type"].(string)

	matches, err := filepath.Glob(filepath.Join(basePath, pattern))
	if err != nil {
		return nil, fmt.Errorf("ingestGlob: glob %q: %w", pattern, err)
	}
	sort.Strings(matches)

	var chunks []*DocumentChunk
	for _, p := range matches {
		base := filepath.Base(p)
		if strings.HasPrefix(base, ".") {
			continue
		}
		ext := filepath.Ext(base)
		stem := strings.TrimSuffix(base, ext)
		name := prefix + stem
		var loaded []*DocumentChunk
		if docType != "" {
			data, readErr := os.ReadFile(p)
			if readErr != nil {
				return nil, fmt.Errorf("ingestGlob: read %q: %w", p, readErr)
			}
			loaded, err = loader.LoadBytes(data, name, docType, nil)
		} else {
			loaded, err = loader.Load(p, &name)
		}
		if err != nil {
			return nil, fmt.Errorf("ingestGlob: load %q: %w", p, err)
		}
		chunks = append(chunks, loaded...)
	}
	return chunks, nil
}

// ingestJSONArray loads chunks from items in a JSON array field.
func ingestJSONArray(loader *DocumentLoader, src map[string]interface{}) ([]*DocumentChunk, error) {
	path, _ := src["path"].(string)
	arrayField, _ := src["array_field"].(string)
	idPathStr, _ := src["id_path"].(string)
	var idPath []string
	if idPathStr != "" {
		idPath = strings.Split(idPathStr, ".")
	}

	raw, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("ingestJSONArray: read %q: %w", path, err)
	}
	var obj interface{}
	if err := json.Unmarshal(raw, &obj); err != nil {
		return nil, fmt.Errorf("ingestJSONArray: parse JSON: %w", err)
	}

	var items []interface{}
	if m, ok := obj.(map[string]interface{}); ok {
		if v, ok2 := m[arrayField]; ok2 {
			if arr, ok3 := v.([]interface{}); ok3 {
				items = arr
			}
		}
	} else if arr, ok := obj.([]interface{}); ok {
		items = arr
	}

	stem := strings.TrimSuffix(filepath.Base(path), filepath.Ext(path))
	var chunks []*DocumentChunk
	for _, item := range items {
		var nameVal interface{} = item
		for _, key := range idPath {
			if m, ok := nameVal.(map[string]interface{}); ok {
				nameVal = m[key]
			} else {
				nameVal = "unknown"
				break
			}
		}
		name := stem
		if nameVal != nil {
			if s := fmt.Sprintf("%v", nameVal); s != "" && s != "<nil>" {
				name = s
			}
		}
		payload, err := json.Marshal(map[string]interface{}{arrayField: []interface{}{item}})
		if err != nil {
			return nil, fmt.Errorf("ingestJSONArray: marshal item: %w", err)
		}
		loaded, err := loader.LoadBytes(payload, name, "json", nil)
		if err != nil {
			return nil, fmt.Errorf("ingestJSONArray: load bytes: %w", err)
		}
		chunks = append(chunks, loaded...)
	}
	return chunks, nil
}

