// LoadSchema builds N+1 DocumentChunks per table (one table chunk + one per column).
func (dl *DocumentLoader) LoadSchema(tables []*TableMeta) []*DocumentChunk {
	var chunks []*DocumentChunk
	for _, table := range tables {
		dbPrefix := "db"
		if table.SourceDB != "" {
			dbPrefix = table.SourceDB
		}
		docName := fmt.Sprintf("schema:%s.%s", dbPrefix, table.Name)

		lines := []string{fmt.Sprintf("Table: %s", table.Name)}
		if table.SchemaName != "" {
			lines = append(lines, fmt.Sprintf("Schema: %s", table.SchemaName))
		}
		if table.SourceDB != "" {
			lines = append(lines, fmt.Sprintf("Source DB: %s", table.SourceDB))
		}
		if table.RowCount != nil {
			lines = append(lines, fmt.Sprintf("Row count: %d", *table.RowCount))
		}
		if table.Description != "" {
			lines = append(lines, fmt.Sprintf("Description: %s", table.Description))
		}
		if len(table.Columns) > 0 {
			var colNames []string
			for _, c := range table.Columns {
				colNames = append(colNames, c.Name)
			}
			lines = append(lines, fmt.Sprintf("Columns: %s", strings.Join(colNames, ", ")))
		}
		chunks = append(chunks, &DocumentChunk{
			DocumentName: docName,
			Content:      strings.Join(lines, "\n"),
			Section:      []string{"table_description"},
			ChunkIndex:   0,
			ChunkType:    "db_table",
		})

		for colIdx, col := range table.Columns {
			colDocName := fmt.Sprintf("schema:%s.%s.%s", dbPrefix, table.Name, col.Name)
			nullableStr := "no"
			if col.Nullable {
				nullableStr = "yes"
			}
			colLines := []string{
				fmt.Sprintf("Column: %s", col.Name),
				fmt.Sprintf("Table: %s", table.Name),
				fmt.Sprintf("Type: %s", col.DataType),
				fmt.Sprintf("Nullable: %s", nullableStr),
			}
			if col.IsPrimaryKey {
				colLines = append(colLines, "Primary key: yes")
			}
			if col.IsForeignKey && col.ForeignKeyRef != "" {
				colLines = append(colLines, fmt.Sprintf("Foreign key: %s", col.ForeignKeyRef))
			}
			if col.Description != "" {
				colLines = append(colLines, fmt.Sprintf("Description: %s", col.Description))
			}
			chunks = append(chunks, &DocumentChunk{
				DocumentName: colDocName,
				Content:      strings.Join(colLines, "\n"),
				Section:      []string{"column_description"},
				ChunkIndex:   colIdx + 1,
				ChunkType:    "db_column",
			})
		}
	}
	return dl.enrich(chunks)
}

