func (b *RelationshipIndexBuilder) Build(
	extractor SVOExtractorIface,
	chunks []ChunkPair,
	onComplete func(*RelationshipIndex),
) {
	go func() {
		b.alive.Store(true)
		defer b.alive.Store(false)

		idx := NewRelationshipIndex()
		for _, pair := range chunks {
			triples, err := extractor.Extract(pair.ChunkID, pair.Text)
			if err != nil {
				log.Printf("RelationshipIndexBuilder: extract error: %v", err)
