		if err != nil {
			log.Printf("RelationshipIndexBuilder background build failed: %v", err)
			return
		}
		log.Printf("RelationshipIndex version %d ready (%d triples)", newVersion, idx.Len())
		if onComplete != nil {
			onComplete(idx)
		}
	}()
}

