func buildEntityMaps(ceRows [][2]string, chunkClusterMap map[string]int) entityMaps {
	entityToChunks := make(map[string]map[string]struct{})
	for _, r := range ceRows {
		chunkID, entityID := r[0], r[1]
		if entityToChunks[entityID] == nil {
			entityToChunks[entityID] = make(map[string]struct{})
		}
		entityToChunks[entityID][chunkID] = struct{}{}
	}

	allEntities := make([]string, 0, len(entityToChunks))
	for e := range entityToChunks {
		allEntities = append(allEntities, e)
	}
	sort.Strings(allEntities)

	entityToClusters := make(map[string]map[int]struct{})
	for chunkID, clusterID := range chunkClusterMap {
		for eid, chunks := range entityToChunks {
			if _, ok := chunks[chunkID]; ok {
				if entityToClusters[eid] == nil {
					entityToClusters[eid] = make(map[int]struct{})
				}
				entityToClusters[eid][clusterID] = struct{}{}
			}
		}
	}
	return entityMaps{
		entityToChunks:   entityToChunks,
		entityToClusters: entityToClusters,
		allEntities:      allEntities,
	}
}

