type finalEdge struct {
	A, B                               string
	Weight, SVOSignal, CoocSignal, ClustSignal float64
}

func normalizeEdges(rawEdges []rawEdge, minWeight float64) []finalEdge {
	if len(rawEdges) == 0 {
		return nil
	}
	maxRaw := 0.0
	for _, e := range rawEdges {
		if e.RawWeight > maxRaw {
			maxRaw = e.RawWeight
		}
	}

	var out []finalEdge
	for _, e := range rawEdges {
		weight := 0.0
		if maxRaw > 0 {
			weight = e.RawWeight / maxRaw
		}
		if weight >= minWeight {
			out = append(out, finalEdge{
				A: e.A, B: e.B,
				Weight: weight, SVOSignal: e.SVOSignal,
				CoocSignal: e.CoocSignal, ClustSignal: e.ClustSignal,
			})
		}
	}
	return out
}

func persistContextGraphEdges(conn DBConn, edges []finalEdge, namespace string) (edgeCount int, err error) {
	if err = conn.Exec("DELETE FROM context_graph_edges WHERE namespace = ?", namespace); err != nil {
		return 0, fmt.Errorf("persistContextGraphEdges delete: %w", err)
	}

	if len(edges) > 0 {
		rows := make([][]interface{}, 0, len(edges)*2)
		for _, e := range edges {
			rows = append(rows,
				[]interface{}{e.A, e.B, namespace, e.Weight, e.SVOSignal, e.CoocSignal, e.ClustSignal},
				[]interface{}{e.B, e.A, namespace, e.Weight, e.SVOSignal, e.CoocSignal, e.ClustSignal},
			)
		}
		if err = conn.ExecMany(
			"INSERT INTO context_graph_edges (source_entity_id, target_entity_id, namespace, weight, svo_signal, cooccur_signal, cluster_signal) VALUES (?, ?, ?, ?, ?, ?, ?)",
			rows,
		); err != nil {
			return 0, fmt.Errorf("persistContextGraphEdges insert: %w", err)
		}
	}
	return len(edges) * 2, nil
}

type BuildAllNamespacesOpts struct {
	MinWeight float64 // Note: zero value 0.0 is ambiguous; pass 0.1 as default
	Force     bool
	Algorithm string
	MinChunks int
}

func BuildContextGraphAllNamespaces(conn DBConn, opts BuildAllNamespacesOpts) (map[string]ContextGraphStats, error) {
	rows, err := conn.Query("SELECT DISTINCT COALESCE(namespace, 'global') FROM chunk_entities")
	if err != nil {
		return nil, fmt.Errorf("BuildContextGraphAllNamespaces list namespaces: %w", err)
	}
	namespaces := make([]string, 0, len(rows))
	for _, r := range rows {
		namespaces = append(namespaces, r[0].(string))
	}

	results := make(map[string]ContextGraphStats, len(namespaces))
	for _, ns := range namespaces {
		stats, err := BuildContextGraphEdges(conn, ns, opts)
		if err != nil {
			return nil, fmt.Errorf("BuildContextGraphAllNamespaces namespace %q: %w", ns, err)
		}
		results[ns] = stats
	}
	return results, nil
}

func GetContextGraphEdges(conn DBConn, entityID string, namespace string, minWeight float64) ([]ContextEdge, error) {
	checkRows, err := conn.Query(
		"SELECT 1 FROM context_graph_edges WHERE namespace = ? LIMIT 1", namespace,
	)
	if err != nil || len(checkRows) == 0 {
		log.Printf("context graph not built for namespace %q — skipping expansion; call BuildContextGraph to enable", namespace)
		return []ContextEdge{}, nil
	}

	rows, err := conn.Query(
		`SELECT target_entity_id, weight, svo_signal, cooccur_signal, cluster_signal
		FROM context_graph_edges
		WHERE source_entity_id = ? AND namespace = ? AND weight >= ?
		ORDER BY weight DESC`,
		entityID, namespace, minWeight,
	)
	if err != nil {
		return nil, fmt.Errorf("GetContextGraphEdges query: %w", err)
	}

	out := make([]ContextEdge, 0, len(rows))
	for _, r := range rows {
		out = append(out, ContextEdge{
			SourceEntityID: entityID,
			TargetEntityID: r[0].(string),
			Weight:         r[1].(float64),
			SVOSignal:      r[2].(float64),
			CooccurSignal:  r[3].(float64),
			ClusterSignal:  r[4].(float64),
		})
	}
	return out, nil
}

