type extractOneResult struct {
	triples      []SVOTriple
	descriptions map[string]string
	aliases      map[string][]string
}

func (p *EntityGraphPipeline) buildPhase2Extract(
	eligible [][2]string,
	chunkEntitiesMap map[string][]chunkEntityEntry,
	prog func(string, int, int),
) (relationshipIndex *RelationshipIndex, newDescriptions map[string]string, newAliases map[string][]string, chunksProcessed int, err error) {
	relationshipIndex = NewRelationshipIndex()
	newDescriptions = make(map[string]string)
	newAliases = make(map[string][]string)

	total := len(eligible)
	prog(PhaseExtract, 0, total)

	type jobResult struct {
		res extractOneResult
		err error
	}

	jobs := make(chan [2]string, len(eligible))
	results := make(chan jobResult, len(eligible))

	for i := 0; i < p.concurrency; i++ {
		go func() {
			for row := range jobs {
				chunkID, content := row[0], row[1]
				entities := chunkEntitiesMap[chunkID]
				if len(entities) < 2 {
					results <- jobResult{res: extractOneResult{
						tripples: nil, descriptions: nil, aliases: nil,
					}}
					continue
				}
				triples, descs, aliases, _, extractErr := p.extractor.ExtractEntityAnchored(content, chunkID, entities)
				results <- jobResult{res: extractOneResult{triples: triples, descriptions: descs, aliases: aliases}, err: extractErr}
			}
		}()
	}
	for _, row := range eligible {
		jobs <- row
	}
	close(jobs)

	done := 0
	for range eligible {
		r := <-results
		if r.err != nil {
			return nil, nil, nil, 0, fmt.Errorf("buildPhase2Extract: %w", r.err)
		}
		for _, t := range r.res.triples {
			relationshipIndex.Add(t)
		}
		for k, v := range r.res.descriptions {
			newDescriptions[k] = v
		}
		for eid, aliasList := range r.res.aliases {
			newAliases[eid] = append(newAliases[eid], aliasList...)
		}
		done++
		chunksProcessed++
		prog(PhaseExtract, done, total)
	}
	return relationshipIndex, newDescriptions, newAliases, chunksProcessed, nil
}

func (p *EntityGraphPipeline) embedEntitiesLoad(conn DBConn) ([]entityRow, error) {
	if p.embedModel == nil {
		return nil, fmt.Errorf("embedEntitiesLoad called without embedModel")
	}
	rows, err := conn.Query(`
		SELECT e.id, e.name,
		       COALESCE(e.description, '') AS description,
		       e.entity_type
		FROM entities e`)
	if err != nil {
		return nil, fmt.Errorf("embedEntitiesLoad query: %w", err)
	}
	if len(rows) == 0 {
		return nil, nil
	}
	out := make([]entityRow, 0, len(rows))
	for _, r := range rows {
		out = append(out, entityRow{
			ID:          r[0].(string),
			Name:        r[1].(string),
			Description: r[2].(string),
			EntityType:  r[3].(string),
		})
	}
	return out, nil
}

func (p *EntityGraphPipeline) embedEntitiesEncodeAndStore(
	store Store,
	conn DBConn,
	texts []string,
	chunks []DocumentChunk,
	prog func(string, int, int),
) (int, error) {
	if len(chunks) == 0 {
		return 0, nil
	}
	prog(PhaseEmbedEntities, 0, len(chunks))

	vecs, err := p.embedModel.Encode(texts, EncodeOpts{
		NormalizeEmbeddings: true,
		ShowProgressBar:     false,
		BatchSize:           512,
	})
	if err != nil {
		return 0, fmt.Errorf("embedEntitiesEncodeAndStore encode: %w", err)
	}

	if err := conn.Exec("DELETE FROM embeddings WHERE chunk_type = 'entity'"); err != nil {
		return 0, fmt.Errorf("embedEntitiesEncodeAndStore delete old: %w", err)
	}
	if err := store.AddDocument(chunks, vecs); err != nil {
		return 0, fmt.Errorf("embedEntitiesEncodeAndStore add_document: %w", err)
	}
	prog(PhaseEmbedEntities, len(chunks), len(chunks))
	return len(chunks), nil
}

