// SVOExtractorOptions holds optional overrides for NewSVOExtractor.
// Note: nil fields fall back to package-level defaults.
type SVOExtractorOptions struct {
	VerbSet              map[string]struct{} // nil → use DefaultVerbSet
	SystemPromptTemplate *string             // nil → use systemPrompt constant
	UserTemplate         *string             // nil → use userTemplate constant
}

// SVOExtractor extracts SVOTriples from text using an injected LLM client.
type SVOExtractor struct {
	llm          LLMClient
	verbSet      map[string]struct{}
	userTemplate string
	system       string
}

// NewSVOExtractor constructs an SVOExtractor. llm must be non-nil.
func NewSVOExtractor(llm LLMClient, opts SVOExtractorOptions) (*SVOExtractor, error) {
	if llm == nil {
		return nil, fmt.Errorf("NewSVOExtractor: llm must implement LLMClient, got nil")
	}

	verbSet := opts.VerbSet
	if verbSet == nil {
		verbSet = DefaultVerbSet
	}

	sysTmpl := systemPrompt
	if opts.SystemPromptTemplate != nil {
		sysTmpl = *opts.SystemPromptTemplate
	}

	userTmpl := userTemplate
	if opts.UserTemplate != nil {
		userTmpl = *opts.UserTemplate
	}

	// Build sorted verb list for the system prompt.
	verbs := make([]string, 0, len(verbSet))
	for v := range verbSet {
		verbs = append(verbs, v)
	}
	sort.Strings(verbs)
	systemMsg := fmt.Sprintf(sysTmpl, strings.Join(verbs, ", "))

	return &SVOExtractor{
		llm:          llm,
		verbSet:      verbSet,
		userTemplate: userTmpl,
		system:       systemMsg,
	}, nil
}

// TextChunkPair holds a text passage and its optional chunk identifier.
type TextChunkPair struct {
	Text    string
	ChunkID *string // nil when no source identifier is available
}

// ExtractBatch extracts SVOTriples from multiple text/chunk-id pairs.
// Returns a flat slice of all valid triples across all inputs.
func (e *SVOExtractor) ExtractBatch(texts []TextChunkPair) []SVOTriple {
	results := make([]SVOTriple, 0)
	for _, pair := range texts {
		triples := e.Extract(pair.Text, pair.ChunkID)
		results = append(results, triples...)
	}
	return results
}

