// parseEntityAnchored parses an entity-anchored LLM response.
// Returns (zero EntityAnchoredResult, false) on JSON failure or type mismatch.
func (e *SVOExtractor) parseEntityAnchored(raw string, chunkID *string, validIDs map[string]struct{}) (EntityAnchoredResult, bool) {
	cleaned := codeBlockRe.ReplaceAllString(raw, "")
	cleaned = strings.TrimSpace(cleaned)

	var obj map[string]interface{}
	if err := json.Unmarshal([]byte(cleaned), &obj); err != nil {
		return EntityAnchoredResult{}, false
	}

	// Parse rel_descriptions first so they can be attached to triples.
	relDescriptions := make(map[string]string)
	if rdRaw, ok := obj["rel_descriptions"]; ok && rdRaw != nil {
		if rdMap, ok := rdRaw.(map[string]interface{}); ok {
			for k, v := range rdMap {
				desc, ok := v.(string)
				if !ok {
					continue
				}
				desc = strings.TrimSpace(desc)
				if len(desc) > 0 {
					relDescriptions[k] = desc
				}
			}
		}
	}

	triples := make([]SVOTriple, 0)
	if triplesRaw, ok := obj["triples"]; ok && triplesRaw != nil {
		if rows, ok := triplesRaw.([]interface{}); ok {
			for _, item := range rows {
				row, ok := item.(map[string]interface{})
				if !ok {
					continue
				}
				verb, ok := row["verb"].(string)
				if !ok {
					continue
				}
				subj, ok := row["subject_id"].(string)
				if !ok {
					continue
				}
				objID, ok := row["object_id"].(string)
				if !ok {
					continue
				}
				conf, ok := row["confidence"].(float64)
				if !ok {
					continue
				}
				if _, allowed := e.verbSet[verb]; !allowed {
					continue
				}
				if _, subjOK := validIDs[subj]; !subjOK {
					continue
				}
				if _, objOK := validIDs[objID]; !objOK {
					continue
				}
				relKey := fmt.Sprintf("%s|%s|%s", subj, verb, objID)
				desc := relDescriptions[relKey]
				t, err := NewSVOTriple(subj, verb, objID, conf, chunkID, desc)
				if err != nil {
					continue
				}
				triples = append(triples, t)
			}
		}
	}

	descriptions := make(map[string]string)
	if descsRaw, ok := obj["descriptions"]; ok && descsRaw != nil {
		if descsMap, ok := descsRaw.(map[string]interface{}); ok {
			for eid, v := range descsMap {
				if _, valid := validIDs[eid]; !valid {
					continue
				}
				desc, ok := v.(string)
				if !ok {
					continue
				}
				desc = strings.TrimSpace(desc)
				if len(desc) > 0 {
					descriptions[eid] = desc
				}
			}
		}
	}

	aliases := make(map[string][]string)
	if aliasesRaw, ok := obj["aliases"]; ok && aliasesRaw != nil {
		if aliasesMap, ok := aliasesRaw.(map[string]interface{}); ok {
			for eid, v := range aliasesMap {
				if _, valid := validIDs[eid]; !valid {
					continue
				}
				aliasList, ok := v.([]interface{})
				if !ok {
					continue
				}
				clean := make([]string, 0)
				for _, a := range aliasList {
					s, ok := a.(string)
					if !ok {
						continue
					}
					s = strings.TrimSpace(s)
					if len(s) > 0 {
						clean = append(clean, s)
					}
				}
				if len(clean) > 0 {
					aliases[eid] = clean
				}
			}
		}
	}

	return EntityAnchoredResult{
		Triples:         triples,
		Descriptions:    descriptions,
		Aliases:         aliases,
		RelDescriptions: relDescriptions,
	}, true
}

