type svoDBRow struct {
	chunkID     *string
	subjectID   string
	verb        string
	objectID    string
	confidence  float64
	namespace   *string
	description string
}

// DBConn is the minimal interface required by SaveToDB.
type DBConn interface {
	Exec(query string, args ...interface{}) error
	QueryRow(query string, args ...interface{}) (string, bool, error) // returns namespace, found, err
	ExecMany(query string, rows []svoDBRow) error
}

// SaveToDB upserts all triples into the svo_triples table and returns the count written.
// If incremental is false the table is cleared before inserting.
func (idx *RelationshipIndex) SaveToDB(con DBConn, incremental bool) (int, error) {
	if err := con.Exec(`CREATE TABLE IF NOT EXISTS svo_triples (
		chunk_id    VARCHAR,
		subject_id  VARCHAR NOT NULL,
		verb        VARCHAR NOT NULL,
		object_id   VARCHAR NOT NULL,
		confidence  FLOAT   NOT NULL DEFAULT 1.0,
		namespace   VARCHAR,
		description TEXT    NOT NULL DEFAULT ''
	)`); err != nil {
		return 0, fmt.Errorf("SaveToDB: create table: %w", err)
	}
	if err := con.Exec("ALTER TABLE svo_triples ADD COLUMN IF NOT EXISTS namespace VARCHAR"); err != nil {
		return 0, fmt.Errorf("SaveToDB: alter namespace: %w", err)
	}
	if err := con.Exec("ALTER TABLE svo_triples ADD COLUMN IF NOT EXISTS description TEXT"); err != nil {
		return 0, fmt.Errorf("SaveToDB: alter description: %w", err)
	}
	if !incremental {
		if err := con.Exec("DELETE FROM svo_triples"); err != nil {
			return 0, fmt.Errorf("SaveToDB: delete: %w", err)
		}
	}

	rows := make([]svoDBRow, 0)
	for _, triples := range idx.bySubject {
		for _, t := range triples {
			ns, found, err := con.QueryRow("SELECT namespace FROM embeddings WHERE chunk_id = ?", t.SourceChunkID)
			if err != nil {
				return 0, fmt.Errorf("SaveToDB: namespace lookup: %w", err)
			}
			var namespace *string
			if found {
				namespace = &ns
			}
			rows = append(rows, svoDBRow{
				chunkID:     t.SourceChunkID,
				subjectID:   t.SubjectID,
				verb:        t.Verb,
				objectID:    t.ObjectID,
				confidence:  t.Confidence,
				namespace:   namespace,
				description: t.Description,
			})
		}
	}
	if len(rows) > 0 {
		if err := con.ExecMany("INSERT INTO svo_triples VALUES (?, ?, ?, ?, ?, ?, ?)", rows); err != nil {
			return 0, fmt.Errorf("SaveToDB: insert: %w", err)
		}
	}
	return len(rows), nil
}

