// LoadFromDB loads a RelationshipIndex from the svo_triples (or all_svo_triples) table.
// Returns an empty index (not an error) when the table does not exist.
// namespaces may be nil to load all namespaces.
func LoadFromDB(con LoadDBConn, namespaces []string) (*RelationshipIndex, error) {
	idx := NewRelationshipIndex()

	count, err := con.QueryCount(
		"SELECT COUNT(*) FROM information_schema.tables WHERE table_name = 'all_svo_triples'",
	)
	if err != nil {
		// Table metadata query failed — return empty index gracefully.
		return idx, nil
	}
	table := "svo_triples"
	if count > 0 {
		table = "all_svo_triples"
	}

	var rows []svoQueryRow
	if namespaces != nil {
		placeholders := make([]string, len(namespaces))
		for i := range namespaces {
			placeholders[i] = "?"
		}
		query := fmt.Sprintf(
			"SELECT chunk_id, subject_id, verb, object_id, confidence, COALESCE(description, '') FROM %s WHERE namespace IN (%s)",
			table, strings.Join(placeholders, ", "),
		)
		args := make([]interface{}, len(namespaces))
		for i, ns := range namespaces {
			args[i] = ns
		}
		rows, err = con.QuerySVORows(query, args...)
	} else {
		query := fmt.Sprintf(
			"SELECT chunk_id, subject_id, verb, object_id, confidence, COALESCE(description, '') FROM %s",
			table,
		)
		rows, err = con.QuerySVORows(query)
	}
	if err != nil {
		// Failed to query — return empty index gracefully.
		return idx, nil
	}

	for _, row := range rows {
		t, err := NewSVOTriple(row.SubjectID, row.Verb, row.ObjectID, row.Confidence, row.ChunkID, row.Description)
		if err != nil {
			continue
		}
		idx.Add(t)
	}
	return idx, nil
}

