// NewSVOTriple constructs a validated SVOTriple.
// Returns an error when confidence is outside [0.0, 1.0].
func NewSVOTriple(subjectID, verb, objectID string, confidence float64, sourceChunkID *string, description string) (SVOTriple, error) {
	if confidence < 0.0 || confidence > 1.0 {
		return SVOTriple{}, fmt.Errorf("NewSVOTriple: confidence must be in [0.0, 1.0], got %f", confidence)
	}
	return SVOTriple{
		SubjectID:     subjectID,
		Verb:          verb,
		ObjectID:      objectID,
		Confidence:    confidence,
		SourceChunkID: sourceChunkID,
		Description:   description,
	}, nil
}

