import "database/sql"

// checkCache determines incremental mode and the set of chunk IDs to skip.
// Returns (shouldReturnEarly, incremental, skipIDs).
func checkCache(db *sql.DB, fingerprint string, force bool) (bool, bool, map[string]struct{}, error) {
	// R04: set comprehension → explicit loop; R05: set → map[string]struct{}
	allChunkIDs := make(map[string]struct{})
	rows, err := db.Query("SELECT chunk_id FROM embeddings")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query embeddings: %w", err) // R03
	}
	defer rows.Close()
	for rows.Next() {
		var cid string
		if err := rows.Scan(&cid); err != nil {
			return false, false, nil, fmt.Errorf("checkCache: scan embedding row: %w", err)
		}
		allChunkIDs[cid] = struct{}{}
	}

	processedIDs := make(map[string]struct{})
	rows2, err := db.Query("SELECT DISTINCT chunk_id FROM chunk_entities")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query chunk_entities: %w", err)
	}
	defer rows2.Close()
	for rows2.Next() {
		var cid string
		if err := rows2.Scan(&cid); err != nil {
			return false, false, nil, fmt.Errorf("checkCache: scan chunk_entities row: %w", err)
		}
		processedIDs[cid] = struct{}{}
	}

	var cachedCount *int
	var cnt int
	err = db.QueryRow("SELECT chunk_count FROM ner_cache WHERE config_fingerprint = ?", fingerprint).Scan(&cnt)
	if err == nil {
		cachedCount = &cnt
	}

	configMatch := cachedCount != nil // R11: cached is not None → cachedCount != nil
	newChunkIDs := make(map[string]struct{})
	for id := range allChunkIDs {
		if _, seen := processedIDs[id]; !seen {
			newChunkIDs[id] = struct{}{}
		}
	}

	empty := make(map[string]struct{})
	if force {
		return false, false, empty, nil
	}
	if configMatch && len(newChunkIDs) == 0 { // R11: not new_chunk_ids → len == 0
		return true, false, empty, nil
	}
	if configMatch && len(newChunkIDs) > 0 { // R11: new_chunk_ids → len > 0
		return false, true, processedIDs, nil
	}
	return false, false, empty, nil
}

