// persistAssociations writes associations and entities to the DB.
// Unless incremental is true, existing rows are deleted first.
func persistAssociations(
	db *sql.DB,
	data map[string]interface{},
	entityMeta map[string]EntityMeta,
	incremental bool,
) error {
	if !incremental { // R11: if not incremental → !incremental
		if _, err := db.Exec("DELETE FROM chunk_entities"); err != nil {
			return fmt.Errorf("persistAssociations: delete chunk_entities: %w", err) // R03
		}
		if _, err := db.Exec("DELETE FROM entities"); err != nil {
			return fmt.Errorf("persistAssociations: delete entities: %w", err)
		}
	}

	assocs, _ := data["associations"].([]map[string]interface{}) // R05: dict → map
	for _, a := range assocs { // R10: for a in data["associations"] → for _, a := range
		chunkID, _ := a["chunk_id"].(string)
		entityID, _ := a["entity_id"].(string)
		freq, _ := a["frequency"].(int)
		score, _ := a["score"].(float64)
		positions, _ := a["positions"].([]int)

		posJSON, err := json.Marshal(positions)
		if err != nil {
			return fmt.Errorf("persistAssociations: marshal positions: %w", err)
		}

		var chunkNamespace *string // R06: None → nil *string
		var ns string
		err = db.QueryRow("SELECT namespace FROM embeddings WHERE chunk_id = ?", chunkID).Scan(&ns)
		if err == nil {
			chunkNamespace = &ns // R11: ns_row[0] if ns_row else None → pointer or nil
		}

		_, err = db.Exec(
			"INSERT OR REPLACE INTO chunk_entities(chunk_id, entity_id, frequency, positions_json, score, namespace) VALUES (?,?,?,?,?,?)",
			chunkID, entityID, freq, string(posJSON), score, chunkNamespace,
		)
		if err != nil {
			return fmt.Errorf("persistAssociations: upsert chunk_entities: %w", err)
		}

		meta, ok := entityMeta[entityID]
		if !ok { // R11: .get() default → map lookup + fallback
			meta = EntityMeta{Name: entityID, DisplayName: entityID, EntityType: "concept"}
		}
		_, err = db.Exec(
			"INSERT OR IGNORE INTO entities(id, name, display_name, entity_type) VALUES (?,?,?,?)",
			entityID, meta.Name, meta.DisplayName, meta.EntityType,
		)
		if err != nil {
