// BuildNER runs NER on all chunks in store and persists results to chunk_entities.
// Returns the number of chunk_entity associations written.
func BuildNER(store *Store, opts BuildNEROptions) (int, error) {
	// Apply defaults (R12)
	if opts.SpacyModel == "" {
		opts.SpacyModel = "en_core_web_sm"
	}
	if opts.Namespace == "" {
		opts.Namespace = "global"
	}

	db := store.Vector.Conn()
	if _, err := db.Exec(nerCacheDDL); err != nil {
		return 0, fmt.Errorf("BuildNER: create ner_cache: %w", err) // R03
	}

	fingerprint, err := nerConfigFingerprint(opts.SpacyModel, opts.UseSchemaVocab, opts.VocabEntities)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: fingerprint: %w", err)
	}

	shouldReturnEarly, incremental, skipIDs, err := checkCache(db, fingerprint, opts.Force)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: check cache: %w", err)
	}
	if shouldReturnEarly { // R11: if should_return_early → explicit bool check
		var cnt int
		if err := db.QueryRow("SELECT COUNT(*) FROM chunk_entities").Scan(&cnt); err != nil {
			return 0, fmt.Errorf("BuildNER: count chunk_entities: %w", err)
		}
		return cnt, nil
	}

	// R04: [t for t in SpacyLabel if t not in _NUMERIC_TYPES] → explicit loop
	labelTypes := make([]SpacyLabel, 0)
	for _, t := range AllSpacyLabels() {
		if !isNumericType(t) {
			labelTypes = append(labelTypes, t)
		}
	}
	matcher, err := NewSpacyMatcher(opts.SpacyModel, true, labelTypes)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: init spacy matcher: %w", err)
	}

	allChunks, err := store.Vector.GetAllChunks()
	if err != nil {
		return 0, fmt.Errorf("BuildNER: get chunks: %w", err)
	}
	schemaMatcher, dataMatcher, err := buildVocabMatchers(allChunks, opts.UseSchemaVocab, opts.VocabEntities)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: vocab matchers: %w", err)
	}
	chunksToProcess := collectChunksToProcess(allChunks, skipIDs)

	entityIndex, entityMeta, err := runNEROnChunks(chunksToProcess, matcher, schemaMatcher, dataMatcher)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: run NER: %w", err)
	}

	data := entityIndex.ToDict()
	if err := persistAssociations(db, data, entityMeta, incremental); err != nil {
		return 0, fmt.Errorf("BuildNER: persist: %w", err)
	}

	allChunkCount, err := allChunkIDCount(db)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: count chunks: %w", err)
	}
	if _, err := db.Exec(
		"INSERT OR REPLACE INTO ner_cache(config_fingerprint, chunk_count) VALUES (?, ?)",
		fingerprint, allChunkCount,
	); err != nil {
		return 0, fmt.Errorf("BuildNER: update cache: %w", err)
	}

	if opts.BuildContextGraph { // R11: if build_context_graph → explicit bool check
		if err := buildContextGraphEdges(db, opts.Namespace, true); err != nil {
			return 0, fmt.Errorf("BuildNER: context graph: %w", err)
		}
	}

	assocs, _ := data["associations"].([]map[string]interface{})
	return len(assocs), nil
}

