// singularExceptions contains words that should never be singularized.
var singularExceptions = map[string]struct{}{
	"data":      {},
	"metadata":  {},
	"criteria":  {},
	"media":     {},
	"agenda":    {},
	"stamina":   {},
	"trivia":    {},
	"insignia":  {},
