// singularize returns the singular form of word, or the original if it is already
// singular, unknown, an acronym, or in the exception set.
// Note: Go has no inflect equivalent; callers must inject a singularizer via
// SingularizerFunc. Returns (result, false) when no singularization was performed.
func singularize(word string, singFn func(string) (string, bool)) string {
	if len(word) == 0 {
		return word
	}
	if isAcronym(word) {
		return word
	}
	lower := strings.ToLower(word)
	if _, ok := singularExceptions[lower]; ok {
		return word
	}
	if singFn == nil {
		return word
	}
	result, ok := singFn(word)
	if !ok {
		return word
	}
	if len(result) == 0 {
		return word
	}
	runes := []rune(word)
	if unicode.IsUpper(runes[0]) && !isAcronym(word) {
		resultRunes := []rune(strings.ToLower(result))
		if len(resultRunes) > 0 {
			resultRunes[0] = unicode.ToUpper(resultRunes[0])
		}
		return string(resultRunes)
	}
	return result
}

