var camelBoundary = regexp.MustCompile(`(?:[a-z0-9])(?:[A-Z])|(?:[A-Z])(?:[A-Z][a-z])`)

// splitResult holds the tokens and separator returned by splitTokens.
type splitResult struct {
	tokens []string
	sep    string
}

// splitTokens splits text into tokens and returns the separator style used.
func splitTokens(text string) splitResult {
	if strings.Contains(text, " ") {
		return splitResult{tokens: strings.Split(text, " "), sep: " "}
	}
	if strings.Contains(text, "_") {
		return splitResult{tokens: strings.Split(text, "_"), sep: "_"}
	}
	// CamelCase: use regexp to find boundaries
	indices := camelBoundary.FindAllStringIndex(text, -1)
	if len(indices) > 0 {
		var parts []string
		prev := 0
		for _, idx := range indices {
			// boundary is between idx[0]+1 and idx[0]+1
			cut := idx[0] + 1
			parts = append(parts, text[prev:cut])
			prev = cut
		}
		parts = append(parts, text[prev:])
		return splitResult{tokens: parts, sep: ""}
	}
	return splitResult{tokens: []string{text}, sep: ""}
}

