import (
	"regexp"
	"strings"
)

var (
	leadingTrailingSymbols = regexp.MustCompile(`(?m)^[^\w\s]+|[^\w\s]+$`)
	multiSpace            = regexp.MustCompile(`\s+`)
	dottedAcronym         = regexp.MustCompile(`^([A-Z0-9]\.){2,}[A-Z0-9]?\.?$`)
)

// NormalizeEntity returns the canonical display form of entity.
func NormalizeEntity(entity string, singFn func(string) (string, bool)) string {
	if len(entity) == 0 {
		return ""
	}
	entity = strings.TrimSpace(entity)
	entity = strings.TrimSpace(leadingTrailingSymbols.ReplaceAllString(entity, ""))

	// Collapse dotted acronyms: U.S.A. → USA
	rawToks := strings.Split(entity, " ")
	collapsed := make([]string, 0, len(rawToks))
	for _, tok := range rawToks {
		candidate := tok
		if !strings.HasSuffix(tok, ".") {
			candidate = tok + "."
		}
		if dottedAcronym.MatchString(candidate) {
			tok = strings.ReplaceAll(tok, ".", "")
		}
		collapsed = append(collapsed, tok)
	}
	entity = strings.Join(collapsed, " ")
	entity = strings.TrimSpace(multiSpace.ReplaceAllString(entity, " "))

	if len(entity) == 0 {
		return ""
	}

	sr := splitTokens(entity)
	var tokens []string
	for _, t := range sr.tokens {
		if len(t) > 0 {
			tokens = append(tokens, t)
		}
	}
	if len(tokens) == 0 {
		return ""
	}
	tokens[len(tokens)-1] = singularize(tokens[len(tokens)-1], singFn)
	return strings.Join(tokens, sr.sep)
}

