import (
	"strings"
	"unicode"
)

// EntityNormalizer is a stateful normalizer with a configurable exceptions list.
type EntityNormalizer struct {
	exceptions map[string]struct{}
	singFn     func(string) (string, bool)
}

// NewEntityNormalizer creates a new EntityNormalizer, merging SINGULAR_EXCEPTIONS
// with any extra exceptions provided. singFn may be nil to skip singularization.
func NewEntityNormalizer(extraExceptions map[string]struct{}, singFn func(string) (string, bool)) (*EntityNormalizer, error) {
	exc := make(map[string]struct{})
	for k := range singularExceptions {
		exc[k] = struct{}{}
	}
	for k := range extraExceptions {
		exc[k] = struct{}{}
	}
	return &EntityNormalizer{exceptions: exc, singFn: singFn}, nil
}

// Normalize returns the canonical display form of entity, respecting the instance exception list.
func (n *EntityNormalizer) Normalize(entity string) string {
	if len(entity) == 0 {
		return ""
	}
	entity = strings.TrimSpace(entity)
	entity = strings.TrimSpace(leadingTrailingSymbols.ReplaceAllString(entity, ""))
	entity = strings.TrimSpace(multiSpace.ReplaceAllString(entity, " "))
	if len(entity) == 0 {
		return ""
	}
	sr := splitTokens(entity)
	var tokens []string
	for _, t := range sr.tokens {
		if len(t) > 0 {
			tokens = append(tokens, t)
		}
	}
	if len(tokens) == 0 {
		return ""
	}
	last := tokens[len(tokens)-1]
	_, inExc := n.exceptions[strings.ToLower(last)]
	if !isAcronym(last) && !inExc && n.singFn != nil {
		if result, ok := n.singFn(last); ok && len(result) > 0 {
			runes := []rune(last)
			if unicode.IsUpper(runes[0]) && !isAcronym(last) {
				resultRunes := []rune(strings.ToLower(result))
				if len(resultRunes) > 0 {
					resultRunes[0] = unicode.ToUpper(resultRunes[0])
				}
				tokens[len(tokens)-1] = string(resultRunes)
			} else {
				tokens[len(tokens)-1] = result
			}
		}
	}
	return strings.Join(tokens, sr.sep)
}

