// Match runs all enabled matchers and returns merged results.
// Priority: schema vocab = data vocab > spaCy.
// Returns nil slice if no matchers are enabled.
func (p *NerPipeline) Match(text string) []EntityMatch {
	var vocabHits []EntityMatch

	if p.dbEnrich {
		sm := p.getSchemaMatcher()
		vocabHits = append(vocabHits, sm.Match(text)...)
	}

	if p.builder.DataTermCount() > 0 {
		dm := p.getDataMatcher()
		vocabHits = append(vocabHits, dm.Match(text)...)
	}

	var spacyHits []EntityMatch
	if p.spacyEntities {
		spacyHits = p.getSpacyMatcher().Match(text)
	}

	if len(vocabHits) > 0 && len(spacyHits) > 0 {
		return MergeMatches(vocabHits, spacyHits, text)
	}
	if len(vocabHits) > 0 {
		return vocabHits
	}
	return spacyHits
}

