import "fmt"

// RunOnChunks runs NER on every chunk and indexes results into entityIndex.
// If chunkIDs is nil, IDs are derived from chunk.DocumentName and chunk.ChunkIndex.
// Returns a map of chunkID -> []EntityMatch for chunks with matches.
func (p *NerPipeline) RunOnChunks(chunks []DocumentChunk, entityIndex EntityIndex, chunkIDs []string) map[string][]EntityMatch {
	results := make(map[string][]EntityMatch)
	for i, chunk := range chunks {
		var cid string
		if chunkIDs != nil {
			cid = chunkIDs[i]
		} else {
			cid = fmt.Sprintf("%s:%d", chunk.DocumentName, chunk.ChunkIndex)
		}
		content := chunk.Content
		if content == "" {
			content = ""
		}
		matches := p.Match(content)
		if len(matches) > 0 {
			entityIndex.IndexChunk(cid, content, matches)
			results[cid] = matches
		}
	}
	return results
}

