// entityRecord holds entity metadata stored in the SchemaMatcher registry.
type entityRecord struct {
	canonical   string
	displayName string
	entityType  string
}

// lookupRecord maps a lowercase variant to its entity.
type lookupRecord struct {
	entityID    string
	displayName string
	entityType  string
}

// SchemaMatcher matches schema/API/business terms case-insensitively.
type SchemaMatcher struct {
	lookup   map[string]lookupRecord
	entities map[string]entityRecord
}

// SchemaMatcherOptions holds term lists for NewSchemaMatcher.
// Note: any nil slice is treated as empty (R12).
type SchemaMatcherOptions struct {
	SchemaTerms   []string
	APITerms      []string
	BusinessTerms []string
}

// NewSchemaMatcher constructs a SchemaMatcher from the provided term lists.
func NewSchemaMatcher(opts SchemaMatcherOptions) *SchemaMatcher {
	sm := &SchemaMatcher{
		lookup:   make(map[string]lookupRecord),
		entities: make(map[string]entityRecord),
	}
	type pair struct {
		terms []string
		etype string
	}
	groups := []pair{
		{terms: opts.SchemaTerms, etype: "schema"},
		{terms: opts.APITerms, etype: "api"},
		{terms: opts.BusinessTerms, etype: "term"},
	}
	for _, g := range groups {
		for _, term := range g.terms {
			canonical := NormalizeSchemaTerm(term, NormalizeSchemaTermOpts{ToSingular: true})
