func (sm *SchemaMatcher) Match(text string) []EntityMatch {
	check := strings.ToLower(text)
	found := make(map[string][]spanPair) // entityID -> spans

	for variant, rec := range sm.lookup {
		start := 0
		for {
			pos := strings.Index(check[start:], variant)
			if pos == -1 {
				break
			}
			pos += start
			beforeOK := pos == 0 || !unicode.IsLetter(rune(check[pos-1])) && !unicode.IsDigit(rune(check[pos-1]))
			afterPos := pos + len(variant)
			afterOK := afterPos >= len(check) || !unicode.IsLetter(rune(check[afterPos])) && !unicode.IsDigit(rune(check[afterPos]))
			if beforeOK && afterOK {
				found[rec.entityID] = append(found[rec.entityID], spanPair{start: pos, end: afterPos})
			}
			start = pos + 1
		}
	}

	var results []EntityMatch
	for eid, spans := range found {
		rec := sm.entities[eid]
		// Deduplicate spans
		spanSet := make(map[spanPair]struct{})
		for _, s := range spans {
			spanSet[s] = struct{}{}
		}
		var deduped []spanPair
		for s := range spanSet {
			deduped = append(deduped, s)
		}
		sort.Slice(deduped, func(i, j int) bool {
			return deduped[i].start < deduped[j].start
		})
		positions := make([]int, len(deduped))
		for i, s := range deduped {
			positions[i] = s.start
		}
		results = append(results, EntityMatch{
			EntityID:    eid,
			Name:        rec.canonical,
			DisplayName: rec.displayName,
			EntityType:  rec.entityType,
			Frequency:   len(deduped),
			Positions:   positions,
			Spans:       deduped,
		})
	}
	return results
}

