// matchFoundEntry tracks accumulated spans for a matched entity.
type matchFoundEntry struct {
	spans       [][2]int
	displayName string
	entityType  string
}

// Match finds all vocabulary entities in text, returning one EntityMatch per unique entity.
func (vm *VocabularyMatcher) Match(text string) []EntityMatch {
	checkText := text
	if vm.matchMode != "exact" {
		checkText = strings.ToLower(text)
	}

	found := make(map[string]*matchFoundEntry)

	for surface, entry := range vm.lookup {
		start := 0
		for {
			pos := strings.Index(checkText[start:], surface)
			if pos == -1 {
				break
			}
			pos += start // absolute position

			// Require word boundaries
			beforeOK := pos == 0 || !isAlphanumeric(rune(checkText[pos-1]))
			afterPos := pos + len(surface)
			afterOK := afterPos >= len(checkText) || !isAlphanumeric(rune(checkText[afterPos]))

			if beforeOK && afterOK {
				if _, exists := found[entry.EntityID]; !exists {
					found[entry.EntityID] = &matchFoundEntry{
						displayName: entry.DisplayName,
						entityType:  entry.EntityType,
					}
				}
				found[entry.EntityID].spans = append(found[entry.EntityID].spans, [2]int{pos, pos + len(surface)})
			}
			start = pos + 1
		}
	}

	var results []EntityMatch
	for eid, info := range found {
		meta := vm.entities[eid]
		spans := sortedSpans(info.spans)
		positions := make([]int, len(spans))
		for i, s := range spans {
			positions[i] = s[0]
		}
		results = append(results, EntityMatch{
			EntityID:    eid,
			Name:        meta.Name,
			DisplayName: info.displayName,
			EntityType:  info.entityType,
			Frequency:   len(spans),
			Positions:   positions,
			Spans:       spans,
		})
	}
	return results
}

