import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
)

// rawEntityJSON is the shape of a JSON entity object on disk.
type rawEntityJSON struct {
	ID          string   `json:"id"`
	Name        string   `json:"name"`
	DisplayName string   `json:"display_name"`
	Type        string   `json:"type"`
	EntityType  string   `json:"entity_type"`
	Aliases     []string `json:"aliases"`
}

// VocabularyMatcherFromFile loads a VocabularyMatcher from a JSON or plain-text file.
func VocabularyMatcherFromFile(path string, matchMode string, minEntityLength int) (*VocabularyMatcher, error) {
	if matchMode == "" {
		matchMode = "case_insensitive" // Note: mirrors Python default
	}
	if minEntityLength == 0 {
		minEntityLength = 2 // Note: mirrors Python default
	}
	bytes, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("VocabularyMatcherFromFile: read failed: %w", err)
	}
	text := string(bytes)

	var entities []EntityRecord

	if strings.ToLower(filepath.Ext(path)) == ".json" {
		var raw []rawEntityJSON
		if err := json.Unmarshal([]byte(text), &raw); err != nil {
			return nil, fmt.Errorf("VocabularyMatcherFromFile: JSON parse failed: %w", err)
		}
		for _, item := range raw {
			name := item.Name
			if name == "" {
				name = item.DisplayName
			}
			displayName := item.DisplayName
			if displayName == "" {
				displayName = item.Name
			}
			id := item.ID
			if id == "" {
				id = autoID(name)
			}
			dtype := item.Type
			if dtype == "" {
				dtype = item.EntityType
			}
			if dtype == "" {
				dtype = "concept"
			}
			aliases := item.Aliases
			if aliases == nil {
				aliases = []string{}
			}
			entities = append(entities, EntityRecord{
				ID:          id,
				Name:        strings.ToLower(name),
				DisplayName: displayName,
				Type:        dtype,
				Aliases:     aliases,
			})
		}
	} else {
		// Plain text: one display name per line
		for _, line := range strings.Split(text, "\n") {
			line = strings.TrimSpace(line)
			if len(line) == 0 || strings.HasPrefix(line, "#") {
				continue
			}
			entities = append(entities, EntityRecord{
				ID:          autoID(line),
				Name:        strings.ToLower(line),
				DisplayName: line,
				Type:        "concept",
				Aliases:     []string{},
			})
		}
	}
	return NewVocabularyMatcher(entities, matchMode, minEntityLength), nil
}

