// selectNamespaces calls llmFn to select relevant namespaces for query.
// Returns nil if fewer than two namespaces have descriptions or on any parse error.
func (s *EnhancedSearch) selectNamespaces(query string, llmFn func(string) (string, error)) ([]string, error) {
	rows, err := s.store.Vector.Conn.Query(
		"SELECT namespace_id, description FROM all_namespaces " +
			"WHERE description IS NOT NULL AND description != '' " +
			"ORDER BY namespace_id",
	)
	if err != nil {
		return nil, fmt.Errorf("selectNamespaces query: %w", err)
	}
	defer rows.Close()

	type nsRow struct {
		nsID string
		desc string
	}
	var nsRows []nsRow
	for rows.Next() {
		var r nsRow
		if err := rows.Scan(&r.nsID, &r.desc); err != nil {
			return nil, fmt.Errorf("selectNamespaces scan: %w", err)
		}
		nsRows = append(nsRows, r)
	}
	if len(nsRows) < 2 {
		return nil, nil
	}

	var linesBuf strings.Builder
	for i, r := range nsRows {
		if i > 0 {
			linesBuf.WriteByte('\n')
		}
		linesBuf.WriteString(fmt.Sprintf("- %s: %s", r.nsID, r.desc))
	}
	prompt := strings.NewReplacer(
		"{namespace_list}", linesBuf.String(),
		"{query}", query,
	).Replace(s.namespaceFilterPrompt)

	raw, err := llmFn(prompt)
	if err != nil {
		return nil, nil // LLM error — degrade gracefully
	}

	re := regexp.MustCompile(`(?s)\[.*?\]`)
	m := re.FindString(raw)
	if m == "" {
		return nil, nil
	}
	var selected []string
	if jsonErr := json.Unmarshal([]byte(m), &selected); jsonErr != nil {
		return nil, nil // unparseable JSON — no namespace filtering
	}

	known := make(map[string]struct{}, len(nsRows))
	for _, r := range nsRows {
		known[r.nsID] = struct{}{}
	}
	var result []string
	for _, ns := range selected {
		if _, ok := known[ns]; ok {
			result = append(result, ns)
		}
	}
	if len(result) == 0 {
		return nil, nil
	}
	return result, nil
}

// SelectDomainsOptions holds optional parameters for selectDomains.
type SelectDomainsOptions struct {
	Namespaces []string // Note: nil means no namespace filter
}

// selectDomains calls llmFn to select relevant domain IDs for query.
func (s *EnhancedSearch) selectDomains(query string, llmFn func(string) (string, error), opts SelectDomainsOptions) ([]string, error) {
	baseWhere := "WHERE d.description IS NOT NULL AND d.description != ''"
	var args []interface{}
	if len(opts.Namespaces) > 0 {
		placeholders := make([]string, len(opts.Namespaces))
		for i := range opts.Namespaces {
			placeholders[i] = "?"
			args = append(args, opts.Namespaces[i])
		}
		baseWhere += fmt.Sprintf(" AND d.namespace_id IN (%s)", strings.Join(placeholders, ", "))
	}
	query2 := fmt.Sprintf(
		"SELECT d.domain_id, d.namespace_id, d.name, d.description FROM domains d %s ORDER BY d.namespace_id, d.name",
		baseWhere,
	)
	rows, err := s.store.Vector.Conn.Query(query2, args...)
	if err != nil {
		return nil, fmt.Errorf("selectDomains query: %w", err)
	}
	defer rows.Close()

	type domainRow struct {
		domainID string
		ns       string
		name     string
		desc     string
	}
	var drows []domainRow
	for rows.Next() {
		var r domainRow
		if err := rows.Scan(&r.domainID, &r.ns, &r.name, &r.desc); err != nil {
			return nil, fmt.Errorf("selectDomains scan: %w", err)
		}
		drows = append(drows, r)
	}
	if len(drows) < 2 {
		return nil, nil
	}

	nameToID := make(map[string]string, len(drows))
	for _, r := range drows {
		nameToID[r.name] = r.domainID
	}
	var linesBuf strings.Builder
	for i, r := range drows {
		if i > 0 {
			linesBuf.WriteByte('\n')
		}
		linesBuf.WriteString(fmt.Sprintf("- %s (%s): %s", r.name, r.ns, r.desc))
	}
	prompt2 := strings.NewReplacer(
		"{domain_list}", linesBuf.String(),
		"{query}", query,
	).Replace(s.domainFilterPrompt)

	raw, err := llmFn(prompt2)
	if err != nil {
		return nil, nil
	}
	re := regexp.MustCompile(`(?s)\[.*?\]`)
	m := re.FindString(raw)
	if m == "" {
		return nil, nil
	}
	var selectedNames []string
	if jsonErr := json.Unmarshal([]byte(m), &selectedNames); jsonErr != nil {
		return nil, nil
	}
	var ids []string
	for _, n := range selectedNames {
		if id, ok := nameToID[n]; ok {
			ids = append(ids, id)
		}
	}
	if len(ids) == 0 {
		return nil, nil
	}
	return ids, nil
}

