// resolveNsChunkIDs builds the allowlist of chunk IDs from namespace and domain filters.
// Returns nil when no filters are active.
func (s *EnhancedSearch) resolveNsChunkIDs(namespaces []string, domainIDs []string) (map[string]struct{}, error) {
	var nsChunkIDs map[string]struct{}

	if len(namespaces) > 0 {
		placeholders := make([]string, len(namespaces))
		args := make([]interface{}, len(namespaces))
		for i, ns := range namespaces {
			placeholders[i] = "?"
			args[i] = ns
		}
		q := fmt.Sprintf("SELECT chunk_id FROM embeddings WHERE namespace IN (%s)", strings.Join(placeholders, ", "))
		rows, err := s.store.Vector.Conn.Query(q, args...)
		if err != nil {
			return nil, fmt.Errorf("resolveNsChunkIDs namespace query: %w", err)
		}
		defer rows.Close()
		nsChunkIDs = make(map[string]struct{})
		for rows.Next() {
			var cid string
			if err := rows.Scan(&cid); err != nil {
				return nil, fmt.Errorf("resolveNsChunkIDs namespace scan: %w", err)
			}
			nsChunkIDs[cid] = struct{}{}
		}
	}

	if len(domainIDs) > 0 {
		placeholders := make([]string, len(domainIDs))
		args := make([]interface{}, len(domainIDs))
		for i, did := range domainIDs {
			placeholders[i] = "?"
			args[i] = did
		}
		q := fmt.Sprintf("SELECT chunk_id FROM embeddings WHERE domain_id IN (%s)", strings.Join(placeholders, ", "))
		rows, err := s.store.Vector.Conn.Query(q, args...)
		if err != nil {
			return nil, fmt.Errorf("resolveNsChunkIDs domain query: %w", err)
		}
		defer rows.Close()
		diChunkIDs := make(map[string]struct{})
		for rows.Next() {
			var cid string
			if err := rows.Scan(&cid); err != nil {
				return nil, fmt.Errorf("resolveNsChunkIDs domain scan: %w", err)
			}
			diChunkIDs[cid] = struct{}{}
		}
		if nsChunkIDs == nil {
			nsChunkIDs = diChunkIDs
		} else {
			// intersection
			for cid := range nsChunkIDs {
				if _, ok := diChunkIDs[cid]; !ok {
					delete(nsChunkIDs, cid)
				}
			}
		}
	}
	return nsChunkIDs, nil
}

// buildSeedPool performs Step 1 vector similarity seeding.
// Returns (pool, seedChunkIDs).
func (s *EnhancedSearch) buildSeedPool(
	queryEmbedding []float32,
	k int,
	queryText *string,
	namespaces []string,
	domainIDs []string,
	seedLimit int,
) (map[string]*ScoredChunk, []string, error) {
	rawSeeds, err := s.store.Search(queryEmbedding, SearchOptions{
		Limit:      seedLimit,
		QueryText:  queryText,
		Namespaces: namespaces,
		DomainIDs:  domainIDs,
	})
	if err != nil {
		return nil, nil, fmt.Errorf("buildSeedPool store.Search: %w", err)
	}

	pool := make(map[string]*ScoredChunk)
	var seedChunkIDs []string
	for _, seed := range rawSeeds {
		if _, exists := pool[seed.ChunkID]; !exists {
			pool[seed.ChunkID] = &ScoredChunk{
				ChunkID:    seed.ChunkID,
				Chunk:      seed.Chunk,
				Score:      seed.Score,
				Provenance: "seed",
				Embedding:  nil,
			}
		}
		seedChunkIDs = append(seedChunkIDs, seed.ChunkID)
	}
	return pool, seedChunkIDs, nil
}

