// expandEntity performs Step 3: entity-adjacent expansion.
// Returns (expandedEntityIDs, addedChunkIDs).
func (s *EnhancedSearch) expandEntity(
	pool map[string]*ScoredChunk,
	nsChunkIDs map[string]struct{},
	queryEmbedding []float32,
) (map[string]struct{}, []string, error) {
	expandedEntityIDs := make(map[string]struct{})
	var added []string
	if !s.entity || s.entityIndex == nil {
		return expandedEntityIDs, added, nil
	}

	var queryVecFlat []float32
	if s.laneEntityMinSim != nil {
		queryVecFlat = queryEmbedding // already flat []float32
	}

	// snapshot pool keys to avoid mutating map during iteration
	poolKeys := make([]string, 0, len(pool))
	for cid := range pool {
		poolKeys = append(poolKeys, cid)
	}

	for _, cid := range poolKeys {
		entities, err := s.entityIndex.GetEntitiesForChunk(cid)
		if err != nil {
			return nil, nil, fmt.Errorf("expandEntity GetEntitiesForChunk: %w", err)
		}
		for _, ep := range entities {
			entityID := ep.EntityID
			expandedEntityIDs[entityID] = struct{}{}
			linked, err := s.entityIndex.GetChunksForEntity(entityID, s.entityTopN)
			if err != nil {
				return nil, nil, fmt.Errorf("expandEntity GetChunksForEntity: %w", err)
			}
			for _, lp := range linked {
				linkedChunkID := lp.ChunkID
				if nsChunkIDs != nil {
					if _, ok := nsChunkIDs[linkedChunkID]; !ok {
						continue
					}
				}
				if _, exists := pool[linkedChunkID]; !exists {
					if queryVecFlat != nil {
						emb, err := s.getEmbedding(linkedChunkID)
						if err != nil {
							return nil, nil, fmt.Errorf("expandEntity getEmbedding: %w", err)
						}
						if emb != nil && s.cosine(queryVecFlat, emb) < *s.laneEntityMinSim {
							continue
						}
					}
					chunk, err := s.fetchChunk(linkedChunkID)
					if err != nil {
						return nil, nil, fmt.Errorf("expandEntity fetchChunk: %w", err)
					}
					if chunk != nil {
						pool[linkedChunkID] = &ScoredChunk{
							ChunkID:    linkedChunkID,
							Chunk:      chunk,
							Score:      0.0,
							Provenance: "entity_adjacent",
							LinkedBy:   entityID,
						}
						added = append(added, linkedChunkID)
					}
				}
			}
		}
	}
	return expandedEntityIDs, added, nil
}

