def _expand_cluster(
    self,
    pool: dict[str, ScoredChunk],
    expanded_entity_ids: set[str],
    ns_chunk_ids: set[str] | None,
    cluster_budget: int,
) -> list[str]:
    added: list[str] = []
    if not self._cluster or self._cluster_map is None or cluster_budget <= 0:
        return added
    cluster_count = 0
    for entity_id in expanded_entity_ids:
        if cluster_count >= cluster_budget:
            break
        for neighbor_entity_id in self._cluster_map.get_neighbors(entity_id):
            if cluster_count >= cluster_budget:
                break
            cluster_chunks = self._entity_index.get_chunks_for_entity(
                neighbor_entity_id, top_n=1
            ) if self._entity_index else []
            for linked_chunk_id, _ in cluster_chunks:
                if ns_chunk_ids is not None and linked_chunk_id not in ns_chunk_ids:
                    continue
                if linked_chunk_id not in pool:
                    chunk = self._fetch_chunk(linked_chunk_id)
                    if chunk is not None:
                        cluster_id = self._cluster_map.get_cluster(neighbor_entity_id)
                        pool[linked_chunk_id] = ScoredChunk(
                            chunk_id=linked_chunk_id,
                            chunk=chunk,
                            score=0.0,
                            provenance="cluster_adjacent",
                            linked_by=neighbor_entity_id,
                            cluster=cluster_id,
                        )
                        cluster_count += 1
                        added.append(linked_chunk_id)
    return added

output:
// expandCluster performs Step 4: budget-limited cluster-adjacent expansion.
// Returns added chunk IDs.
func (s *EnhancedSearch) expandCluster(
	pool map[string]*ScoredChunk,
	expandedEntityIDs map[string]struct{},
	nsChunkIDs map[string]struct{},
	clusterBudget int,
) ([]string, error) {
	var added []string
	if !s.cluster || s.clusterMap == nil || clusterBudget <= 0 {
		return added, nil
	}
	clusterCount := 0
	for entityID := range expandedEntityIDs {
		if clusterCount >= clusterBudget {
			break
		}
		neighbors, err := s.clusterMap.GetNeighbors(entityID)
		if err != nil {
			return nil, fmt.Errorf("expandCluster GetNeighbors: %w", err)
		}
		for _, neighborEntityID := range neighbors {
			if clusterCount >= clusterBudget {
				break
			}
			var clusterChunks []ChunkPair
			if s.entityIndex != nil {
				clusterChunks, err = s.entityIndex.GetChunksForEntity(neighborEntityID, 1)
				if err != nil {
					return nil, fmt.Errorf("expandCluster GetChunksForEntity: %w", err)
				}
			}
			for _, cp := range clusterChunks {
				linkedChunkID := cp.ChunkID
				if nsChunkIDs != nil {
					if _, ok := nsChunkIDs[linkedChunkID]; !ok {
						continue
					}
				}
				if _, exists := pool[linkedChunkID]; !exists {
					chunk, err := s.fetchChunk(linkedChunkID)
					if err != nil {
						return nil, fmt.Errorf("expandCluster fetchChunk: %w", err)
					}
					if chunk != nil {
						clusterID, err := s.clusterMap.GetCluster(neighborEntityID)
						if err != nil {
							return nil, fmt.Errorf("expandCluster GetCluster: %w", err)
						}
						pool[linkedChunkID] = &ScoredChunk{
							ChunkID:    linkedChunkID,
							Chunk:      chunk,
							Score:      0.0,
							Provenance: "cluster_adjacent",
							LinkedBy:   neighborEntityID,
							Cluster:    clusterID,
						}
						clusterCount++
						added = append(added, linkedChunkID)
					}
				}
			}
		}
	}
	return added, nil
}

