// resolveQueryEmbedding returns a valid embedding, auto-generating from text when embedding is nil.
func (s *EnhancedSearch) resolveQueryEmbedding(queryEmbedding []float32, queryText *string) ([]float32, error) {
	if queryEmbedding != nil {
		return queryEmbedding, nil
	}
	if queryText == nil {
		return nil, fmt.Errorf("resolveQueryEmbedding: either queryEmbedding or queryText must be supplied")
	}
	if s.embedFn == nil {
		return nil, fmt.Errorf("resolveQueryEmbedding: queryEmbedding is nil and no embedFn was set on EnhancedSearch; pass embedFn to the constructor or supply queryEmbedding directly")
	}
	vecs, err := s.embedFn([]string{*queryText})
	if err != nil {
		return nil, fmt.Errorf("resolveQueryEmbedding embedFn: %w", err)
	}
	if len(vecs) == 0 {
		return nil, fmt.Errorf("resolveQueryEmbedding: embedFn returned empty result")
	}
	return vecs[0], nil
}

