def _graph_traverse_hops(self, ents: list[str]) -> tuple[set[str], int]:
    assert self._relationship_index is not None
    ents_set = set(ents)
    hop1: set[str] = set()
    svo_count = 0
    for entity_id in ents:
        for triple in self._relationship_index.get_objects(entity_id):
            hop1.add(triple.object_id)
            svo_count += 1
        for triple in self._relationship_index.get_subjects(entity_id):
            hop1.add(triple.subject_id)
            svo_count += 1
    hop1 -= ents_set

    hop2: set[str] = set()
    for entity_id in hop1:
        for triple in self._relationship_index.get_objects(entity_id):
            hop2.add(triple.object_id)
        for triple in self._relationship_index.get_subjects(entity_id):
            hop2.add(triple.subject_id)
    hop2 -= ents_set | hop1

    return hop1 | hop2, svo_count

output:
// graphTraverseHops performs 2-hop RelationshipIndex traversal.
// Returns (relatedEntityIDs, svoCount). Caller must ensure relationshipIndex != nil.
func (s *EnhancedSearch) graphTraverseHops(ents []string) (map[string]struct{}, int, error) {
	if s.relationshipIndex == nil {
		return nil, 0, fmt.Errorf("graphTraverseHops: relationshipIndex is nil")
	}
	entsSet := make(map[string]struct{}, len(ents))
	for _, e := range ents {
		entsSet[e] = struct{}{}
	}

	hop1 := make(map[string]struct{})
	svoCount := 0
	for _, entityID := range ents {
		objects, err := s.relationshipIndex.GetObjects(entityID)
		if err != nil {
			return nil, 0, fmt.Errorf("graphTraverseHops GetObjects: %w", err)
		}
		for _, triple := range objects {
			hop1[triple.ObjectID] = struct{}{}
			svoCount++
		}
		subjects, err := s.relationshipIndex.GetSubjects(entityID)
		if err != nil {
			return nil, 0, fmt.Errorf("graphTraverseHops GetSubjects: %w", err)
		}
		for _, triple := range subjects {
			hop1[triple.SubjectID] = struct{}{}
			svoCount++
		}
	}
	for e := range entsSet {
		delete(hop1, e)
	}

	hop2 := make(map[string]struct{})
	for entityID := range hop1 {
		objects, err := s.relationshipIndex.GetObjects(entityID)
		if err != nil {
			return nil, 0, fmt.Errorf("graphTraverseHops hop2 GetObjects: %w", err)
		}
		for _, triple := range objects {
			hop2[triple.ObjectID] = struct{}{}
		}
		subjects, err := s.relationshipIndex.GetSubjects(entityID)
		if err != nil {
			return nil, 0, fmt.Errorf("graphTraverseHops hop2 GetSubjects: %w", err)
		}
		for _, triple := range subjects {
			hop2[triple.SubjectID] = struct{}{}
		}
	}
	for e := range entsSet {
		delete(hop2, e)
	}
	for e := range hop1 {
		delete(hop2, e)
	}

	// union hop1 | hop2
	result := make(map[string]struct{}, len(hop1)+len(hop2))
	for e := range hop1 {
		result[e] = struct{}{}
	}
	for e := range hop2 {
		result[e] = struct{}{}
	}
	return result, svoCount, nil
}

// globalSearch performs vector search over community_summary chunks only.
func (s *EnhancedSearch) globalSearch(
	queryEmbedding []float32,
	k int,
	queryText *string,
	namespaces []string,
	domainIDs []string,
	trace *RetrievalTrace,
) ([]*ScoredChunk, error) {
	raw, err := s.store.Search(queryEmbedding, SearchOptions{
		Limit:              k,
		QueryText:          queryText,
		ChunkTypes:         []string{"community_summary"},
		Namespaces:         namespaces,
		DomainIDs:          domainIDs,
		SessionFingerprint: s.sessionFingerprint,
	})
	if err != nil {
		return nil, fmt.Errorf("globalSearch store.Search: %w", err)
	}
	results := make([]*ScoredChunk, 0, len(raw))
	for _, seed := range raw {
		results = append(results, &ScoredChunk{
			ChunkID:    seed.ChunkID,
			Chunk:      seed.Chunk,
			Score:      seed.Score,
			Provenance: "seed",
		})
	}
	if trace != nil {
		communityIDs := make([]string, len(results))
		for i, sc := range results {
			communityIDs[i] = sc.ChunkID
		}
		trace.CommunityChunkIDs = communityIDs
	}
	return results, nil
}

