// collectEntityIDs collects entity IDs from retrieved chunks and query entity resolver.
func (s *EnhancedSearch) collectEntityIDs(chunkIDs []string, queryText *string) (map[string]struct{}, error) {
	entityIDs := make(map[string]struct{})
	if s.entityIndex != nil {
		for _, cid := range chunkIDs {
			entities, err := s.entityIndex.GetEntitiesForChunk(cid)
			if err != nil {
				return nil, fmt.Errorf("collectEntityIDs GetEntitiesForChunk: %w", err)
			}
			for _, ep := range entities {
				entityIDs[ep.EntityID] = struct{}{}
			}
		}
	}
	if s.queryEntityIDFn != nil && queryText != nil && *queryText != "" {
		extras, err := s.queryEntityIDFn(*queryText)
		if err != nil {
			return nil, fmt.Errorf("collectEntityIDs queryEntityIDFn: %w", err)
		}
		for _, eid := range extras {
			entityIDs[eid] = struct{}{}
		}
	}
	return entityIDs, nil
}

// EntityRecord holds entity metadata for graph context assembly.
type EntityRecord struct {
	ID          string
	Name        string
	Type        string
	Description string
}

// fetchEntityRecords fetches (id, name, type, description) rows for the given entity IDs.
func (s *EnhancedSearch) fetchEntityRecords(entityIDs map[string]struct{}) ([]EntityRecord, error) {
	if len(entityIDs) == 0 {
		return nil, nil
	}
	eidList := make([]interface{}, 0, len(entityIDs))
	placeholders := make([]string, 0, len(entityIDs))
	for eid := range entityIDs {
		eidList = append(eidList, eid)
		placeholders = append(placeholders, "?")
	}
	q := fmt.Sprintf(
		"SELECT e.id, e.name, e.entity_type, COALESCE(e.description, '') FROM entities e WHERE e.id IN (%s)",
		strings.Join(placeholders, ", "),
	)
	rows, err := s.store.Vector.Conn.Query(q, eidList...)
	if err != nil {
		return nil, fmt.Errorf("fetchEntityRecords query: %w", err)
	}
	defer rows.Close()
	var records []EntityRecord
	for rows.Next() {
		var r EntityRecord
		if err := rows.Scan(&r.ID, &r.Name, &r.Type, &r.Description); err != nil {
			return nil, fmt.Errorf("fetchEntityRecords scan: %w", err)
		}
		records = append(records, r)
	}
	return records, nil
}

