def _collect_rel_rows(
    self,
    entity_ids: set[str],
    entity_records: list[dict],
) -> list[tuple[str, str, str, str]]:
    rel_rows: list[tuple[str, str, str, str]] = []
    if self._relationship_index is None or not entity_ids:
        return rel_rows
    id_to_name = {r["id"]: r["name"] for r in entity_records}
    seen: set[tuple[str, str, str]] = set()
    for eid in entity_ids:
        for t in self._relationship_index.get_objects(eid):
            key = (t.subject_id, t.verb, t.object_id)
            if key not in seen:
                seen.add(key)
                rel_rows.append((
                    id_to_name.get(t.subject_id, t.subject_id),
                    t.verb,
                    id_to_name.get(t.object_id, t.object_id),
                    t.description or "",
                ))
    return rel_rows

output:
// RelRow represents a subject-verb-object relationship row for context assembly.
type RelRow struct {
	Subject     string
	Verb        string
	Object      string
	Description string
}

// collectRelRows collects 1-hop SVO triples for matched entities.
func (s *EnhancedSearch) collectRelRows(entityIDs map[string]struct{}, entityRecords []EntityRecord) ([]RelRow, error) {
	var relRows []RelRow
	if s.relationshipIndex == nil || len(entityIDs) == 0 {
		return relRows, nil
	}
	idToName := make(map[string]string, len(entityRecords))
	for _, r := range entityRecords {
		idToName[r.ID] = r.Name
	}
	type tripleKey struct{ subj, verb, obj string }
	seen := make(map[tripleKey]struct{})
	for eid := range entityIDs {
		triples, err := s.relationshipIndex.GetObjects(eid)
		if err != nil {
			return nil, fmt.Errorf("collectRelRows GetObjects: %w", err)
		}
		for _, t := range triples {
			key := tripleKey{t.SubjectID, t.Verb, t.ObjectID}
			if _, ok := seen[key]; !ok {
				seen[key] = struct{}{}
				subjName := t.SubjectID
				if n, ok := idToName[t.SubjectID]; ok {
					subjName = n
				}
				objName := t.ObjectID
				if n, ok := idToName[t.ObjectID]; ok {
					objName = n
				}
				desc := t.Description
				relRows = append(relRows, RelRow{Subject: subjName, Verb: t.Verb, Object: objName, Description: desc})
			}
		}
	}
	return relRows, nil
}

