// collectCommunityTexts fetches community summary texts for communities containing chunkIDs.
func (s *EnhancedSearch) collectCommunityTexts(chunkIDs []string) ([]string, error) {
	if s.communityIndex == nil || len(chunkIDs) == 0 {
		return nil, nil
	}
	commIDs := make(map[int]struct{})
	for _, cid := range chunkIDs {
		c, ok := s.communityIndex.CommunityID(cid)
		if ok {
			commIDs[c] = struct{}{}
		}
	}
	if len(commIDs) == 0 {
		return nil, nil
	}
	names := make([]interface{}, 0, len(commIDs))
	placeholders := make([]string, 0, len(commIDs))
	for cid := range commIDs {
		names = append(names, fmt.Sprintf("community:%d", cid))
		placeholders = append(placeholders, "?")
	}
