// contextGraphExpandMissing expands missing entities via context graph edges into newPool (mutates in place).
// Caller must ensure entityIndex != nil.
func (s *EnhancedSearch) contextGraphExpandMissing(
	missing []string,
	newPool map[string]*ScoredChunk,
	foundEntities *[]string,
	namespaces []string,
) error {
	if s.entityIndex == nil {
		return fmt.Errorf("contextGraphExpandMissing: entityIndex is nil")
	}
	namespace := "global"
	if len(namespaces) > 0 {
		namespace = namespaces[0]
	}
	for _, entity := range missing {
		edges, err := s.store.GetContextGraph(entity, namespace, s.contextGraphMinWeight)
		if err != nil {
			return fmt.Errorf("contextGraphExpandMissing GetContextGraph: %w", err)
		}
		topK := s.contextGraphTopK
		if topK > len(edges) {
			topK = len(edges)
		}
		for _, edge := range edges[:topK] {
			linked, err := s.entityIndex.GetChunksForEntity(edge.TargetEntityID, s.entityTopN)
			if err != nil {
				return fmt.Errorf("contextGraphExpandMissing GetChunksForEntity: %w", err)
			}
			for _, lp := range linked {
				linkedChunkID := lp.ChunkID
				if _, exists := newPool[linkedChunkID]; !exists {
					chunk, err := s.fetchChunk(linkedChunkID)
					if err != nil {
						return fmt.Errorf("contextGraphExpandMissing fetchChunk: %w", err)
					}
					if chunk != nil {
						newPool[linkedChunkID] = &ScoredChunk{
							ChunkID:    linkedChunkID,
							Chunk:      chunk,
							Score:      edge.Weight,
							Provenance: "context_graph_expansion",
							LinkedBy:   edge.TargetEntityID,
						}
					}
				}
			}
		}
		found := false
		for _, fe := range *foundEntities {
			if fe == entity {
				found = true
				break
			}
		}
		if !found {
			*foundEntities = append(*foundEntities, entity)
		}
	}
	return nil
}

