// semanticExpandMissing performs per-entity vector search for missing entities.
// Returns (possibly filtered) missing list.
// Note: minSim is *float64; nil means no similarity gate.
func (s *EnhancedSearch) semanticExpandMissing(
	missing []string,
	newPool map[string]*ScoredChunk,
	foundEntities *[]string,
	precomputedEntityVecs map[string][]float32,
	namespaces []string,
	domainIDs []string,
) ([]string, error) {
	var perK int
	if s.entityRefExpansionPerK != nil {
		perK = *s.entityRefExpansionPerK
	} else {
		denom := len(missing)
		if denom < 1 {
			denom = 1
		}
		perK = s.entityRefExpansionK / denom
		if perK < 3 {
			perK = 3
		}
	}
	minSim := s.entityRefExpansionMinSim // *float64, nil means no gate

	var entityVecs [][]float32
	if precomputedEntityVecs != nil {
		var available []string
		for _, e := range missing {
			if _, ok := precomputedEntityVecs[e]; ok {
				available = append(available, e)
				entityVecs = append(entityVecs, precomputedEntityVecs[e])
			}
		}
		missing = available
	} else {
		if s.embedFn == nil {
			return missing, fmt.Errorf("semanticExpandMissing: embedFn is nil")
		}
		var err error
		entityVecs, err = s.embedFn(missing)
		if err != nil {
			return missing, fmt.Errorf("semanticExpandMissing embedFn: %w", err)
		}
	}

	if len(entityVecs) == 0 || len(missing) == 0 {
		return missing, nil
	}
	for i, entity := range missing {
		hits, err := s.store.Search(entityVecs[i], SearchOptions{
			Limit:      perK,
			Namespaces: namespaces,
			DomainIDs:  domainIDs,
		})
		if err != nil {
			return missing, fmt.Errorf("semanticExpandMissing store.Search: %w", err)
		}
		for _, h := range hits {
			if minSim != nil && h.Score < *minSim {
				continue
			}
			if _, exists := newPool[h.ChunkID]; !exists {
				newPool[h.ChunkID] = &ScoredChunk{
					ChunkID:    h.ChunkID,
					Chunk:      h.Chunk,
					Score:      h.Score,
					Provenance: "entity_ref_expansion",
				}
			}
			found := false
			for _, fe := range *foundEntities {
				if fe == entity {
					found = true
					break
				}
			}
			if !found {
				*foundEntities = append(*foundEntities, entity)
			}
		}
	}
	return missing, nil
}

