// literalExpandMissing performs literal substring fallback expansion.
// Expands pool with chunks containing missing entity text.
func (s *EnhancedSearch) literalExpandMissing(
	missing []string,
	newPool map[string]*ScoredChunk,
	foundEntities *[]string,
	queryEmbedding []float32,
	queryText *string,
	namespaces []string,
	domainIDs []string,
) error {
	expandedSeeds, err := s.store.Search(queryEmbedding, SearchOptions{
		Limit:      s.entityRefExpansionK,
		QueryText:  queryText,
		Namespaces: namespaces,
		DomainIDs:  domainIDs,
	})
	if err != nil {
		return fmt.Errorf("literalExpandMissing store.Search: %w", err)
	}
	for _, h := range expandedSeeds {
		if _, exists := newPool[h.ChunkID]; exists {
			continue
		}
		chunkText := strings.ToLower(h.Chunk.Content)
		var matched []string
		for _, e := range missing {
			if strings.Contains(chunkText, strings.ToLower(e)) {
				matched = append(matched, e)
			}
		}
		if len(matched) > 0 {
			newPool[h.ChunkID] = &ScoredChunk{
				ChunkID:    h.ChunkID,
				Chunk:      h.Chunk,
				Score:      h.Score,
				Provenance: "entity_ref_expansion",
			}
			for _, e := range matched {
				found := false
				for _, fe := range *foundEntities {
					if fe == e {
						found = true
						break
					}
				}
				if !found {
					*foundEntities = append(*foundEntities, e)
				}
			}
		}
	}
	return nil
}

