// ChunkNeighbor pairs a chunk ID with its DocumentChunk.
type ChunkNeighbor struct {
	ChunkID string
	Chunk   *DocumentChunk
}

// structuralNeighbors pulls prev/next chunks by index adjacency from the vector store.
func (s *ScoringMixin) structuralNeighbors(seedChunkIDs []string) ([]ChunkNeighbor, error) {
	allChunks, err := s.store.Vector.GetAllChunks()
	if err != nil {
		return nil, fmt.Errorf("structuralNeighbors GetAllChunks: %w", err)
	}

	type docIdx struct {
		doc string
		idx int
	}
	lookup := make(map[docIdx]ChunkNeighbor, len(allChunks))
	idToChunk := make(map[string]*DocumentChunk, len(allChunks))
	for i := range allChunks {
		chunk := &allChunks[i]
		content := chunk.EmbeddingContent
		if content == "" {
			content = chunk.Content
		}
		cid := GenerateChunkID(chunk.DocumentName, chunk.ChunkIndex, content)
		lookup[docIdx{chunk.DocumentName, chunk.ChunkIndex}] = ChunkNeighbor{ChunkID: cid, Chunk: chunk}
		idToChunk[cid] = chunk
	}

	var results []ChunkNeighbor
	for _, seedID := range seedChunkIDs {
		seedChunk, ok := idToChunk[seedID]
		if !ok {
			continue
		}
		for _, neighborIdx := range []int{seedChunk.ChunkIndex - 1, seedChunk.ChunkIndex + 1} {
			key := docIdx{seedChunk.DocumentName, neighborIdx}
			if nb, ok := lookup[key]; ok {
				results = append(results, nb)
			}
		}
	}
	return results, nil
}

