// PreloadChunkCache preloads all chunk metadata and embeddings into memory.
func (s *ScoringMixin) PreloadChunkCache() error {
	rows, err := s.store.Vector.Conn.Query(
		"SELECT chunk_id, document_name, content, section, chunk_index, " +
			"source_offset, source_length, embedding FROM embeddings",
	)
	if err != nil {
		log.Printf("preload_chunk_cache failed: %v", err)
		return nil // degrade gracefully — cache remains nil
	}
	defer rows.Close()

	s.chunkCache = make(map[string]*DocumentChunk)
	s.embeddingCache = make(map[string][]float32)

	for rows.Next() {
		var (
			cid, doc, content, section string
			idx, off, length           int
			emb                        []float32
		)
		if err := rows.Scan(&cid, &doc, &content, &section, &idx, &off, &length, &emb); err != nil {
			return fmt.Errorf("PreloadChunkCache scan: %w", err)
		}
		s.chunkCache[cid] = &DocumentChunk{
			DocumentName: doc,
			Content:      content,
			Section:      section,
			ChunkIndex:   idx,
			SourceOffset: off,
			SourceLength: length,
		}
		if len(emb) > 0 {
			s.embeddingCache[cid] = emb
		}
	}
	return nil
}

