// selectCohort performs greedy sequential MMR selection.
// composite = rw*relevance + pw*priority + cw*coverage
func (s *ScoringMixin) selectCohort(candidates []*ScoredChunk, queryEmbedding []float32, k int) ([]*ScoredChunk, error) {
	if len(candidates) == 0 {
		return nil, nil
	}
	q := normalizeVec(queryEmbedding)
	dim := len(q)

	type entry struct {
		sc        *ScoredChunk
		unit      []float32 // nil if embedding unavailable
		relevance float32
	}
	entries := make([]entry, 0, len(candidates))
	for _, sc := range candidates {
		raw, err := s.getEmbedding(sc.ChunkID)
		if err != nil {
			return nil, fmt.Errorf("selectCohort getEmbedding: %w", err)
		}
		sc.Embedding = raw
		var unit []float32
		var rel float32
		if len(raw) == dim {
			unit = normalizeVec(raw)
			rel = dot(q, unit)
		}
		entries = append(entries, entry{sc, unit, rel})
	}

	remaining := make([]int, len(entries))
	for i := range remaining {
		remaining[i] = i
	}

	var selUnits [][]float32
	var result []*ScoredChunk
	limit := k
	if limit > len(remaining) {
		limit = len(remaining)
	}
	for iter := 0; iter < limit; iter++ {
		bestScore := float32(-1e38)
		bestJ := 0
		for j, i := range remaining {
			e := entries[i]
			pri := float32(s.priority[e.sc.Provenance])
			if pri == 0 {
				pri = 0.5
			}
			var coverage float32
			if len(selUnits) > 0 {
				var maxSim float32
				if e.unit != nil {
					for _, su := range selUnits {
						if v := dot(su, e.unit); v > maxSim {
							maxSim = v
						}
					}
				}
				coverage = e.relevance - float32(s.lambda)*maxSim
			} else {
				coverage = e.relevance
			}
			composite := float32(s.rw)*e.relevance + float32(s.pw)*pri + float32(s.cw)*coverage
			if composite > bestScore {
				bestScore = composite
				bestJ = j
			}
		}
		chosenI := remaining[bestJ]
		remaining = append(remaining[:bestJ], remaining[bestJ+1:]...)
		sc := entries[chosenI].sc
		sc.Score = float64(bestScore)
		sc.Embedding = nil
		if entries[chosenI].unit != nil {
			selUnits = append(selUnits, entries[chosenI].unit)
		} else {
			selUnits = append(selUnits, make([]float32, dim))
		}
		result = append(result, sc)
	}
	return result, nil
}

