func tryKillOrphanLockHolder(errorMsg string) {
	re := regexp.MustCompile(`\(PID (\d+)\)`)
	matches := re.FindStringSubmatch(errorMsg)
	if len(matches) < 2 {
		return
	}
	pid, err := strconv.Atoi(matches[1])
	if err != nil {
		return
	}
	if pid == os.Getpid() {
		return
	}
	proc, err := os.FindProcess(pid)
	if err != nil {
		return
	}
	if err := proc.Signal(syscall.Signal(0)); err != nil {
		return
	}
	var cmdline string
	cmdlineBytes, err := os.ReadFile(fmt.Sprintf("/proc/%d/cmdline", pid))
	if err != nil {
		out, runErr := exec.Command("ps", "-p", strconv.Itoa(pid), "-o", "command=").Output()
		if runErr != nil {
			return
		}
		cmdline = strings.TrimSpace(string(out))
	} else {
		cmdline = string(cmdlineBytes)
	}
	if strings.Contains(cmdline, "multiprocessing") || strings.Contains(cmdline, "resource_tracker") {
		log.Printf("Killing orphaned multiprocessing child PID %d", pid)
		if err := proc.Signal(syscall.SIGKILL); err == nil {
			time.Sleep(500 * time.Millisecond)
		}
	}
}

