func (p *PendingResult) release() {
	if !p.released {
		p.released = true
		p.mu.Unlock()
	}
}

func (p *PendingResult) FetchAll() ([][]interface{}, error) {
	defer p.release()
	return p.conn.FetchAll()
}

func (p *PendingResult) FetchOne() ([]interface{}, error) {
	defer p.release()
	return p.conn.FetchOne()
}

