type LockedConnection struct {
	conn DBConn
	mu   sync.Locker
}

func NewLockedConnection(conn DBConn, mu sync.Locker) *LockedConnection {
	return &LockedConnection{conn: conn, mu: mu}
}

func (lc *LockedConnection) Execute(sql string, params ...interface{}) (*PendingResult, error) {
	lc.mu.Lock()
	if err := lc.conn.Execute(sql, params...); err != nil {
		lc.mu.Unlock()
		return nil, fmt.Errorf("execute: %w", err)
	}
	return NewPendingResult(lc.conn, lc.mu), nil
}

func (lc *LockedConnection) ExecuteMany(sql string, rows [][]interface{}) error {
	lc.mu.Lock()
	defer lc.mu.Unlock()
	if err := lc.conn.ExecuteMany(sql, rows); err != nil {
		return fmt.Errorf("executemany: %w", err)
	}
	return nil
}

