func (d *DuckDBVectorBackend) rebuildFTSIndex() error {
	if !d.ftsDirty {
		return nil
	}
	row, err := d.conn.QueryRow("SELECT COUNT(*) FROM embeddings")
	if err != nil {
		return fmt.Errorf("fts count: %w", err)
	}
	var count int
	if err := row.Scan(&count); err != nil {
		return fmt.Errorf("fts count scan: %w", err)
	}
	if count == 0 {
		d.ftsDirty = false
		return nil
	}
	const pragma = "PRAGMA create_fts_index('embeddings', 'chunk_id', 'content', " +
		"stemmer='none', stopwords='none', ignore='[^a-zA-Z0-9]', lower=1, overwrite=1)"
	if err := d.conn.Execute(pragma); err != nil {
		log.Printf("FTS index rebuild failed: %v", err)
		_ = d.conn.Execute("ROLLBACK")
		return fmt.Errorf("fts rebuild: %w", err)
	}
	d.ftsDirty = false
	return nil
}

