func (s *Store) InvalidateCommunityCache(domainID string) (int, error) {
	rows, err := s.vector.Conn().Query("SELECT fingerprint, domain_ids FROM community_cache")
	if err != nil {
		return 0, fmt.Errorf("query community_cache: %w", err)
	}
	defer rows.Close()
	var toDelete []string
	for rows.Next() {
		var fingerprint, domainIDsJSON string
		if err := rows.Scan(&fingerprint, &domainIDsJSON); err != nil {
			return 0, fmt.Errorf("scan community_cache row: %w", err)
		}
		var domainIDs []string
		if err := json.Unmarshal([]byte(domainIDsJSON), &domainIDs); err != nil {
			continue
		}
		for _, did := range domainIDs {
			if did == domainID {
				toDelete = append(toDelete, fingerprint)
				break
			}
		}
	}
	if err := rows.Err(); err != nil {
		return 0, fmt.Errorf("iterate community_cache: %w", err)
	}
	if len(toDelete) == 0 {
		return 0, nil
	}
	placeholders := strings.Join(strings.Fields(strings.Repeat("? ", len(toDelete))), ", ")
	args := make([]interface{}, len(toDelete))
	for i, fp := range toDelete {
		args[i] = fp
	}
	if err := s.vector.Conn().Execute(fmt.Sprintf("DELETE FROM embeddings WHERE session_fingerprint IN (%s)", placeholders), args...); err != nil {
		return 0, fmt.Errorf("delete embeddings: %w", err)
	}
	if err := s.vector.Conn().Execute(fmt.Sprintf("DELETE FROM community_cache WHERE fingerprint IN (%s)", placeholders), args...); err != nil {
		return 0, fmt.Errorf("delete community_cache: %w", err)
	}
	s.vector.SetFTSDirty(true)
	return len(toDelete), nil
}

