func (s *Store) NamespaceCacheValid(namespaceID string) (bool, error) {
	conn := s.vector.Conn()
	nsRow, err := conn.QueryRow("SELECT 1 FROM namespaces WHERE namespace_id = ?", namespaceID)
	if err != nil {
		return false, fmt.Errorf("query namespace: %w", err)
	}
	var nsExists int
	if err := nsRow.Scan(&nsExists); err != nil {
		return false, nil
	}
	rows, err := conn.Query(`SELECT s.uri, s.last_crawled FROM sources s JOIN domains d ON s.domain_id = d.domain_id WHERE d.namespace_id = ?`, namespaceID)
	if err != nil {
		return false, fmt.Errorf("query sources: %w", err)
	}
	defer rows.Close()
	type sourceRow struct {
		uri         string
		lastCrawled *time.Time
	}
	var sources []sourceRow
	for rows.Next() {
		var sr sourceRow
		if err := rows.Scan(&sr.uri, &sr.lastCrawled); err != nil {
			return false, fmt.Errorf("scan source row: %w", err)
		}
		sources = append(sources, sr)
	}
	if err := rows.Err(); err != nil {
		return false, fmt.Errorf("iterate sources: %w", err)
	}
	if len(sources) == 0 {
		return false, nil
	}
	remotePrefixes := []string{"http://", "https://", "github://", "s3://", "ftp://", "sftp://"}
	for _, src := range sources {
		if src.lastCrawled == nil {
			return false, nil
		}
		isRemote := false
		for _, p := range remotePrefixes {
			if strings.HasPrefix(src.uri, p) {
				isRemote = true
				break
			}
		}
		if !isRemote {
			info, err := os.Stat(src.uri)
			if err != nil {
				return false, nil
			}
			if info.ModTime().After(*src.lastCrawled) {
				return false, nil
			}
		}
	}
	countRow, err := conn.QueryRow("SELECT COUNT(*) FROM embeddings WHERE namespace = ?", namespaceID)
	if err != nil {
		return false, fmt.Errorf("count embeddings: %w", err)
	}
	var chunkCount int
	if err := countRow.Scan(&chunkCount); err != nil {
		return false, fmt.Errorf("scan chunk count: %w", err)
	}
	return chunkCount > 0, nil
}

func (s *Store) AddEntityAliasesBatch(aliases map[string]string, source string, namespace string) (int, error) {
	written := 0
	for alias, entityID := range aliases {
		row, err := s.vector.Conn().QueryRow(
			"SELECT source FROM entity_aliases WHERE alias = ? AND namespace = ?",
			alias, namespace,
		)
		if err != nil {
			return written, fmt.Errorf("query alias %s: %w", alias, err)
		}
		var existingSource string
		scanErr := row.Scan(&existingSource)
		if scanErr == nil && source != "user" {
			continue
		}
		if err := s.AddEntityAlias(alias, entityID, source, namespace); err != nil {
			return written, fmt.Errorf("add entity alias %s: %w", alias, err)
		}
		written++
	}
	return written, nil
}

