var forwardHierarchyVerbs = []string{"classified_as", "extends", "instance_of", "member_of", "part_of", "type_of"}
var reverseHierarchyVerbs = []string{"composed_of", "contains"}

func (s *Store) GetEntityParents(entityNames []string, namespace string) (map[string][2]string, error) {
	if len(entityNames) == 0 {
		return map[string][2]string{}, nil
	}
	conn := s.vector.Conn()
	placeholders := strings.Join(strings.Fields(strings.Repeat("? ", len(entityNames))), ", ")
	fwdVerbs := "'" + strings.Join(forwardHierarchyVerbs, "', '") + "'"
	revVerbs := "'" + strings.Join(reverseHierarchyVerbs, "', '") + "'"
	query := fmt.Sprintf(
		"SELECT child_e.name, parent_e.name, st.verb "+
			"FROM svo_triples st "+
			"JOIN entities child_e ON st.subject_id = child_e.id "+
			"JOIN entities parent_e ON st.object_id = parent_e.id "+
			"WHERE child_e.name IN (%s) AND st.verb IN (%s) AND (st.namespace = ? OR st.namespace IS NULL) "+
			"UNION ALL "+
			"SELECT child_e.name, parent_e.name, st.verb "+
			"FROM svo_triples st "+
			"JOIN entities child_e ON st.object_id = child_e.id "+
			"JOIN entities parent_e ON st.subject_id = parent_e.id "+
			"WHERE child_e.name IN (%s) AND st.verb IN (%s) AND (st.namespace = ? OR st.namespace IS NULL)",
		placeholders, fwdVerbs, placeholders, revVerbs,
	)
	args := make([]interface{}, 0, len(entityNames)*2+2)
	for _, n := range entityNames {
		args = append(args, n)
	}
	args = append(args, namespace)
	for _, n := range entityNames {
		args = append(args, n)
	}
	args = append(args, namespace)
	rows, err := conn.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("query entity parents: %w", err)
	}
	defer rows.Close()
	result := make(map[string][2]string)
	for rows.Next() {
		var childName, parentName, verb string
		if err := rows.Scan(&childName, &parentName, &verb); err != nil {
			return nil, fmt.Errorf("scan entity parent row: %w", err)
		}
		if _, exists := result[childName]; !exists {
			result[childName] = [2]string{parentName, verb}
		}
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate entity parent rows: %w", err)
	}
	return result, nil
}

