func (d *DirectoryCrawler) walkLocal(directory string, out *[]string) error {
	if len(*out) >= d.maxFiles {
		return nil
	}
	entries, err := os.ReadDir(directory)
	if err != nil {
		if os.IsPermission(err) {
			log.Printf("WARN DirectoryCrawler: permission denied: %v", err)
			return nil
		}
		return fmt.Errorf("DirectoryCrawler: readdir %q: %w", directory, err)
	}
	sort.Slice(entries, func(i, j int) bool { return entries[i].Name() < entries[j].Name() })
	for _, entry := range entries {
		if len(*out) >= d.maxFiles {
			return nil
		}
		name := entry.Name()
		if entry.IsDir() {
			if _, excluded := d.excludeDirs[name]; excluded {
				continue
			}
			if strings.HasPrefix(name, ".") {
				continue
			}
			if d.recursive {
				if err := d.walkLocal(filepath.Join(directory, name), out); err != nil {
					return err
				}
			}
		} else {
			fullPath := filepath.Join(directory, name)
			if d.accept(fullPath) {
				*out = append(*out, fullPath)
			}
		}
	}
	return nil
}

