func (g *GmailCrawler) Crawl(ctx context.Context, uri string, query string, limit int) ([]string, error) {
	if limit <= 0 {
		limit = 100
	}
	svc, err := g.getService()
	if err != nil {
		return nil, fmt.Errorf("GmailCrawler.Crawl: get service: %w", err)
	}
	label := labelFromURI(uri)
	maxResults := limit
	if maxResults > 500 {
		maxResults = 500
	}
	var uris []string
	var pageToken string
	for len(uris) < limit {
		reqParams := map[string]string{
