			"maxResults": strconv.Itoa(maxResults),
		}
		if query != "" {
			reqParams["q"] = query
		} else {
			reqParams["labelIds"] = label
		}
		if pageToken != "" {
			reqParams["pageToken"] = pageToken
		}
		resp, err := svc.ListMessages(ctx, reqParams)
		if err != nil {
			return nil, fmt.Errorf("GmailCrawler.Crawl: list messages: %w", err)
