func (t *ImapTransport) FetchMessages(uri string, limit *int) ([]FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return nil, fmt.Errorf("ImapTransport: parse URI %q: %w", uri, err)
	}
	useSSL := parsed.Scheme == "imaps"
	host := parsed.Hostname()
	if host == "" {
		host = "localhost"
	}
	portStr := parsed.Port()
	port := 143
	if useSSL {
		port = 993
	}
	if portStr != "" {
		if p, err := strconv.Atoi(portStr); err == nil {
			port = p
		}
	}
	user, _ := url.QueryUnescape(parsed.User.Username())
	password := ""
	if parsed.User != nil {
		if pw, ok := parsed.User.Password(); ok {
			password, _ = url.QueryUnescape(pw)
		}
	}
	mailbox := strings.TrimPrefix(parsed.Path, "/")
	if mailbox == "" {
		mailbox = "INBOX"
	}
	qs, _ := url.ParseQuery(parsed.RawQuery)
	searchCriteria := "ALL"
	if vals, ok := qs["search"]; ok && len(vals) > 0 {
		searchCriteria = vals[0]
	}
	effectiveLimit := -1
	if limit != nil {
		effectiveLimit = *limit
	} else if vals, ok := qs["limit"]; ok && len(vals) > 0 {
		if n, err := strconv.Atoi(vals[0]); err == nil {
			effectiveLimit = n
		}
	}
	addr := fmt.Sprintf("%s:%d", host, port)
	var conn *imap.Client
	if useSSL {
		conn, err = imap.DialTLS(addr, nil)
	} else {
		conn, err = imap.Dial(addr)
	}
	if err != nil {
		return nil, fmt.Errorf("ImapTransport: dial %s: %w", addr, err)
	}
	defer func() {
		_ = conn.Close(true)
		_ = conn.Logout(30 * time.Second)
	}()
	if _, err := conn.Login(user, password); err != nil {
		return nil, fmt.Errorf("ImapTransport: login: %w", err)
	}
	if _, err := conn.Select(mailbox, true); err != nil {
		return nil, fmt.Errorf("ImapTransport: select mailbox %q: %w", mailbox, err)
	}
	cmd, err := imap.Wait(conn.Search(searchCriteria))
	if err != nil {
		return nil, fmt.Errorf("ImapTransport: search: %w", err)
	}
	var msgIDs []uint32
	for _, rsp := range cmd.Data {
		msgIDs = append(msgIDs, rsp.SearchResults()...)
	}
	// Most-recent first
	for i, j := 0, len(msgIDs)-1; i < j; i, j = i+1, j-1 {
		msgIDs[i], msgIDs[j] = msgIDs[j], msgIDs[i]
	}
	if effectiveLimit >= 0 && len(msgIDs) > effectiveLimit {
		msgIDs = msgIDs[:effectiveLimit]
	}
	var results []FetchResult
	for _, mid := range msgIDs {
		set := new(imap.SeqSet)
		set.AddNum(mid)
		cmd, err := imap.Wait(conn.Fetch(set, "RFC822"))
		if err != nil {
			log.Printf("WARN ImapTransport: skipping message %d: %v", mid, err)
			continue
		}
		for _, rsp := range cmd.Data {
			body := imap.AsBytes(rsp.MessageInfo().Attrs["RFC822"])
			source := fmt.Sprintf("imap://%s/%s/%d", host, mailbox, mid)
			mime := "message/rfc822"
			results = append(results, FetchResult{
				Data:         body,
				DetectedMIME: &mime,
				SourcePath:   &source,
			})
		}
	}
	return results, nil
}

