func (m *MongoCrawler) schemaFromValidator(ctx context.Context, db *mongo.Database, collName, dbName string) (string, error) {
	cursor, err := db.ListCollections(ctx, bson.M{"name": collName})
	if err == nil {
		defer cursor.Close(ctx)
		for cursor.Next(ctx) {
			var info bson.M
			if err := cursor.Decode(&info); err != nil {
				continue
			}
			if opts, ok := info["options"].(bson.M); ok {
				if validator, ok := opts["validator"].(bson.M); ok {
					if jsonSchema, ok := validator["$jsonSchema"].(bson.M); ok && len(jsonSchema) > 0 {
						fields := m.fieldsFromJSONSchema(jsonSchema, "")
						for f := range fields {
							m.knownFields[f] = struct{}{}
						}
						schemaBytes, _ := json.MarshalIndent(jsonSchema, "", "  ")
						return fmt.Sprintf("Source: %s/%s\nSchema (validator $jsonSchema):\n%s\n",
							dbName, collName, string(schemaBytes)), nil
					}
				}
			}
		}
	}
	// Fallback: $sample aggregation
	var sample []map[string]interface{}
	pipeline := mongo.Pipeline{bson.D{{Key: "$sample", Value: bson.M{"size": schemaSampleSize}}}}
	aggCursor, aggErr := db.Collection(collName).Aggregate(ctx, pipeline)
	if aggErr == nil {
		defer aggCursor.Close(ctx)
		for aggCursor.Next(ctx) {
			var doc map[string]interface{}
			if err := aggCursor.Decode(&doc); err == nil {
				sample = append(sample, doc)
			}
		}
	}
	for f := range collectFieldPaths(sample) {
		m.knownFields[f] = struct{}{}
	}
	total, _ := db.Collection(collName).EstimatedDocumentCount(ctx)
	schemaText := inferSchemaText(sample, fmt.Sprintf("%s/%s", dbName, collName), int(total), len(sample))
	return schemaText, nil
}

