func (s *S3Transport) Fetch(ctx context.Context, uri string, opts S3FetchOptions) (FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return FetchResult{}, fmt.Errorf("S3Transport: parse URI %q: %w", uri, err)
	}
	bucket := parsed.Hostname()
	key := strings.TrimPrefix(parsed.Path, "/")

	var cfgOpts []func(*config.LoadOptions) error
	if opts.Profile != "" {
		cfgOpts = append(cfgOpts, config.WithSharedConfigProfile(opts.Profile))
	}
	region := opts.Region
	if region == "" {
		if r := os.Getenv("AWS_REGION"); r != "" {
			region = r
		} else if r := os.Getenv("AWS_DEFAULT_REGION"); r != "" {
			region = r
		}
	}
	if region != "" {
		cfgOpts = append(cfgOpts, config.WithRegion(region))
	}
	cfg, err := config.LoadDefaultConfig(ctx, cfgOpts...)
	if err != nil {
		return FetchResult{}, fmt.Errorf("S3Transport: load AWS config: %w", err)
	}
	var clientOpts []func(*s3.Options)
	endpoint := opts.EndpointURL
	if endpoint == "" {
		endpoint = os.Getenv("AWS_ENDPOINT_OVERRIDE")
	}
	if endpoint != "" {
		clientOpts = append(clientOpts, func(o *s3.Options) { o.BaseEndpoint = &endpoint })
	}
	client := s3.NewFromConfig(cfg, clientOpts...)
	result, err := client.GetObject(ctx, &s3.GetObjectInput{
		Bucket: &bucket,
		Key:    &key,
	})
	if err != nil {
		return FetchResult{}, fmt.Errorf("S3Transport: get object s3://%s/%s: %w", bucket, key, err)
	}
	defer result.Body.Close()
	data, err := io.ReadAll(result.Body)
	if err != nil {
		return FetchResult{}, fmt.Errorf("S3Transport: read body: %w", err)
	}
	var contentType *string
	if result.ContentType != nil && *result.ContentType != "" {
		contentType = result.ContentType
	}
	return FetchResult{
		Data:         data,
		DetectedMIME: contentType,
		SourcePath:   &uri,
	}, nil
}

