// InferSchemaTextOptions holds optional params for InferSchemaText.
// Note: TotalDocs and SampleSize use pointers to distinguish "not provided" from zero.
type InferSchemaTextOptions struct {
	TotalDocs  *int
	SampleSize *int
}

func InferSchemaText(docs []map[string]interface{}, label string, opts InferSchemaTextOptions) string {
	n := len(docs)
	if n == 0 {
		return fmt.Sprintf("Source: %s\nNo documents sampled \u2014 schema unavailable.\n", label)
	}
	sampleSize := n
	if opts.SampleSize != nil {
		sampleSize = *opts.SampleSize
	}
	counts := make(map[string]*fieldInfo)
	for _, doc := range docs {
		walkDoc(doc, counts, "")
	}
	lines := []string{fmt.Sprintf("Source: %s", label)}
	if opts.TotalDocs != nil {
		lines = append(lines, fmt.Sprintf("Sampled: %s / %s documents",
			formatInt(sampleSize), formatInt(*opts.TotalDocs)))
	} else {
		lines = append(lines, fmt.Sprintf("Sampled: %s documents", formatInt(sampleSize)))
	}
	lines = append(lines, "")
	lines = append(lines, fmt.Sprintf("%-40s  %-20s  Present", "Field", "Type"))
	lines = append(lines, strings.Repeat("-", 72))
	paths := make([]string, 0, len(counts))
	for p := range counts {
		paths = append(paths, p)
	}
	sort.Strings(paths)
	for _, path := range paths {
		info := counts[path]
		presentPct := 0
		if n > 0 {
			presentPct = int(100 * info.present / n)
		}
		typeStr := buildTypeStr(info.types)
		if len(info.itemTypes) > 0 {
			typeStr += "  \u2192 items: " + buildTypeStr(info.itemTypes)
		}
		depth := strings.Count(path, ".") + strings.Count(path, "[]")
		indent := strings.Repeat("  ", depth)
		lines = append(lines, fmt.Sprintf("%s%-40s  %-20s  %d%%", indent, path, typeStr, presentPct))
	}
	return strings.Join(lines, "\n") + "\n"
}

// SftpFetchOptions holds optional SFTP connection parameters.
type SftpFetchOptions struct {
	Port     int
	Username string
	Password string
	KeyPath  string
}

func (s *SftpTransport) Fetch(uri string, opts SftpFetchOptions) (FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return FetchResult{}, fmt.Errorf("SftpTransport: parse URI %q: %w", uri, err)
	}
	host := parsed.Hostname()
	if host == "" {
		return FetchResult{}, fmt.Errorf("SftpTransport: missing host in URI %q", uri)
	}
	port := opts.Port
	if port == 0 {
		if portStr := parsed.Port(); portStr != "" {
			if p, err := strconv.Atoi(portStr); err == nil {
				port = p
			}
		}
	}
	if port == 0 {
		port = 22
	}
	username := opts.Username
	if username == "" && parsed.User != nil {
		username = parsed.User.Username()
	}
	password := opts.Password
	if password == "" && parsed.User != nil {
		if pw, ok := parsed.User.Password(); ok {
			password = pw
		}
	}
	var authMethods []ssh.AuthMethod
	if opts.KeyPath != "" {
		key, err := os.ReadFile(opts.KeyPath)
		if err != nil {
			return FetchResult{}, fmt.Errorf("SftpTransport: read key %q: %w", opts.KeyPath, err)
		}
		signer, err := ssh.ParsePrivateKey(key)
		if err != nil {
			return FetchResult{}, fmt.Errorf("SftpTransport: parse key: %w", err)
		}
		authMethods = append(authMethods, ssh.PublicKeys(signer))
	}
	if password != "" {
		authMethods = append(authMethods, ssh.Password(password))
	}
	sshConfig := &ssh.ClientConfig{
		User:            username,
		Auth:            authMethods,
		HostKeyCallback: ssh.InsecureIgnoreHostKey(), // Note: production use should verify host key
	}
	conn, err := ssh.Dial("tcp", fmt.Sprintf("%s:%d", host, port), sshConfig)
	if err != nil {
		return FetchResult{}, fmt.Errorf("SftpTransport: ssh dial: %w", err)
	}
	defer conn.Close()
	client, err := sftp.NewClient(conn)
	if err != nil {
		return FetchResult{}, fmt.Errorf("SftpTransport: sftp client: %w", err)
	}
	defer client.Close()
	f, err := client.Open(parsed.Path)
	if err != nil {
		return FetchResult{}, fmt.Errorf("SftpTransport: open %q: %w", parsed.Path, err)
	}
	defer f.Close()
	data, err := io.ReadAll(f)
	if err != nil {
		return FetchResult{}, fmt.Errorf("SftpTransport: read: %w", err)
	}
	return FetchResult{
		Data:       data,
		SourcePath: &uri,
	}, nil
}

