func (s *SolrCrawler) fetchSchema(ctx context.Context, session *http.Client) string {
	schemaURL := fmt.Sprintf("%s/%s/schema?wt=json", s.baseURL, s.collection)
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, schemaURL, nil)
	if err != nil {
		return fmt.Sprintf("Source: %s\nSchema unavailable: %v\n", s.collection, err)
	}
	resp, err := session.Do(req)
	if err != nil {
		return fmt.Sprintf("Source: %s\nSchema unavailable: %v\n", s.collection, err)
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return fmt.Sprintf("Source: %s\nSchema unavailable: HTTP %d\n", s.collection, resp.StatusCode)
	}
	var body map[string]interface{}
	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
		return fmt.Sprintf("Source: %s\nSchema unavailable: %v\n", s.collection, err)
	}
	schema, _ := body["schema"].(map[string]interface{})
	schemaName, _ := schema["name"].(string)
	if schemaName == "" {
		schemaName = s.collection
	}
	rawFields, _ := schema["fields"].([]interface{})
	var fieldList []map[string]interface{}
	for _, f := range rawFields {
		if fm, ok := f.(map[string]interface{}); ok {
			fieldList = append(fieldList, fm)
		}
	}
	sort.Slice(fieldList, func(i, j int) bool {
		ni, _ := fieldList[i]["name"].(string)
		nj, _ := fieldList[j]["name"].(string)
		return ni < nj
	})
	lines := []string{
		fmt.Sprintf("Source: %s", s.collection),
		fmt.Sprintf("Schema (Solr): %s", schemaName),
		"",
		fmt.Sprintf("%-40s  %-24s  Flags", "Field", "Type"),
		strings.Repeat("-", 80),
	}
	for _, field := range fieldList {
		name, _ := field["name"].(string)
		ftype, _ := field["type"].(string)
		s.knownFields[name] = struct{}{}
		var flags []string
		if req, _ := field["required"].(bool); req {
			flags = append(flags, "required")
		}
		if mv, _ := field["multiValued"].(bool); mv {
			flags = append(flags, "multiValued")
		}
		if indexed, ok := field["indexed"].(bool); ok && !indexed {
			flags = append(flags, "not-indexed")
		}
		if stored, ok := field["stored"].(bool); ok && !stored {
			flags = append(flags, "not-stored")
		}
		lines = append(lines, fmt.Sprintf("  %-40s  %-24s  %s", name, ftype, strings.Join(flags, ", ")))
	}
	rawDyn, _ := schema["dynamicFields"].([]interface{})
	if len(rawDyn) > 0 {
		var dynFields []map[string]interface{}
		for _, f := range rawDyn {
			if fm, ok := f.(map[string]interface{}); ok {
				dynFields = append(dynFields, fm)
			}
		}
		sort.Slice(dynFields, func(i, j int) bool {
			ni, _ := dynFields[i]["name"].(string)
			nj, _ := dynFields[j]["name"].(string)
			return ni < nj
		})
		lines = append(lines, "", "Dynamic fields:")
		for _, field := range dynFields {
			name, _ := field["name"].(string)
			ftype, _ := field["type"].(string)
			lines = append(lines, fmt.Sprintf("  %-40s  %s", name, ftype))
		}
	}
	rawCopy, _ := schema["copyFields"].([]interface{})
	if len(rawCopy) > 0 {
		lines = append(lines, "", "Copy fields:")
		for _, cf := range rawCopy {
			if cfm, ok := cf.(map[string]interface{}); ok {
				src, _ := cfm["source"].(string)
				dst, _ := cfm["dest"].(string)
				lines = append(lines, fmt.Sprintf("  %s \u2192 %s", src, dst))
			}
		}
	}
	return strings.Join(lines, "\n") + "\n"
}

