// SqlQueryTransport.Fetch executes a SQL query and returns results as CSV bytes.
// The SQL may be provided via the sql parameter or as a ?sql=... query parameter in the URI.
type SqlQueryTransport struct {
	db *sql.DB
}

func (t *SqlQueryTransport) Fetch(ctx context.Context, uri string, sqlQuery string) (FetchResult, error) {
	parsed, err := url.Parse(uri)
	if err != nil {
		return FetchResult{}, fmt.Errorf("SqlQueryTransport: parse URI %q: %w", uri, err)
	}
	qs, _ := url.ParseQuery(parsed.RawQuery)
	if vals, ok := qs["sql"]; ok && len(vals) > 0 {
		var decoded string
		decoded, err = url.QueryUnescape(vals[0])
		if err != nil {
			return FetchResult{}, fmt.Errorf("SqlQueryTransport: decode sql param: %w", err)
		}
		sqlQuery = decoded
	}
	if sqlQuery == "" {
		return FetchResult{}, fmt.Errorf("SqlQueryTransport: no SQL provided for %q — pass sqlQuery or include ?sql=... in the URI", uri)
	}
	docName := parsed.Host
	if docName == "" {
		docName = strings.TrimPrefix(parsed.Path, "/")
	}
	if docName == "" {
		docName = "query"
	}
	rows, err := t.db.QueryContext(ctx, sqlQuery)
	if err != nil {
		return FetchResult{}, fmt.Errorf("SqlQueryTransport: execute query: %w", err)
	}
	defer rows.Close()
	cols, err := rows.Columns()
	if err != nil {
		return FetchResult{}, fmt.Errorf("SqlQueryTransport: get columns: %w", err)
	}
	var buf bytes.Buffer
	w := csv.NewWriter(&buf)
	if err := w.Write(cols); err != nil {
		return FetchResult{}, fmt.Errorf("SqlQueryTransport: write csv header: %w", err)
	}
	vals2 := make([]interface{}, len(cols))
	valPtrs := make([]interface{}, len(cols))
	for i := range vals2 {
		valPtrs[i] = &vals2[i]
	}
	for rows.Next() {
		if err := rows.Scan(valPtrs...); err != nil {
			return FetchResult{}, fmt.Errorf("SqlQueryTransport: scan row: %w", err)
		}
		row := make([]string, len(cols))
		for i, v := range vals2 {
			if v == nil {
				row[i] = ""
			} else {
				row[i] = fmt.Sprintf("%v", v)
			}
		}
		if err := w.Write(row); err != nil {
			return FetchResult{}, fmt.Errorf("SqlQueryTransport: write csv row: %w", err)
		}
	}
	if err := rows.Err(); err != nil {
		return FetchResult{}, fmt.Errorf("SqlQueryTransport: rows error: %w", err)
	}
	w.Flush()
	if err := w.Error(); err != nil {
		return FetchResult{}, fmt.Errorf("SqlQueryTransport: flush csv: %w", err)
	}
	mime := "text/csv"
	return FetchResult{
		Data:         buf.Bytes(),
		DetectedMIME: &mime,
		SourcePath:   &docName,
	}, nil
}

