func (w *WebCrawler) shouldVisit(rawURL, rootDomain string) bool {
	parsed, err := url.Parse(rawURL)
	if err != nil {
		return false
	}
	if w.sameDomain && parsed.Hostname() != rootDomain {
		return false
	}
	if w.includeRe != nil && !w.includeRe.MatchString(rawURL) {
		return false
	}
	for _, ep := range w.excludeRes {
		if ep.MatchString(rawURL) {
			log.Printf("DEBUG WebCrawler: excluded by pattern: %s", rawURL)
			return false
		}
	}
	if w.wikiMode {
		for _, p := range wikiSkipPrefixes {
			if strings.HasPrefix(parsed.Path, p) {
				return false
			}
		}
		qs := parsed.RawQuery
		for _, param := range wikiSkipParams {
			if strings.Contains(qs, param) {
				return false
			}
		}
	}
	return true
}

