// renderOne renders a single MITRE ATT&CK technique dict into a markdown string.
func renderOne(tech map[string]interface{}, index *Index) string {
	attackID := extID(tech)
	if attackID == "" {
		if id, ok := tech["id"].(string); ok && id != "" {
			attackID = id
		} else {
			attackID = "UNKNOWN"
		}
	}
	name, _ := tech["name"].(string)
	descRaw, _ := tech["description"].(string)
	description := strings.TrimSpace(descRaw)

	platformsRaw, _ := tech["x_mitre_platforms"].([]interface{})
	platforms := make([]string, 0, len(platformsRaw))
	for _, p := range platformsRaw {
		if s, ok := p.(string); ok {
			platforms = append(platforms, s)
		}
	}

	// R04: list comprehension → explicit for loop
	kcpRaw, _ := tech["kill_chain_phases"].([]interface{})
	tactics := make([]string, 0, len(kcpRaw))
	for _, p := range kcpRaw {
		if pm, ok := p.(map[string]interface{}); ok {
			if phase, ok := pm["phase_name"].(string); ok {
				tactics = append(tactics, phase)
			}
		}
	}

	isSub, _ := tech["x_mitre_is_subtechnique"].(bool)
	url := extURL(tech)

	var parentID string
	if isSub {
		techID, _ := tech["id"].(string)
		if parentStix, ok := index.Parent[techID]; ok && parentStix != "" {
			if parentObj, ok := index.ByID[parentStix]; ok {
				parentID = extID(parentObj)
			}
		}
	}

	techID, _ := tech["id"].(string)
	mitigations := index.TechMitigations[techID]

	lines := []string{fmt.Sprintf("# %s %s", attackID, name), ""}

	meta := []string{}
	if len(tactics) > 0 {
		meta = append(meta, fmt.Sprintf("**Tactics:** %s", strings.Join(tactics, ", ")))
	}
	if len(platforms) > 0 {
		meta = append(meta, fmt.Sprintf("**Platforms:** %s", strings.Join(platforms, ", ")))
	}
	if parentID != "" {
		meta = append(meta, fmt.Sprintf("**Sub-technique of:** %s", parentID))
	}
	lines = append(lines, meta...)

	if description != "" {
		lines = append(lines, "", "## Description", "", description)
	}

	if len(mitigations) > 0 {
		lines = append(lines, "", "## Mitigations", "")
		for _, m := range mitigations {
			mname, _ := m["name"].(string)
			mdescRaw, _ := m["description"].(string)
			mdesc := strings.TrimSpace(mdescRaw)
			var firstSentence string
			if mdesc != "" {
				parts := strings.SplitN(mdesc, ". ", 2)
				firstSentence = strings.TrimSuffix(parts[0], ".") + "."
			}
			if firstSentence != "" {
				lines = append(lines, fmt.Sprintf("- **%s** — %s", mname, firstSentence))
			} else {
				lines = append(lines, fmt.Sprintf("- %s", mname))
			}
		}
	}

	if url != "" {
		lines = append(lines, "", "## References", "", fmt.Sprintf("- %s", url))
	}

