// iterStudies extracts study dicts from various ClinicalTrials.gov API v2 response shapes.
func iterStudies(obj interface{}) []map[string]interface{} {
	switch v := obj.(type) {
	case map[string]interface{}:
		if studiesRaw, ok := v["studies"]; ok {
			studiesList, _ := studiesRaw.([]interface{})
			// R04: list comprehension → explicit for loop
			result := make([]map[string]interface{}, 0, len(studiesList))
			for _, s := range studiesList {
				if sm, ok := s.(map[string]interface{}); ok {
					result = append(result, sm)
				}
			}
			return result
		}
		if _, ok := v["protocolSection"]; ok {
			return []map[string]interface{}{v}
		}
	case []interface{}:
		// R04: list comprehension → explicit for loop
		result := make([]map[string]interface{}, 0, len(v))
		for _, s := range v {
			if sm, ok := s.(map[string]interface{}); ok {
				if _, hasProt := sm["protocolSection"]; hasProt {
					result = append(result, sm)
				}
			}
		}
		return result
	}
	return []map[string]interface{}{}
}

// renderStudy renders a ClinicalTrials.gov study record into a markdown string.
func renderStudy(study map[string]interface{}) string {
	ps, _ := study["protocolSection"].(map[string]interface{})
	if ps == nil {
		ps = map[string]interface{}{}
	}

	ident, _ := ps["identificationModule"].(map[string]interface{})
	if ident == nil {
		ident = map[string]interface{}{}
	}
	nctID, _ := ident["nctId"].(string)
	if nctID == "" {
		nctID = "UNKNOWN"
	}
	title, _ := ident["briefTitle"].(string)
	if title == "" {
		title, _ = ident["officialTitle"].(string)
	}

	statusMod, _ := ps["statusModule"].(map[string]interface{})
	if statusMod == nil {
		statusMod = map[string]interface{}{}
	}
	status, _ := statusMod["overallStatus"].(string)

	designMod, _ := ps["designModule"].(map[string]interface{})
	if designMod == nil {
		designMod = map[string]interface{}{}
	}
	phaseRaw, _ := designMod["phases"].([]interface{})
	phaseList := make([]string, 0, len(phaseRaw))
	for _, p := range phaseRaw {
		if s, ok := p.(string); ok {
			phaseList = append(phaseList, s)
		}
	}
	phases := strings.Join(phaseList, ", ")

	descMod, _ := ps["descriptionModule"].(map[string]interface{})
	if descMod == nil {
		descMod = map[string]interface{}{}
	}
	briefRaw, _ := descMod["briefSummary"].(string)
	brief := strings.TrimSpace(briefRaw)
	detailedRaw, _ := descMod["detailedDescription"].(string)
	detailed := strings.TrimSpace(detailedRaw)

	condMod, _ := ps["conditionsModule"].(map[string]interface{})
	if condMod == nil {
		condMod = map[string]interface{}{}
	}
	condRaw, _ := condMod["conditions"].([]interface{})
	conditions := make([]string, 0, len(condRaw))
	for _, c := range condRaw {
		if s, ok := c.(string); ok {
			conditions = append(conditions, s)
		}
	}

	armsMod, _ := ps["armsInterventionsModule"].(map[string]interface{})
	if armsMod == nil {
		armsMod = map[string]interface{}{}
	}
	ivRaw, _ := armsMod["interventions"].([]interface{})
	interventions := make([]string, 0)
	for _, item := range ivRaw {
		iv, ok := item.(map[string]interface{})
		if !ok {
			continue
		}
		itype, _ := iv["type"].(string)
		iname, _ := iv["name"].(string)
		if iname != "" {
			if itype != "" {
				interventions = append(interventions, fmt.Sprintf("%s: %s", itype, iname))
			} else {
				interventions = append(interventions, iname)
			}
		}
	}

	eligMod, _ := ps["eligibilityModule"].(map[string]interface{})
	if eligMod == nil {
		eligMod = map[string]interface{}{}
	}
	eligRaw, _ := eligMod["eligibilityCriteria"].(string)
	eligibility := strings.TrimSpace(eligRaw)
	minAge, _ := eligMod["minimumAge"].(string)
	maxAge, _ := eligMod["maximumAge"].(string)
	sex, _ := eligMod["sex"].(string)

	lines := []string{fmt.Sprintf("# %s %s", nctID, title), ""}

	meta := []string{}
	if status != "" {
		meta = append(meta, fmt.Sprintf("**Status:** %s", status))
	}
	if phases != "" {
		meta = append(meta, fmt.Sprintf("**Phase:** %s", phases))
	}
	if len(conditions) > 0 {
		// R09: conditions[:5]
		cap := 5
		if len(conditions) < cap {
			cap = len(conditions)
		}
		meta = append(meta, fmt.Sprintf("**Conditions:** %s", strings.Join(conditions[:cap], ", ")))
	}
	lines = append(lines, meta...)

	if brief != "" {
		lines = append(lines, "", "## Summary", "", brief)
	}
	if detailed != "" {
		lines = append(lines, "", "## Detailed Description", "", detailed)
	}

	if len(interventions) > 0 {
		lines = append(lines, "", "## Interventions", "")
		// R09: interventions[:10]
		cap := 10
		if len(interventions) < cap {
			cap = len(interventions)
		}
		for _, iv := range interventions[:cap] {
			lines = append(lines, fmt.Sprintf("- %s", iv))
		}
	}

	if eligibility != "" {
		ageParts := make([]string, 0, 2)
		if minAge != "" {
			ageParts = append(ageParts, minAge)
		}
		if maxAge != "" {
			ageParts = append(ageParts, maxAge)
		}
		ageStr := strings.Join(ageParts, " to ")
		var eligHeader string
		if sex != "" || ageStr != "" {
			eligHeader = fmt.Sprintf("## Eligibility (%s, %s)", sex, ageStr)
		} else {
			eligHeader = "## Eligibility"
		}
		// R09: eligibility[:2000]
		eligTrunc := eligibility
		if len(eligTrunc) > 2000 {
			eligTrunc = eligTrunc[:2000]
		}
		lines = append(lines, "", eligHeader, "", eligTrunc)
	}

	return strings.Join(lines, "\n")
}

