// CsvExtractor extracts CSV/TSV files into markdown tables.
type CsvExtractor struct{}

// cell sanitizes a CSV cell value for use in a markdown table.
func cell(value string) string {
	v := strings.ReplaceAll(value, "|", "\\|")
	v = strings.ReplaceAll(v, "\n", " ")
	return strings.TrimSpace(v)
}

// Extract decodes CSV bytes, sniffs the dialect, and renders the data as a markdown table.
func (e *CsvExtractor) Extract(data []byte, sourcePath *string) (string, error) {
	text, err := decodeBytes(data)
	if err != nil {
		return "", fmt.Errorf("extract: decode: %w", err)
	}

	delimiter, err := sniffDelimiter(text)
	if err != nil {
		// fall back to comma
		delimiter = ','
	}

	r := csv.NewReader(strings.NewReader(text))
	r.Comma = delimiter
	r.LazyQuotes = true

	var rows [][]string
	for {
		row, err := r.Read()
		if err == io.EOF {
			break
		}
		if err != nil {
			return "", fmt.Errorf("extract: read csv: %w", err)
		}
		// R11: equivalent of any(cell.strip() for cell in row)
		hasContent := false
		for _, c := range row {
			if strings.TrimSpace(c) != "" {
				hasContent = true
				break
			}
		}
		if hasContent {
			rows = append(rows, row)
		}
	}

	if len(rows) == 0 {
		return "", nil
	}

	headers := rows[0]
	// R09: rows[1:]
	body := rows[1:]

	// R04: generator → explicit for loop
	headerCells := make([]string, 0, len(headers))
	for _, h := range headers {
		headerCells = append(headerCells, cell(h))
	}
	headerRow := "| " + strings.Join(headerCells, " | ") + " |"

	sepCells := make([]string, 0, len(headers))
	for range headers {
		sepCells = append(sepCells, "---")
	}
	sepRow := "| " + strings.Join(sepCells, " | ") + " |"

	// R04: list comprehension → explicit for loop
	dataLines := make([]string, 0, len(body))
	for _, row := range body {
		rowCells := make([]string, 0, len(row))
		for _, c := range row {
			rowCells = append(rowCells, cell(c))
		}
		dataLines = append(dataLines, "| "+strings.Join(rowCells, " | ")+" |")
	}

	allLines := make([]string, 0, 2+len(dataLines))
	allLines = append(allLines, headerRow, sepRow)
	allLines = append(allLines, dataLines...)
	return strings.Join(allLines, "\n"), nil
}

