// rowEntry maps a 1-based data row index to its rendered markdown row string.
type rowEntry struct {
	Index    int
	Rendered string
}

// Annotate enriches DocumentChunks with row_start/row_end source_detail by matching
// rendered markdown rows against chunk content.
func (e *CsvExtractor) Annotate(chunks []*DocumentChunk, data []byte, sourcePath *string) ([]*DocumentChunk, error) {
	text, err := decodeBytes(data)
	if err != nil {
		return nil, fmt.Errorf("annotate: decode: %w", err)
	}

	delimiter, err := sniffDelimiter(text)
	if err != nil {
		delimiter = ','
	}

	r := csv.NewReader(strings.NewReader(text))
	r.Comma = delimiter
	r.LazyQuotes = true

	// R04: list comprehension → explicit for loop
	var rows [][]string
	for {
		row, readErr := r.Read()
		if readErr == io.EOF {
			break
		}
		if readErr != nil {
			return nil, fmt.Errorf("annotate: read csv: %w", readErr)
		}
		hasContent := false
		for _, c := range row {
			if strings.TrimSpace(c) != "" {
				hasContent = true
				break
			}
		}
		if hasContent {
			rows = append(rows, row)
		}
	}

	if len(rows) < 2 {
		return chunks, nil
	}

	// Build 1-based row_map: R10 enumerate → for i, row := range rows[1:]
	// R09: rows[1:]
	dataRows := rows[1:]
	rowMap := make([]rowEntry, 0, len(dataRows))
	for i, row := range dataRows {
		rowCells := make([]string, 0, len(row))
		for _, c := range row {
			rowCells = append(rowCells, cell(c))
		}
		rendered := "| " + strings.Join(rowCells, " | ") + " |"
		rowMap = append(rowMap, rowEntry{Index: i + 1, Rendered: rendered})
	}

	for _, chunk := range chunks {
		content := chunk.Content
		// R04: list comprehension for matched indices → explicit for loop
		matched := make([]int, 0)
		for _, entry := range rowMap {
			if strings.Contains(content, entry.Rendered) {
				matched = append(matched, entry.Index)
			}
		}
		if len(matched) > 0 {
			rowStart := matched[0]
			rowEnd := matched[0]
			for _, idx := range matched[1:] {
				if idx < rowStart {
					rowStart = idx
				}
				if idx > rowEnd {
					rowEnd = idx
				}
			}
			chunk.SourceDetail = map[string]interface{}{
				"row_start": rowStart,
				"row_end":   rowEnd,
			}
		}
	}
	return chunks, nil
}

