var cvssKeys = []string{"cvssMetricV40", "cvssMetricV31", "cvssMetricV30", "cvssMetricV2"}

func bestCVSS(metrics map[string]any) (*float64, *string) {
	for _, key := range cvssKeys {
		entries, ok := metrics[key]
		if !ok {
			continue
		}
		list, ok := entries.([]any)
		if !ok {
			continue
		}
		for _, e := range list {
			entry, ok := e.(map[string]any)
			if !ok {
				continue
			}
			data, _ := entry["cvssData"].(map[string]any)
			scoreRaw := data["baseScore"]
			if scoreRaw == nil {
				continue
			}
			score, ok := scoreRaw.(float64)
			if !ok {
				continue
			}
			var sevStr string
			if s, ok := data["baseSeverity"].(string); ok && s != "" {
				sevStr = s
			} else if s, ok := entry["baseSeverity"].(string); ok && s != "" {
				sevStr = s
			} else if s, ok := entry["severity"].(string); ok && s != "" {
				sevStr = s
			}
			sevStr = strings.ToUpper(sevStr)
			scoreCopy := score
			if sevStr != "" {
				return &scoreCopy, &sevStr
			}
			return &scoreCopy, nil
		}
	}
	return nil, nil
}

