func iterCVEs(obj any) []map[string]any {
	switch v := obj.(type) {
	case map[string]any:
		if vulns, ok := v["vulnerabilities"]; ok {
			list, ok := vulns.([]any)
			if !ok {
				return nil
			}
			var out []map[string]any
			for _, item := range list {
				m, ok := item.(map[string]any)
				if !ok {
					continue
				}
				cve, ok := m["cve"].(map[string]any)
				if ok {
					out = append(out, cve)
				}
			}
			return out
		}
		if id, ok := v["id"].(string); ok && strings.HasPrefix(strings.ToUpper(id), "CVE-") {
			return []map[string]any{v}
		}
		if cve, ok := v["cve"].(map[string]any); ok {
			return []map[string]any{cve}
		}
	case []any:
		var out []map[string]any
		for _, item := range v {
			out = append(out, iterCVEs(item)...)
		}
		return out
	}
	return nil
}

