func iterWeaknessesFromDict(obj map[string]any) []map[string]any {
	wc := obj["Weaknesses"]
	if wc == nil {
		return nil
	}
	var container map[string]any
	switch v := wc.(type) {
	case []any:
		if len(v) == 0 {
			return nil
		}
		var ok bool
		container, ok = v[0].(map[string]any)
		if !ok {
			return nil
		}
	case map[string]any:
		container = v
	default:
		return nil
	}
	raw := container["Weakness"]
	if raw == nil {
		return nil
	}
	switch r := raw.(type) {
	case []any:
		var out []map[string]any
		for _, item := range r {
			if m, ok := item.(map[string]any); ok {
				out = append(out, m)
			}
		}
		return out
	case map[string]any:
		return []map[string]any{r}
	}
	return nil
}

