type CweRenderer struct{}

func (r *CweRenderer) Annotate(chunks []DocumentChunk, obj any) []DocumentChunk {
	objMap, ok := obj.(map[string]any)
	if !ok {
		return chunks
	}
	weaknesses := iterWeaknessesFromDict(objMap)

	meta := make(map[string]map[string]any)
	rendered := make(map[string]string)
	for _, w := range weaknesses {
		cweID, _ := w["ID"].(string)
		if cweID == "" {
			continue
		}
		var platforms []string
		ap := w["Applicable_Platforms"]
		if ap != nil {
			var apMap map[string]any
			switch v := ap.(type) {
			case []any:
				if len(v) > 0 {
					apMap, _ = v[0].(map[string]any)
				}
			case map[string]any:
				apMap = v
			}
			if apMap != nil {
				for _, item := range getAnyList(apMap, "Language") {
					lang, ok := item.(map[string]any)
					if !ok {
						continue
					}
					var n string
					if s, ok := lang["Name"].(string); ok && s != "" {
						n = s
					} else if s, ok := lang["Class"].(string); ok && s != "" {
						n = s
					}
					if n != "" {
						platforms = append(platforms, n)
					}
				}
			}
		}
		name, _ := w["Name"].(string)
		meta[cweID] = map[string]any{
			"cwe_id":    fmt.Sprintf("CWE-%s", cweID),
			"name":      name,
			"platforms": platforms,
		}
		rendered[cweID] = renderOneWeakness(w)
	}
	return chunks
}

